insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JUANA'and edp.apellido1='VECINO'and apellido2='GARCIA'),'2014-07-10','-Se le comunica a su vecina Mariana que en respuesta a su escrito solicitando el cambio de centro de Olivenza a Badajoz para facilitarle a ella visitarla más a menudo , este traslado no se va a solicitar. Se han pedido informes al centro en los que se manifiesta que Juana está muy adaptada y muy contenta en Caser. -Mariana me da su conformidad , está de acuerdo pq ella tb la ve muy bien allí .','2');
