insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2014-06-27','El pasado día 19 de junio Consuelo se puso en contacto con esta Comisió para informar que no tenía suficiente dinero con su asignación mensual, ese asunto se atendió y se le autorizó un poco más de dinero al mes. Pero se apreció en la conversación la falta de coherencia en el discurso de Consuelos, comentarios relacionados con la religión...y lo más preocupante, informó de que ha dejado la medicación porque dice que no le sienta bien. Se llamó al Centro de Salud y mantuve conversación con Inmaculada T.S. le expliqué que no veía bien a Consuelo y que podrí aestar sdescompensada, su médico está de baja laboral y el lunes se encargaría la T.S. de citarla. El 24 de junio hablo de nuevo con Inmaculada me dice que ha visto a Consuelo que ha admitido que el último inyectable se lo puso el 8 de mayo. Le pdi que sea vista por un médico. Llamo a Salud mental y esplico la situación, tras hablar la T. S. con la psiquiatra esta al parecer dice que si no quiere tomarse la medicación ella no puede hacer nada. Le pido que adelanten su cita. El 26 de junio llaman de la Unidad de Salud Mental para informar que la tutelada se encuentra es sus dependencias que le ha llevado la Policía Local, hablamos varias veces a los largo de la mañana.Finalmente se le ingresa el la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2014-06-27','- Intentamos poner al dia la deuda con la empresa de ayuda a domicilio para dar de alta de nuevo al servicio de ayuda a domicilio . -no se puede solicitar SAD del Ayto ( corroborado por Esther -Dar largas a la peticion de Paloma de independizarse con su novio .','2');
