insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='MORENO'and apellido2='CARRASCO'),'2014-07-16','Se mantiene conversación telefónica con Beatriz trabajadora Social del Centro Penitenciario de Badajoz, informe que: Julián se encuentra en enfermería, que está totalmente desorientado no siendo ni siquiera consciente de dode se encuentra. -De momento tiene una condena de 8 meses. Permanecerá en este centro hasta que lo claifiquen, que pudiera ser en el mes de agosto, finales. Si para entonces continía allí es posible que sea trasladado a otro centro de la provincia de Sevilla donde sólo hay personas mayores o a Segovia. - Que la cantidad de dinero que consideran conveniente para el mes es de 200 Euros, facilitándome un número de cuenta para que se le ingrese. - Se le explica que su primo Manuel ha mostrado interés por su estado y se le facilita su número de teléfono. A continuación llamamos al abogado, quien informa que la solicitud de traslado a Centro sociosanitario puede tardar y que el hermano del tutelado quiere hablar cn nosotros.','2');
