insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2014-07-25','Despues de tres meses sin tomar la medicación y encontrarse muy alterado, la TS del CS nos comunicó ayer que mediante el 112 ha sido ingresado en la UHB de Mérida.El facultativo que le atiende es el Dr. Alí. De momento no hemos coseguido hablar con él para conocer el estado de Paco. Seguimos intentándolo.','2');
