insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2014-08-21','Med iante E mail, recibido en esta Comisión remitido desde el CRR de Plasencia, se nos informa de lo siguiente: Tras el trascurso de los últimos días de alteración, conductas verbalmente violentas y deseos de abandono del centro, hoy día 20 de julio del 2014, se considera necesario acudir a urgencias del hospital Virgen del puerto para valoración. En un primer momento es atendida por los profesionales del hospital y del CRR, mostrando una reacción violenta y agresiva, faltando al respeto de los profesionales, estando muy referenciada con estos, negándose a ser valorada por el psiquiatra y golpeando la mesa. Tras la llegada de la Doctora Parrado, esta le explica la situación y el motivo por el que consideran que seria beneficioso para Concepción el ingreso, negándose esta a ningún tipo de intervención. En función al elevado estado de alteración y agitación en el que se encontraba la usuaria, se considera necesario la intervención de los profesionales de seguridad del hospital, causada por el estado incontrolable de Concepción. Finalmente, siendo imposible intervenir con ella, se le inyectan tranquilizantes y se produce un ingreso involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='ALVES'and apellido2='MOYA'),'2014-08-25','Se recibe llamada telefónica del Centro Socio sanitaria para comunicar que el sabado pasado se ha escapado. A continuación se llama al hospital de la Montaña para informar, por si aparece por allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2014-09-02','FECHA DE ALTA EN EL HOSPITAL DE MERIDA EL DIA 20.08.2014','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2014-09-18','Se mantiene conversación con Javier, Director del piso de Plasencia, tras los últimos altercados que ha protagonizado. Actalmente permanece en el CRR pues quedaba una habitación libre. La hermana de Fernando Sánchez Escobero, usuario al que agredió, ha presenatdo denuncia en un juzgado de Galicia y ha pedido que adopten alguna medida de protección como "alejamiento". Jonathan sigue manteniendo una mala actitud agresiva-pasiva y en ocasiones agresiva tanto con semejantes como con profesionales del recurso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2014-09-19','En el día de hoy nos comunican que Jonathan se fugó ayer del centro y que procedieron a poner una denuncia. A primera hora de la mañana se recibe llamada de su madre Dña. Mª Carmen para informar que en la tarde de ayer su hijo mayor, Antonio se encontró en un acalle del centro de Mérida con él, que le pisdió 2 euros para irse a Almendralejo, que tenía muy mala pinta, que olía muy mal y le encontró muy agresivo. La madre manifiesta estar muy preocupada, teme "que lo maten o que mate a alguien" . Les ha dicho que se ha fugado porque le queremos ingresar en un centro psiquiátrico. Les ha contado que le retenemos su dinero y que no tiene ni para cortarse el pelo. A continuación mantenemos conversación telefónica con un Sr que se identifica conmo Gabriel Mendoza Yañez y dice ser amigo de la familia desde hace años dice que también está preocupado, que esperaba que fuera a su casa. Se les pide que si Jonathan se pone en contacto con ellos nos lo comuniquen a nosotros o a la Policía. A continuación se llama a la Comisaría de Policía de Almendralejo para trasladar la información que la familia ha aportado y se les envía por fax la copia de la denuncia que se interpuso en Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='FERNANDEZ'and apellido2='PINILLA'),'2014-09-24','Miguel Fernandez Pinilla ha estado ingresado en el Hospital de Merida desde el dia 14 al día 15/07/2014','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2014-10-06','El pasado viernes dia 3 de octubre de 2014 se recibe llamada de la Trabajadora Social de Nova forma para informarme que en unos minutos se personarán en mi despacho junto con Luis Miguel, para contarme un problema muy importante que está teniendo. Transcurridos 15 minutos se mantiene entrevista con Beatriz psicologa de Novaforma,Teresa NogLa misma se mantiene durante durante aproximadamente 1 hora. Los hechos que relatan son los siguientes: · Que la pareja de Luis Miguel Elena, está ejerciendo la prostitución. · Que lo lleva a cabo en su piso pero que él no está de acuerdo · Que hay un cliente con el que Elena se ha encaprichado que se llama José y él se siente muy mal por esto. · Que existe un señor que se llama Antonio, que él conoció en la Asociación ADEX y le ha ofrecido “quitarse del medio” a José, matarlo y ocuparse de ocultar el cuerpo a cambio de 650 Euros. · Que ha llegado a creer que ya lo ha hecho pues ha estado mucho tiempo sin verlo pero que recientemente le ha visto y tiene un brazo roto así que cree que sí al menos lo ha intentado. · Que Elena además se acuesta con más hombres. Tras esta conversación se toma la decisión de ir a la Policía al objeto de poner esto en su conocimiento. Sobre las 14.00 horas, comienza la declaración, terminando la misma sobre las 18:30 horas. Debido a que los hecho que en un primer momento relataba no se parecían a los que finalmente acabó confesando siendo estos últimos de gravedad y temiendo que durante el fin de semana pudiera correr peligro se le pide a la Asociación Novaforma que pueda permanecer allí el fin de semana por parte de la Asociación en un primer momento parecían aceptarlo finalmente no dieron el visto bueno a este asunto. Se le propuso también pasar el fin de semana con su hermano Felipe, rechazando Luis Miguel dicha propuesta. Finalmente se marcho a su casa siendo acompañado parte del camino por Bene, Directora del Centro Ocupacional. Se le pide que no hable con nadie de este tema eira Trabajadora Social de la misma entidad y Luis Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2014-10-08','En el día se realiza llamada telefónica a Novaforma para conocer la situación de Luis Miguel, me informan que no han vuelto a saber nada desde que le dejaron en Comisaría el Lunes. Se recibe también llamada de su hermano Jesus,quien ha llamado varias veces desde el lunes. Tampoco saben nada de él, no saben si está en la comisaría o ya ha sido puesto a disposición judicial. Que la policía no les informa de nada pues les dice que él es mayor de edad y que al parecer tampoco les ofrecen datos sobre quien es su abogado. A continuación se realiza llamada a la Comsisaría de Policía de Cáceres donde nos informan que aún continúa allí. Que no nos pueden dar más información que dependerá del Juez, que una vez que lo suelten si fuera así al tratarse de una persona mayor de edad no llamarán a nadie para que lo recoja. Le explico que aunque tenga sólo una curatela se trata de una persona con discpacidad y que convendría llamar a la familia, Me repite que eso es una decisión del Juez. Le pregunto sobre el abogado que se le ha asignado y me informan de que existe una norma del Decanato de Cáceres y no nos pueden facilitar infromación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2014-10-08','En el día de ayer y previa convocatoria a la misma se acude a la subcomisión de casos convocada por el Equipo de Salud Mental de Plasencia. A la misma acuden: Una representante del SEPAD (Salud Mental de Mérida), la Directora de Centro Socio sanitario de Plasencia, dos Psiquiatras del Centro Socio Sanitario de Plasencia, El director del CRR Y piso supervisado de Plasencia, dos psicólogos del mismo. Se expuso el brevemente la historia clínica de Jonathan, su psiquiatra se pronunció sobre el diagnóstico afirmando que Jonathan presenta claramente un trastorno de personalidad de tipo antisocial, sin ninguna duda, por lo que no reúne perfil para estar en recurso de tipo rehabiliatador y en este caso debe abandonar el piso donde se encuentra y que no existe recurso en la Comunidad donde pueda ser derivado. Se pregunta por mi parte si existe algún recurso en otra comunidad Autónoma dodnde pudiera ser canalizado, contestando que al parecer así es y que se puede solicitar dicha canalización. pero que esto tardaría un tiempo y él debe abandonar el piso en dos días, además de porque ha perdido la plaza porque esa plaza ya está adjudicada y hay un usuario listo para ocuparla que se encuentra en el Centro Socio Sanitario. Se plantea que una solución puede ser que se le oriente a un Centro de transeúntes ante esta propuesta yo expreso que esa opción no me parece adecuada que Jonathan debe de estar en un Centro, como así se hace mención en el punto quinto de los Fundamentos de Derecho de su Sentencia de Incapacitación. “ En su informe el Medico Forense recomienda la permanencia de Jonathan en un Centro que permita la supervisión intensiva, puesto que su limitación intelectual y la inmadurez e impulsividad representan un riesgo importante para sí mismo y para los demás...” Jonathan aunque actualmente no consume ninguna sustancia tóxica , como consecuencia de la supervisión que se tiene sobre él en el CRR. Mantiene cierto hábito de consumo por lo que podría ser susceptible de ingresar en una comunidad terapéutica de esta forma se trataría el problema del consumo y además se le estaría proporcionado un ambiente controlado, al parecer en las comunidades terapéuticas habitualmente hay usuarios con el mismo trastorno de Jonathan (trastorno de personalidad antisocial ) Se concluye que se le intentará agilizar la cita que se solicitó en su día al CEDEX para iniciar tramites hacia el ingreso en Comunidad Terapéutica y paralelamente se procederá a pedir la canalización a un recurso en otra Comunidad Autónoma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2014-10-08','En el día de hoy se recibe llamada de LA Técnico PIA de Plasencia para preguntar en que zona se solicita la plaza de Rosario, por lo que a continuación se relaiza llamada a Lola Venegas, que es la Trabajadora Social que ha realizado el informe de Rosario para tener en cuanta su opinión pues es quien conoce la situación con más detalle. Lola informa que a ella le parece lo más adecuado que no se le cambie de centro pues supondría un desarraigo muy importante para ella. Pero que hablará con la Técnico de plasencia. A los pocos minutos envía un correo electrónico donde informa que se pedirá plaza pública por la zona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2014-10-08','En el día de hoy llama Jonathan desde el CRR (927 423337) para comentar que sabe que ha perdido la plaza que tenía y quiere saber donde le vamos a llevar. Pregunta si puede tener otro móvil pues el que tiene se le ha roto, le digo que eso no depende de mi y que tendrá que hablarlo con el centro. Dice que lo está pasando mal, que no quiere regresar al "psiquiátrico". Le informo ue aún no se sabe el centro donde irá y que deberá acceder voluntariamente al que se le proponga.','2');
