insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2014-10-18','Se da de baja el contrato con Canal Plus, telefónicamente, con Raquel Rodríguez del depertamento de bajas (902.11.00.10) . Se solicita que se nos envíe copia del contrato. Se informa de que se penalizará con 222 Euros en concepto de deuda por intalación pues se comprometió a permanecer con el servicio 18 meses. Segun aparece en la clausula 3 y 4','2');
