insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2014-10-21','Desde que Luis Miguel entró en el Centro penitenciario se le ha pedido prácticamente a su hermano felipe que vaya a su domicilio a buscar ropa para él.Obteniendo múltiples excusas un día tras otro. Hoy se le pide la llave de la vivienda de forma tajante.Para poder ir nosotros a recogerla','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2014-10-21','Se nos informa desde el Centro de Don Benito que ayer regresó hermeregildo del pueblo y esta mañana se le ha informado de los castigos que se le aplicarán por habese marchado la última vez sin permiso: - No podrá volver a salir a tomar café por la manaña - No podrá salir ni disponer de dinero hasta el 5 de noviembre. Tras recibir esta información se ha marchado del Cntro y no saben nada más de él. Se esperará un tiempo prudencial y si no aparece se pondrá denuncia','2');
