insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2014-10-27','En el día de hoy se realiza llamada telefónica a Teresa, médico de atención primaria de Valdeobispo para saber como estaba Josefa, me cuenta que no sabe nada pues ha ido a visitarla pero no había nadie en el domicilio, porque deben estar en el campo.Que ella nunca ha tenido ningún problema con la tutelada, que siempre ha sido muy colaboradora y que sí es cierto que necesita un centro con urgencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2014-10-28','En el día de hoy se mantiene reunión con dos técnicos de la Dirección General de Infancia y familias al objeto de buscar recurso para Minerva. Se les comunica que no hay ninguna plaza libre de RAL. Se propone, que continúe el tiempo que pueda en el CAM y si hubiera que salir se le podría solicitar Servicio Residencial a la par que continúa en lista de espera para RAL, ampliando además los centros de esta solicitud siguiendo el siguiente orden: 1º Aprosuba 7 (Mérida) 2 Aprosuba 9 ( Villafranca) 3º Aprosuba 1 (Zafra) 4 Aprosuba 3 ( Badajoz)','2');
