insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2014-11-05','En el día de hoy se visita la UHB para visitar a Consuelo, cuando llegamos al hospital nos comunican que se ha marchado esa misma mañana a la UME a Plasencia. Que creen que su familia no le ha llevado la ropa para el ingreso en la UME. A continuación se realiza llamada al CSS para preguntar si tiene alguna necesidad, nos informan de que de momneto no y que si así fuera nos lo comunicarían.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2014-11-05','Nos entrevistamos con el médico de familia de Ventura, le solicitamos informe actual. Informa que ha cambiado mucho, que lo ve muy bien, con buenos hábitos de vida pero que desconoce si pudiera ser manipulado por otras personas y que en ese sentido realizará el informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2014-11-05','Se realiza llamada telefónica a su madre, le pregunto donde vive Hermeregildo y me informa que vive en su casa con ella, que es ella la que corre con sus gastos, que su nieto le ha comprado unas zapatillas y algo más pero que la que soporta sus gastos es ella. Que además tiene a 6 personas comiendo en casa y que el dinero no le llega. Se le pregunta donde quiere que viva Hermeregildo, que si quiere que vuleva al CAMP , que se quede en casa, que vaya a otro centro...expresa que no quiere que regrese al CAMP pues allí no está bien, que le gustaría que le diesen plaza en otro centro, por ejemplo el de Cabeza del Buey, bien medio pensionista o interno pues allí lo tendría más cerca. Se le explica que ha de pensar bien la decisión y que en unos meses no se arrepienta y llame diciendo que le ha echado de casa como ya sucedió en le pasado.','2');
