insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2014-11-12','- TF 699634246-689024423 - HAY QUE VISITARLA CADA DOS MESES APROXIMADAMENTE. NO ACEPTA LAS VISITAS DE FUTUEX. - NO PODEMOS HACER SEGUIMIENTO INDIRECTO, SOLO ACEPTA LAS VISITAS DE AMALIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2014-11-14','Se mantiene entrevista con José Moreno, la información que aporta es la siguiente: - Ha estado de vacaiones desde el 23 de octubre hasta el 9 de noviembre. - Que ha estadoe n Almoharín casi todas las vacaiones excepto el lunes 3 de noviemmbre que fue a recibir la charla de la policía y el fin de semana anterior a incorporarse al trabajo. - Que está muy contento en el Hostal, la comida es muy buena, la dueña muy amable. Y hay unos doce estudiantes allí que comparten espacios comunes. Aunque tienen una relación muy superficial límitandose a pequeñas charlas en la hora de la cena. - Este fin de semana se marcgha a su pueblo,el domingo va de ruta con el grupo de senderismo de Almoharín, esta vez van a Quintana de la Serena. - Se ha apuntado a gimnasia en la Universidad Popular, acude lunes y miércoles. - Tiene en Cáceres un amigo, paisano, con el que queda algunas tardes para ir a dar de comer a sus perros. - Que está muy ciontento,que no quiere volver a ningun piso tutelado. - Que José Mª Tovar le ha llamado varias veces y él se pone muy nervisoso cuando esto ocurre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2014-11-19','Se recibe llamada telefónica de Rosario Ortíz, técnico de menores para presguntar por Jonatha. Se le informa de los recursos por los que ha pasado y que actualmente (desde el 2 de octubre se encuentra en proyecto hombre de plasencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2014-11-19','Se renuncia a la plaza del CAMP de Don Benito, ante la negativa del tutelado a regresar al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2014-11-20','-Tras la llamada tf de Vanesa en la que nos comunica que ha tenido un enfrentamiento con la familia de rumanos con la que vivia y que esta en el albergue de Málaga se contacta inmediatamente con ellos. -Se solicita plaza de discapacidad por decreto puesto que no está valorada por dependencia. -se pide plaza en albergues de Extremadura a la espera de la plaza para hacer el traslado desde Málaga cuanto antes , se está relacionando con malas compañías. Se coordina traslado para el Albergue de Don Benito . -EL dia del mismo Vanesa se niega en rotundo , tiene novio allí ( Miguel ) y van a buscar una habitación para los dos . -Se contacta con Vanesa telefonicamente sin resultados. -Contacto nuevamente con el albergue que me informa que la preja duerme en la calle y acude al centro a comer y a ducharse y que ambos se niegan al ingreso en centro de nuestra tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIO'and edp.apellido1='CARRETERO'and apellido2='HERNANDEZ'),'2014-11-24','Se llama por teléfono al Centro y hablamos con Mª José con motivo del alta en la UDAC del tutelado. Nos informa que fueron a recogerlo el jueves, que viene más o menos igual que se fue". Se le explica que durante su estancia en la UDAC, se le ha denegado permiso a su tía y al acompañante de esta (Felipe) para que salgan con él fuera del centro. El motivo es que la tía no está en condiciones de hacverse cargo de él y el "cuidador" realmente no ha tenido nunca relación con el tutelado. Además en la última ocasión en la que José Mario salió con ellos volvió bastante desestabilizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2014-11-26','Comunica Angela Trabajadora Social que está ingresado en la UHB de Plasencia, que con motivo de las obras de rehabilitación que se están llevando a cabo en San Gil se ha trasladado a Plasencia y desde esta fecha está bastante alborotado. Rompe Grifos, lámparas...Hablamos de la posibilidad de derivarloa la UDAC, me comentan que se lo están planteando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2014-11-27','-Vuelvo a llamar al albergue de Málaga para poder hablar con Vanesa que acude sólo a comer y duerme en la calle con su compañero Miguel .Mantengo entrevista motivacional para intentar paliar esta situación , y le progongo alternativas . Me doy cuenta que ella no va a decidir sola , todo va a depender de Miguel con lo que cambio de estrategia y mantengo entrevista con este . Me comentan que han estado mirando un estudio pero que no tienen el dienro para el alquiler (350E)y la fianza (350€). En el albergue ya no les dejan ni comer , como medida para presionar a Vanesa a aceptar el recurso propuesto desde la Comisión en Extremadura. Hoy dilubia en Málaga y los han acogido en el salón del albergue pero no tienen plaza para dormir allí . Tras varias gestiones bancarias y negociaciones con ellos , se procede a mandarles un reintegro de 350€ esta mañana para que hoy mismo se trasladen al piso de alquiler . La arrendadora acepta esperar al dia 9 para cobrar el resto que es cuando Miguel percibe 426€ de la RAI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2014-11-27','-Se acuerda con ellos que se les dará 357€ al mes , correspondiente a la PNC de Vanesa para cubrir la mitad de los gastos de vivienda +comida+agua+luz. Se comprometen a enviarnos justificantes de pagos a trabés de la Trabajadora Social .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2014-12-01','-tf Maria 653514284 cita en cadex badajoz el dia 5 de diciembre','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2014-12-01','En el día de hoy se recibe un correo electrónico de Fernanda (Trabajadora Social )para informar que Saúl se ha marchado esta misma mañana acompañado por su padre y su tío, al centRO. que iba muy contento y que todo ha sido muy cordial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2014-12-01','Se mantiene conversacion telefónica con José Luis dueño del piso, para decirle que Luis Miguel Interrumpe el contrato de alquiler. Nos dice que le debe unos 1000 Euros con los dos meses que le debe de abonar ahora por no continuar con el contrato y algún mes más que le debe del verano. Le pregunto si la fianza se la va a devolver y me explica que dependerá como haya dejado el piso.','2');
