insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2014-10-31','En el día de ayer se mantiene entrevista con Teresa Trabajadora Social de Novaforma y Mª Carmen Hoya, directora del Centro de día.En la primera parte de la reunión se nos informa sobre su trayectoria e historia familiar.Las relaciones con su madre nunca han estado exentas de problemas aunque reconocen que en los últimos meses ésta responde a los requerimientos del centro. Explican que Álvaro sólo sale de casa para asistir al centro que no sale ni los fines de semana. Creen que será mejor citar a la madre en las dependencias del servicio territorial por darle más oficialidad a la entrevista pero dudan de si se presentará. Nos facilitan el teléfono de una tía suya, Victoria quien ha llamado al centro para interesarse por Álvaro en difererentes ocasiones. Desde que murió su padre las relaciones con su hermana no han existido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOTO'and apellido2='DURAN'),'2015-01-12','Se llama al centro residencial donde se encuentra José Soto y nos informan de que llegó el día 10 tal y como habíamos acordado con su hijo. Que viene muy contento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2014-01-14','-Pto establecido : -120€ aportación para gastos de manutencion a la madre por transferencia . -30€ semanales para gastos personales , sobre todo tabaco. -extras de 100€ durante un par de meses , el de enero se hará la semana que viene para terminar de pagar deudas del pueblo . -facturas de farmacia y podologia se pagarán por transferencia .','2');
