insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2015-02-25','- A Eva se le transfieren mensualmente 400€ de su cuenta de Montijo en la que está ella sola a otra en Pueblonuevo donde está con su suegra . Es la suegra la que retira los reintegros . De estos 400€ , 150 son para aportación a los gastos de la casa , 35 € se quedan en la cuenta para pagar el movil y 185 son para Eva , para sus gastos de tabaco y demás. Esto se hace desde abril 2014. Los gastos extras son a parte .','2');
