insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2015-08-19','Se fuga del Centro a las 8:30 Hs. Antes de escaparse estaba nervioso, con temblores y muy alterado. Decía que se iba a escapar al igual que ha hecho en algunas de las ocasiones en las que se ha marchado. A las 11:22 Hs. le trae, al Centro, la Policía Nacional. Se encontraba en la estación de tren de Villanueva de la Serena y hábía sacado un billete para ir a su pueblo, Cabeza del Buey. Refiere que, cuando se escapó del Centro fue al lugar de trabajo de uno de sus hermanos que reside en Don Benito y le pidió 10€. Suficiente para comprar el billete de tre par ir a su pueblo. Continúa nervioso y con temblores, al igual que esta mañana. Una vez en el centro se le toma muestra de orina y se envía al CEDEX de Don Benito para que sea analizada. Desde el día 2 de agosto, hasta hoy, se ha fugado en doce (12) ocasiones del Centro Ntra. Sra. de las Cruces, de Don Benito. Ver informes posteriores Centro Ntra. Sra. de las Cruces, entre el 19 de agosto y el 21 de septiembre.','2');
