insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ROMERO'and apellido2='VERA'),'2015-10-06','Hemos autorizado a la Asociación de Gestores Culturales de Extremadura para que puedan captar y utilizar las imágenes fotográficas y audiovisuales en las que aparezca, tanto en la página web de la Asociación, como en las salidas, excursiones y/o visitas que pudieran realizarse, y/o en todo proyecto que se esté llevando a cabo, para argumentar el trabajo que se hace desde la Asociación y así mostrarlo, en interés de los fines de atención a las personas con discapacidad intelectual propios de la citada entidad. Dichas imágenes no podrán ser objeto de tratamiento ni usarse para finalidades distintas en las que se autorizan.','2');
