insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2015-10-13','ASUNTO: ABONO FACTURA SES por ingreso en H. Virgen de la Montaña (5357.60 euros). ++++Comunicación con Piedad, hermana de Jesús Bermejo (606-424930). Han recogido una carta del buzón, de fecha 20 de agosto de 2015, reclamando el SES el pago de la factura. Nos la envía por fax. ++++Comunicación con ASISA Cáceres (Regino. 927-225355). Enviaron carta certificada denegatoria del cargo de fecha 23 de julio (parece ser que firmó Sebas). En el expediente no aparece dicha carta.Nos la remitirán por correo-e junto con el certificado de recepción. ++++Comunicación con Jesús Martínez,Jefe de Sección Cargos a Terceros del SES (927-256171). Se le comunica la situación y nos indica que caso de no aceptar ASISA el abono de la factura, hay que SOLICITAR A MUFACE LA REUNIÓN DE LA COMISIÓN MIXTA (MUFACE/ASISA)desde la CTAEx como responsdables de Jesús Bermejo Tello: solicitar la documentación requerida para ello a Jesús Barriga, delegado de MUFACE (927-750510)y hacer la solicitud desde CTaex. En esa Comisión Mixta se aclarará quién debe hacerse cargo de la factura). +Com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2015-10-14','Conversación telefónica con Toni (Futuex). Al parecer, la cuenta conjunta con su padre se ha podido cancelar. Paloma figura sola con la CTAEx en la cuenta que se le abrió desde aquí. Según Toni, el padre ha pedido al banco una tarjeta (crédito o débito¿?) y le ha dado otra a Paloma. Hemos pedido extracto de moviminetos al BBV. Toni intentará averiguar algo más sobre el caso. Ayer llamaron de la Empresa que presta el SAD diciendo que se le adeudan los tres últimos meses del servicio y que si no se paga lo suspenderán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2015-09-23','Ingreso, el día 22/09/15, en la Granja Terapéutica "Arca de Noé". No aportó documentación alguna al ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2015-10-14','Conversación telefónica con Jesús Martínez (Jefe Sección de Cargo a terceros del SES. 927-238961). Solicitar a Muface la reunión de la Comisión Mixta (Muface/Asisa) argumentando que: +++++++++El ingreso se produjo ante una situación de emergencia vital (ver informes médicos) +++++++++Asisa no dispone en toda la C.A. de Extremadura de un centro con capacidad para prestar asistencia psiquiátrica con carácter de urgencia. ************************************************************ Conversación con Muface Cáceres. Director Jesús Barriga. (Telef.927-750520. Correo-e: jesús.barriga@muface.es. Dirección: Muface Cáceres/Avda. Virgen de la Montaña 13,1º/10002. Cáceres). Valorarán la solcitud de CTAEx y: ****caso de dar la razón al mutualista, nos lo comunicarán y se pagará la factura sin necesidad de convocar a la Comisión Misxta; ****caso de dar la razón a Asisa, entonces queda abierta la opción de recurso de alzada; ****si no se llega a un acuerdo en la Comisión Mixta, se convocará la C.Mixta Nacional. Si se le da la razón al mutualista, termina el proceso; si se le da la razón a Asisa, cabe nuevamente recurso de Alzada. ************************************************************Conversación con Piedad, hermana de Jesús Bermejo(606424930). El ingreso fue motivado por una fuerte descompesación de Jesús, acompañada de delirios que no remitía con la medicación. Antes del ingreso acudieron a la consulta del Dr.Sevilla, en Plasencia, quien aconsejó su ingreso en el H. Virgen de la Montaña. La familia no tiene ningún informe al respecto. Jesús llevaba 11 años sin necesidad de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2015-10-14','Estancia en su domicilio familiar -Villanueva del Fresno (Badajoz)- los días 9, 10, 11 y 12 de octubre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2015-10-15','Nos hemos ratificado en la herencia de sus padres el día 17/9/2015. Como consecuencia de ella, vamos a abonar, en concepto de plusvalía, 47,12 euros al OAR de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='RIVERA'and apellido2='DONAIRE'),'2015-10-15','Hemos acudido a la notaría de Juan Manuel Ángel Ávila, en Badajoz, para la disolución de comunidad de la herencia de sus padres, el día 25/09/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2015-10-16','Se envía por correo ordinario la solicitud de convocatoria de la Comisión Mixta Provincial y documentación complementaria que figura en el expediente. Valorar cambio de Muface a Seguridad Social para que no veulva a suder lo mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2015-10-08','Acuden a la CTAEx Ramón, con su hermana y con Manuel Martínez Gómez (un residente en los pisos supervisados de Rosalba que dice ser amigo suyo. Teléfono 633961413).Los atendemos Verónica y yo (Pedro). La hermana dice que quiere hacerse cargo de la tutela de Ramón y traen una carta del Colegio de Abogados de Badajoz dirigida a Ramón en la que se solicita la documentación necesaria para asignar letrado y procurador del Turno de Oficio en respuesta a la solicitud de asistencia jurídica gratuíta realizada por Ramón (esta carta es de fecha 07 de septiembre de 2015, por lo que el plazo de 10 días para remitirla ya se había pasado y se habría denegado la solicitud y procedido a su arrchivo). Se llama al Colegio de Abogados de Cáceres y hablamos con Daniel (927-951051): tienen que volver a solcitarlo. SE autoriza a Ramón a sacar 40 euros para comer y volver después a Jerez. A lo largo de la mañana vuelve otra vez diciendo que su hermana se ha quedado el dinero, aspecto que no se puede confirmar. Desconocemos las intenciones de su hermana para hacerse cargo de la tutela...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2015-10-16','Inicio de la asistencia al C.O. de Aprosuba 7 de Minerva, a la que tenía que llevar su padre (D. Víctor, 638295086). Verónica ha acudido en representación de CTAEx pero D. Víctor no ha llevado a su hija. Desde CTAEx hemos tratado de hablar con él para saber los motivos de dicha ausencia pero el teléfono disponible está apagado o fuera de cobertura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2015-10-16','Le reclaman desde la financiera del Banco Santander Consumer (teléfono 911773230), 3.479 euros por la compra de una motocicleta. Puestos en contacto con la financiera, le hemos hecho saber que se trata de una persona incapacitada, que necesita nuestro consentimiento para realizar este tipo de gestiones. Van a enviarnos el contrato y para ello remitimos a scpostventaclientes@santanderconsumer.com el D.N.I y la Sentencia de Incapacitación de Ricardo. Mientras tanto, dejan en suspenso la reclamación de la deuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2015-10-16','Constitución de Tutela por Sentencia 60/2015, de 12 de mayo de 2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2015-10-16','Juzgado nº 4 de Mérida. Llama Isabel (924-387375) solicitando el informe que al parecer se requirió a CTAEX en mayo de 2015 para informar sobre la remoción de tutela de D. Diego solicitada desde los juzgados de Villafranca. Consultado el expediente no parece constar dicha petición. Se solicita a Isabel la remisión nuevamente de dicha solicitud y se proporciona nº de fax de CTAEx para su envío, además de por correo ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2015-10-19','Ayer ingresó en la UCI del Hospital de Mérida donde continua ingresada. En la visita realizada la médico de la UCI, Mª Luz Moro, nos ha comentado que no sabe hasta que punto ha podido faltar el oxígeno al cerebro.Durante nuestra estancia allí le retiran la respiración asistida y en el momento de la visita respira autónomamenmte.Están pendientes de realizar un electroencefalograma. El pronóstico no es bueno. Llamo a su hermana Mari Luz, que me dice estar de camino a Mérida. Llamo a Coro, CSS Mérida, para informar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2015-10-19','Reunión en CSS Mérida con el psiquiatra de Juan (Isaac) y la T.Social (Blanca). Posteriormente también con Juan y su pareja (ingresada en UME, pendiente de alta). Juan y su pareja quieren irse a vivir juntos a casa se Juan, en Torremejía. Isaac y Blanca están de acuerdo en intentar dicha posibilidad. Se descartan las alternativas de CRR y pisos tutelados por la premura y deseo de convivencia de ambos. Condiciones: +++Permiso de tres meses, con supervisión en CSS de Mérida cada 15 días (al menos durante el primer mes)y visitas semanales de FUTUEX al principio (solicitarlas). Desde el CSS enviarán informe con la propuesta indicando el comienzo del permiso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2015-10-20','Conversación con CRR Badajoz. Leonor (924-231645). Se "aparca" por el momento la posibilidad de relación laboral de Aquilino con la empresa Stanhom (limpieza y cosmética), dado que, según informe de CRR de Badajoz, no se considera un actividad que se estime terapéutica en estos momentos. Se informa a Ana (agente de Stanhome. 651-320534) que de momento no se autoriza dicha relación. Hablo con Leonor (CRR): se puede plantear nuevamente el tema en la reunión del próximo día 4 de noviembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='SANCHEZ'and apellido2='GARCIA'),'2015-10-20','Disfrutará de unos días de vacaciones en el domicilio familiar. Del 20/10/2015 hasta el 03/11/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2015-10-20','Llamo a la UCI de Mérida para preguntar por Luisa: tiene una encefalopatía por anoxia cerebral de muy mal pronóstico. Solicitan firma de consentimiento informado parta prácticar traqueotomía. Se les envía firmado. Reunión con Soledad, Mari Luz y Sergio (hermanos de Luisa). Acuden protestando por la atención recibida por su hermana, por no haber sido avisados antes de las circunstancias, solicitando su traslado a Badajoz y una segunda opinión. Regresan sobre las 13:00h exigiendo que solicitemos una segunda opinión y su traslado a Badajoz, solicitud que no se va a hacer salvo que la petición venga del hospital o del juzgado. Dicen que presentarán denuncia ante el juzgado (se les informa del juzgado que es 1ª instancia e instrucción nº 4 de Mérida). Durante las entrevistas preguntan indirectamente por el dinero de su hermana: "puede costearse el traslado","se lo va a quedar hacienda". Y también preguntan por sus efectos personales, a lo que se les reponde que su hermana sigue viva. Se marchan muy enfadados, asegurando denuncia ante el juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2015-10-09','Se plantea a Manuel Zambrano la carta al director (Periódico Extremadura del 7 de octubre) enviada supuestamente por nuestro tuetelado, por si fuera suceptible de respuesta por parte de Gabinete de Prensa previa consulta con Gabinete Jurídico de la Junta, al revelarse datos de carácter personal del tutelado por CTAEx','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2015-10-20','En fecha 15/10/2015, ha sido trasladada su residencia desde la Escuela de Animación Libre a APROSUBA-3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2015-10-21','Nos informan de la Dirección del CSS de Mérida de la denuncia interpuesta por la familia de Luisa. Acude a la CTAEx el Inspector de la UDEV (CNP) D. Bernardino (924-387469// merida.udev.policia.es). ************************************************************* UCI. Hablo con Daniel, médico que atiende a Luisa. Hoy se le ha realizado la traqueotomía. Se encuentra en "estado vegetativo persistente". Si la situación se mantiene estable le darán el alta de la UCI en uno o dos días y pasará a planta (nos lo comunicarán por fax). Han ido a verla sus hermanos y el padre.','2');
