insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2015-10-21','Nos comunican el fallecimiento de su padre en el día de hoy. Hablar con Pilar (ESM Cáceres)para ver situación de Ceferino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2015-10-22','Se llama a Mari Luz (657-267607)para informar a la familia del alta de Luisa en la UCI y su traslado a planta. Se encuentra ingresada en Neurología, en la habitación 327 (cama 2).El traslado a planta se se producirá a lo largo de la tarde y según el enfermero con el que hemos hablado (Miguel)sería aconsejable que se quedase alguien de acompañante. Se intenta contactar con el CSS para que nos aconsejen alguna de las personas con las que allí cuentan para estas labores de acompañamiento pero dicho contacto no es posible. Hablo con Mari Luz y con Soledad (697-172137) y me dicen que esta noche se quedará su hermano Sergio. Les digo que a partir de mañana intentaremos encontrar a una persona que pueda desempeñar dicha labor si ellos no pueden. Soledad me pregunta que quién va a apagar a esa persona y si estará cualificada para ello. Considera que no debe ser su hermana la que lo pague, sino la Junta por ser su tutora. Me insiste en que ya ha puesto la denuncia en el juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2015-10-22','Nos comunican desde el Centro Sociosanitario de Mérida, que en la última salida que ha tenido a Badajoz con su hermana,ha pedido un cuchillo en un bar y se ha personado en la cárcel de Badajoz.El director de la misma, contactó con el CSS comentando que no sabe si la intención era ir contra un cuñado que está en la cárcel o contra una ATS de la que se obsesionó, durante el periódo que él cumplió condena. Pasan nota al psiquiatra con el fin de limitar sus salidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='LUCAS'and apellido2='LUCAS'),'2015-10-23','Llamada telefónica de Teresa (Supervisora de Enfermería.615962070). Ha sido el padre de Luisa el que se ha quedado con ella esta noche, no su hermano Sergio. Al parecer ya ha comentado con el equipo sanitario el tema de la "querella" que han puesto. A Teresa le digo que cualquier aspecto a tratar sobre Luisa debe ser puesto en conocimineto de la CTAEx y si la familia quiere saber algo que contacten con la Comisión. Respecto al acompañamiento, cree que no es necesario durante todo el día. Considera más oportuno que lo haya a partir de las 20-21h y hasta el cambio de turno. Alternativas cuando se pueda dar el alta a Luisa: derivación a una plaza T-1 (Rosalba, Almendralejo...). Hablaré sobre ello con Nuria (T.S. del Hospital: 81159,81610,81041 y 924-381014). Llamo a las empresas de servicios ADIPER (120euros/noche; 315 euros V-S-D) y SADEX (80 euros/noche). SE contrata a esta última con previsión de seguir requiriendo sus servicios. SE avisa a Teresa (supervisora de enfermería) y a Soledad (hemna de Luisa).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2015-10-26','Se recibe en CTAEx informe desfavorable, de la Comisión de Valoración del CSS de Mérida, al traslado de José Luis desde el CSS Plasencia al CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2015-10-26','Está hecha la derivación a CRR. En estos momentos no hay plaza, y hay otra persona, además de Ceferino, solicitante también de plaza por emergencia. Hablo con PIlar (ESM Cácers):hablará con Juan Pedro (Psiquiatra) por si fuera posible un ingreso temporal en UHB de Plasencia, para que no se quedara solo en casa hasta ingreso en CRR. También se plantea la posibilidad de que se quede con su hermano unos días hasta dicho ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2015-10-26','Llega a CTAEx resolución de MUFACE Cáceres en relación a la reclamación sobre el cargo que, de la asistencia de Jesús entre el 27 de enero de 2015 y el 04 de febereo de 2015 debe costear la aseguradora ASISA. La resolución es favorable a Jeús y ASISA costeará la asistencia prestada.','2');
