insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2015-11-03','Conversación mantenida con Mª Ángeles, Enfermera del ESM de Talarrubias (924-648100, martes y jueves//// Vva. de la Serena 924-847327, lunes, miércoles y viernes). Carmelo tiene cita pasado mañana, 5 de noviembre. Actualmente hay un Psiquiatra suplente, David, que va a tener su primera consulta con él pasado mañana. Carmelo quiere la remoción de la curatela, aspecto este que solicito tengan en cuenta en la consulta programada. MªÁngeles opina que quizá no sea un momento adecuado para solicitar la remoción porque, si bien es una persona autónoma, la edad va haceiendo que pierda facultades: "cuando le hemos preguntado en otras ocasiones cuál era el nombre de su tutor nunca lo recordaba..." Quedo en llamar pasado mañana para hablar con el Psiquiatra (solo pasan consulta los martes y jueves).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2015-11-03','La entidad bancaria Santander Consumer Finance, S.A., le reclama 90.697,92 euros, en relación con la Ejecución Hipotecaria nº 106/2013 (PROCEDIMIENTO 3472MV). Al no hacer frente a los pagos, el banco se queda con la vivienda tras subastarla. Para no echar a Ventura del piso solicitamos un alquiler social al banco, hablamos con maria.mar.roman@lindorff.com 914847850-ext 342067. Antes de proceder a ello el banco necesita inscribir la vivienda en el registro a su nombre, tras el Decreto de Adjudicacion que se produjo el 19/10/2015. Una vez inscrita, la entidad va a solicitar la posibilidad del alquiler social, aunque tras conversación telefónica, nos indican que va a resultar muy difícil, ya que la vivienda estaba a nombre de su exmujer, Josefina Baltasar Rivas con dni 07013397-F.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-11-03','Conversación con Alicia Naharro. Tiene la maleta hecha pero no se puede ir porque dice que no tiene dinero. No le pueden obligar a quedarse porque no es un centro cerrado ni tienen medios para ello. Conversación con Silvia (Futuex): dice que se va mañana cuando le autoricemos a sacar dinero de su cuenta. Conversación con Juan: "No aguanto más aquí, hecerme una una autorización para sacar dinero de mi cuenta y coger mañana el autobús para ir a Zorita con mis primos." Le pregunto por la familia de Zorita, pero solo me dicen que son unos primos que le acogen sin problema. Le pregunto que si ha hablado con ellos y están dispuestos a atenderlo pero solo insiste en que ellos lo acogen sin problemas.','2');
