insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2015-11-05','DEBIDO A SU SITUCIÓN ECONÓNICA, JESÚS DEL PISO DONDE ESTÁBA EN ALQUILER POR ESTE MOTIVO Y PORQUE LA DUEÑA NO QUERÍA ESTAR CON PERSONAS DE ESA PROBLEMATICA. SE INTENTÓ BUSCAR UNA CASA DE ALQUILER PERO NO HA SIDO POSIBLE DEBIDO A QUE LOS PROPIETARIOS NO QUERÍA ALQUILAR A PERSONAS TUTELADA NI TAMPOCO QUERÍAN REALIZAR CONTRATOS. LA CONSECUENCIA DE TODO ESTO ES QUE HA TENIDO QUE IRSE A VIVIR AL ALBERTE-HOSTAL LAS VELETAS DE CÁCERES. MIENTRAS SE LE ESTABA BUSCANDO UNA VIVIENDA SOCIAL PERO NO ES POSIBLE POR TODO LO QUE CONLLEVA ECONÓMICAMENTE (ENGANCHES DE LUZ,AGUA, INMOBILIARIO,ETC), QUE EL NO PUEDE PERMITIRSELO. ESTÁ EN UNA SITUACIÓN ECONÓMICA MALA. TIENE DEUDAS CON COFIDIS. COMO NO PUEDE HACERSE CON EL PISO, SE HA DECIDIDO POR AHORA QUE SIGA VIVIENDO EN EL ALBERGUE HASTA QUE SE ARREGLE LA SITUACIÓN O ENCONTREMOS UN HOGAR QUE PUEDA HACERSE CARGO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2015-11-06','CATALINA VIMO PARA PEDIRNOS PERMISO, PARA QUE VIVIERA CON ELLA UNA PERSONA QUE ACTUALMENTE ESTÁ EN EL CSS DE MÉRIDA, SE LLAMA MIGUEL TELLEZ.ME COMENTA DESDE EL CSS QUE HASTA EL MOMENTO A ESTA PERSONA NO SE LE DARÁ EL ALTA. LLAMO A CATALINA PRA COMENTARSELO Y NO PONE NINGÚN TIPO DE PROBLEMA. A LA VEZ ME PREGUNTA SI VUELTA LA ANTERIOR COMPAÑERA QUE SI PODRÍA VOLVER A VIVIR CON ELLA. LE DIGO QUE SI ELLA ESTÁ AGUSTO CON ELLA, NO HAY NINGÚN PROBLEMA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-11-06','NOS COMUNICA LA TRABAJADORA SOCIAL DE BASE DE GUADALUPE QUE ACTUALMENTE ESTÁ EN EL DOMICILIO FAMILIAR DE LA LOCALIDAD. AUNQUE LOS HERMANOS NO ESTÁN DE ACUERDO CON LA SITUACIÓN. SE LES COMUNICA QUE SI EMPIEZA A CREAR PROBLEMAS SE LE AVISE AL 112 O GUARDIA CIVIL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2015-11-06','Ingresa en UHB. Causasse nos inform el día 5 de noviembre que se ha mostrado agresivo con un usuario ( le ha propinado una colleja), amenzado al monitor, y ha renunciacio a cumplir al contrato refereente a dieta y deporte. En la salida anterior le cogió 100€ a la hermana que restituyó la madre. Ayer accede voluntariamente a ser valorado por el Psiquiatra que lo deriva a la UHB donde está ingresado. Referenta a la devolución a la madre de los 100€ ya que se gestiona la pensión desde el CRR una vez retorne o se reubique se planificará la forma en varios plazos de devolución de esa cantidad a la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2015-11-06','Informa que se le ha descorchado el techo de WC, se le pide que envie por fax fotografía.','2');
