insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2015-11-06','Tras conversaciones con el Centro Regional de Reinserción de Plasencia (Consuelo Izquierdo, Psicóloga: 927-420448) y con los ESM (Ana, T.Social:927-458036) y de CEDEX Plasencia (Puerto, T.Social: 927-427129 y fax 927-414760) se solicita desde CTAEx Informes de ambos Equipos para valorar el recurso más adecuado para D. José María. Consuelo comenta que, en caso de que dicho recurso tardara algún tiempo, nuestro tutelado podría quedarse en el Centro hasta un par de meses más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2015-11-06','Lllaman de Novaforma (Teresa, T. Social)diciendo que la madre de Álvaro se ha presentado con la abuela y una tercera persona para llevarse a su hijo el fin de semana. Al parecer no han podido contactar con la madre desde nuestra última conversación y no le han podido plantear la salida de un solo día, volviendo al Centro por la tarde. Están muy alteradas, amenazando con llevarse a su hijo por la fuerza. Pido hablar con la madre pero ella se niega a ponerse al teléfono. Teresa plantea que le autoricemos la salida para hoy, pero ante la negativa de la madre de volver a llevar a su hijo por la tarde al Centro no se autoriza dicha salida. En caso de alteración de la convivencia en el Centro se llamará a la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2015-11-09','Conversación con Teresa. El fin de semana tranquilo. El pasado viernes, tras nuestra conversación, siguieron los incidentes en los mismos términos (voces, insultos, etc.). Plantearán nuevamente a la madre, María José,las salidas de un día con retorno por la tarde. Si no se acepta, las visitas se deberán realizar en el propio Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='CAMPOS'and apellido2='ROJO'),'2015-11-09','Nos comunican, del CSS de Plasencia, el fallecimiento de Dª Francisca Campos Rojo la tarde del viernes 6 de noviembre de 2015. Contacto familiar: Gloria (sobrina: 658-604366). ES probable que nos llame para tratar la declaración de herederos. Dª Francisca tiene 2 hijos: una hija, ingresada en la Hermanas de la Caridad de Plsencia y un hijo que vive en Málaga. La compañía Ocaso se ha hecho cargo de todos los gastos del funeral (al parecer la familia tiene un nicho en propiedad).','2');
