insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2015-11-09','Llama D. Juan insisitiendo en que ya se tiene que ir a su casa porque sus hermanas ya han sacado de allí lo que tenían y la Comisión no tiene nada que ver con ellas. Cree que se va a ir ya y no es consciente, al parecer, de que la familia no quiere que vaya al pueblo: la reunión prevista con las hermanas para el 5 de noviembre fue aplazada por ellas hasta después de Navidad al no poder acudir ese día. Llamo a Blanca para informarle de las "intenciones" de D. Juan. Informará a su vez a Isaac (Psiquiatra).','2');
