insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2015-11-06','ingreso uhb voluntariamente. Había agredido( colleja) a un compañero y amenzado monitor. Roto el contrato terapeutico referente a dieta y deporte. Ultima salida cogió 100€ a la hermana que repuso l madre.Acordamos la devolucion con la TS. Blanca en varios plazos una vez vuelva al centro.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2015-11-10','EL JUZGADO HA ENVIADO UNA DILIGENCIA DE ORDENACIÓN AL CENTRO RESIDENCIAL DE PLASENZUELA DONDE SE ENCUENTRA INGRESADA PARA QUE INFORME CADA SEIS MESES DEL ESTADO EN QUE SE ENCUENTRA. NOSOTROS CONTINUAREMOS CON NUESTRA DECLARACIÓN ANUAL.','2');
