insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2015-11-10','SE RECIBE COPIA DE LA DENUNCIA INTERPUESTA POR UN MONITOR DEL CRR DEBIDO A UNA AGRESIÓN DE FELIX. ESPERAR COMUNICACIÓN DEL JUZGADO SI SE DA TRAMITE A LA DENUNCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2015-11-10','HABLO CON SU PRIMA MARIA LEBRATO (616 337 245) SOBRE LOS PASOS A SEGUIR PARA TRAMITAR LA LIQUIDACIÓN DE HERENCIA DE SUS ABUELOS. LE INFORMO QUE NO NECESITAMOS AUTORIZACIÓN PREVIA DEL JUZGADO SINO APROBRACIÓN POSTERIOR DE LAS PARTICIONES HEREDITARIAS. ME DICE QUE SE PONDRÁ EN CONTACTO CON LAS PARTES PARA RETORMAR DE NUEVO EL TEMA EN LA NOTARIA DE JEREZ DE LOS CABALLEROS POR NUESTRA PARTE YA TENEMOS EL TESTIMONIO DE LA SENTENCIA Y ACEPTACIÓN DEL CARGO QUE ES LO QUE NOS HARÍA FALTA. QUEDO A LA ESPERA DE QUE NOS AVISE CUANDO YA ESTÉ TODA LA DOCUMENTACIÓN EN LA NOTARIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2015-11-10','EL JUZGADO DE 1ª INSTANCIA Nº 4 DE MERIDA PROPONE SU INHIBICIÓN AL ENVIAR LA RENDICIÓN ANUAL CORRESPONDIENTE A ESTE AÑO POR ENCONTRARSE FELICIANO RESIDIENDO EN DON BENITO. CONTESTAMOS AL JUZGADO QUE NO NOS OPONEMOS A LA INHIBICION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2015-11-10','CENTRO SOCIOSANITARIO PLASENCIA ha realizado un plan psicológico donde se incluye una restricción de visitas. -Madre/padre cada 15 días Y LA MADRE debe de ir acompañada siempre del padre. -EL SOBRINO de José María tiene restringidas las visitas independientemente de con quien vaya acompañado. -las salidas siempre debe de ir acompañado de personal del centro. CAUSAS: -la madre desestabiliza a José María siendo solo en presecia del padre cuando la madre, no bombardea con problemas de indole económico y familiares. -Sobrino: Padro (psicóloga) informa que jose mari padece de impulsos sexuales. El sobrino que es menor de edad tiene 16 años es sindromico y la madre de Jose Mari los ha enviado al wc creyendo que puede realizar tocamientos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-11-10','Información remitida al Juzgado de Logrosán sobre la situación actual de D. Juan (Fax: 927-158093; teléfono:927-158082).En conversación con el agente del Juzgado se me informa de que el primer escrito enviado por fax ha sido ya remitido por el Juez a la Fiscalía. Se adjuntará a quel el enviado también hoy por fax. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación telefónica con Dª Mª Carmen Chamorro (hermana, 927-367528). Está muy asustada: procura no salir sola de casa, ha vuelto a ir a por los niños al colegio, sale acompañada del trabajo, etc. Se le informa de las medidas a tomar ante la más mínima incidencia, para que quede constancia de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2015-11-11','Ingresado en el Sociosanitario de Plasencia en virtud de las medidas cautelares establecidas en el Auto nº 151/15, de 20/10/2015, del juzgado 1ª inst. e inst. nº 4.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2015-11-10','Aceptado compra dos tarjetas pre-pago orange, una para él y otra para la madre. El pago se realizará a través de su asignación mensual. NO EXTRA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2015-11-10','Se recibe carata por fax (924-433005// correo-e: teresa.barco@hotmail.com) de Dª Teresa Barco, madre de D. Ricardo, preocupada por su situación económica (gastos que le suponen las visitas a su hijo), por la posibilidad de que sea él el que vaya a verla y por su futuro si recibe el alta del Centro Socisosanitario de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2015-11-11','Llama Dª Teresa (924-230543/// 659-064628) para avisar de que han entrado a robar en la casa de Ricardo y ahora mismo está sin puerta. Iremos a poner denuncia y la presentaremos al seguro de Ocaso para ver si entra la reposición de la puerta. La vivienda, propiedad de Don Ricardo (no debe vivir allí, y menos solo): Margarita Xirgu nº3, 1ºA. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Visitamos el domicilio, en el que hablamos con una vecina, Dª Carmen H.(669889331).Se adjuntan al expediente fotografías del destrozo de la puerta de la vivienda. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se presenta denuncia en la Comisaría de Policía y se envía a la compañía Ocaso como adjunto mediante correo-e (jjcorchuelo@hotmail.com). Se habla con Javier Corchuelo (645-985967) para ver la posibilidad de arreglar, siquiera provisionalmente, la puerta del piso antes de las tres, pero dice que ya tiene que ser por la tarde o mañana por la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-11','AYER SE PRESENTÓ PAR DECIRNOS QUE NO TENÍA DONDE VIVIR. SE LE BUSCÓ PARA QUE FUERA AL CENTRO DE TRANSEUNTES Y ESTE NO SE HA PRESENTANDO A DOMIR. NOS PIDIÓ 70 EUROS PARA COMPRARSE UN MÓVIL, SE PRESENTÓ EN LA TIENDA DE VODAFONE PERO AL FINAL NO TENÍA EL DINERO SUFICIENTE PARA COMPRARSELO Y SE HA COGIDO UNA TARJETA PREPAGO POR 15EUROS, SEGÚN NOS DIJERON EN LA TIENDA PARA PONERLA A UN MÓVIL DE SU TÍA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2015-11-11','Conversación con Cristina Lancho (Gerente territorial Cáceres). Hay que trasladar a Dª Sofía de residencia, ya que el convenio finaliza el 31 de diciembre. Nos pide no hacer nada de momento por nuestra parte. La CTAEx está dispuesta a aceptar la propueta que se haga con el único límite del bienestar de Dª Sofía respecto al trasalado. Queda pendiente hablar de otros tutelados.','2');
