insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-12','Hoy se han presentado en la CTAEx la madre y el hermano de Jonathan, informando de las amenazas sufridas por su madre en la tarde-noche de ayer que llegaraon a ser incluso amenazas de muerte. Su hermano comenta que está durmiendo en la calle y cree que también está consumiendo, por lo menos porros. Se les indica que pongan la denuncia y que nos traigan una copia de la misma para ponerla en conocimiento del Juzgado. A las 15:00 no habían vuelto a aparecer por la Comisión Tutelar.','2');
