insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2015-11-17','Como Ceferino no es titular de su cuenta corriente y causa del fallecimiento del padre la cuenta está congelada. se inician los trámites para abrirle una cuenta y pedir un cambio en el ingreso de su prestación a la futura cuenta.','2');
