insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-11-17','A través de la TS. de Guadalupe, Raquel , Juan se pone en contacto con nosotros para comunicar que no ha podido sacar los 50€ semanales estupulados ya que solo quedaban en la cuenta 28€, los cuales le ha entregado la entidad. Se había gestionado la devolución de la mensualidad y gastos de bolsillos de Feafes. Debía varios adelantos por parte de feafes de Gastos de Bolsillo, por lo cual estos han hecho una devolución de 108€. La TS. una vez finalizada la entrevista con Juan, nos informa la situación de pánico y miedo que vive el Pueblo. Se le comunica que se le ha realizado un escrito a Juez.','2');
