insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-19','Se solicta cita en CEDEX Mérida (día 20-11-2015, a las 10:00h) y cita en ESM. de Mérida (pdte. de recibir).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2015-11-19','Llamo a ATI (625-245891) pero salta el contestador del teléfono. Me llama a continuación. Gastos: +++++Aporta a sus padres una cantidad que no me determina. +++++ONGs: ACNUR (17e.), UNICEF (19 e.) y Save de Childre (30 e.) +++++Teléfono de contrato. +++++Tarjeta: dice que no la usa y que la tiene solamente por si algún día tiene algún problema con la cartilla. Dice que en caja Rural de Extremadura no la tiene operativa pero sí en los cajeros del BBVA. +++++Seguro deceso: 5 euros/mes Dicen quedarle 200-250 euros para sus gastos. Se le nota tranquilo y su madre, DªAraceli, dice que se encuentra muy bien, que se toma la medicación. El propio Ati dice que cuando se le "aturrulla" la cabeza se toma un transilium y se le pasa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2015-11-19','la semana pasada informó que había comprado dos crias de cabras, a lo que se informó que debía de salir de su asiganación el pago del chip. Posteriormente después de telefonear de forma alterada y amenazando se le autorizó al pago de compra de leche en polvo para las crias, 50€. Hoy nos informa que los veterinarios lo han denunciado por no tener la documentación de las crias. Se le informa que dicho pago tendrán que salir de su asignación. Que cuando reciba la notificación de la multa nos la envie por fax','2');
