insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2015-11-18','RETORNO Ingresó en la UDAC de Plasencia el 29/06/15. Ha causado alta en dicha entidad el 16/11/15. Ese mismo día, reincorporación al Ctro. Ntra. Sra. de la Luz de Badajoz, en los srvicios de Residencia y Centro Ocupacional.','2');
