insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2015-06-29','Ingreso en la UDAC de Plasencia. Efectivo el día 29/06/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-20','Tiene cita en CEDEX hoy a las 10:00h. Acudimos a dicha cita pero él no se presenta a pesar de las llamadas realizadas a primera hora de la mañana a su móvil, a las cuales contesta. +++++++Se le pide también cita en Salud Mental: día 28 de diciembre a las 11:40h. +++++++Se solcitará informe a los SSB de Mérida para poder empadronar a Jonathan, al no tener dirección propia ni fija. +++++++Tiene que recoger la medicación recetada por el Psiquiatra, José Gómez, en la visita realizada por urgencias la semana pasada y en la que se derivó a CEDEX y ESM. SE le iban a entregar hoy, pero no ha sido posible al no presentarse a la cita en Salud Mental, a pesar de las llamadas a su móvil desde el propio Centro De Salud, llamadas en las que el teléfono estaba apagado o fuera de cobertura. Queda pendiente la entrega de dicha medicación, de la que tenemos dudas se vaya a tomar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2015-11-19','Consulta en el Servicio de Urología del Hospital de Mérida. Se le hace exploración y clínicamente existen dudas acerca de la conveniencia o no de intervención quirúrgica para reitar sonda vesical: se le pide cita para ecografía y se indica a la Auxiliar que lo acompaña del CSS de Mérida que se compruebe en el Centro la funcionalidad de la vejiga "taponándola" durante el día y dejándola por la noche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2015-11-09','Se propuso desde menores el acercamiento de la madre a a la localidad de Zafra donde el hijo cursa estudios Antonio Tomillo. Desde el programa de familia la comisióntutelar no vimos adecuado el tralado por dos motivos, El desarraigo que le provocaría a Felisa, ya que en su localidad está orientada e integrda y porque no existe un recurso institucional donde la madre e hijo convivan ( no es viable ni economicamente ni personalmente el alquiler de vivienda). Se nos informa que Felisa ha comenzado una relación sentimental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2015-11-23','Desde el PF. están trabajando el tema de las relaciones sexuales y métodos anticonceptivos. Se considera oportuno la colocación del DIU. EPF Mancomunidad Tajo Salor sigue trabajando el tema de su hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2015-11-23','Concha se pone en contacto con nosotras, porque ha solicitado que se le compre ropa y se le deniega, por lo cual quiere el alta. El control economico se realiza desde el crr Mérida, no obstante nos parece adecuado que con la paga extra (cobra pnc) se le de un extra. Comunicamos con el crr (Gisela) nos comenta que ultimamente se altera y pide el alta se le pasa con el director que la tranquiliza. le indicamos que nos parece apropiado que con la paga se le otorgue un extra ACUERDO CR: nos comunicarán pr email o teléfono la actuación que van a realizar referente a lo hablado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICANOR'and edp.apellido1='IÑAÑEZ'and apellido2='CORTES'),'2015-08-25','Regreso del Hospital de Mérida en fecha 24/08/2015. En el turno de tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CASIMIRO'and edp.apellido1='IÑAÑEZ'and apellido2='CORTES'),'2015-07-17','Traslado y regreso del Hospital de Mérida en fecha 16/07/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2015-11-23','Se solicita al 112 el traslado de D. José María Guillén Román desde su domicilio en C/. Espadón nº 10, 1ºA al C.Sociosanitario de Plasencia para su ingreso involuntario por orden judicial. Se indica, como persona de contacto para dicho traslado, a su hermana Dª Ana (609-060640). Miguel Ángel (hermano, 669-794813 y 91-3233713). También acudira al traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOTO'and apellido2='DURAN'),'2015-11-23','Se acude a la cita del Juzgado en el día de hoy. Se le condena a: +++++ 52 días de trabajos en beneficio de la comunidad. +++++ 2 años y 1 día de prohibición de tenencia de armas. +++++ 3 años de alejamiento de su hija Fernanda a una distancia mínima de 200 m y a cualquier otro tipo de contacto con ella. +++++ indemnización de 120 euros por lesiones (ansiedad). Todo ello en sustitucióen de la pena propuesta de 9 meses de prisión. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Desea hacer testamento. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Desea denunciar que los hechos que se le imputan son falsos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-23','No se presenta en la oficina del DNI, por lo que tampoco se le ha podido dar la medicación prescrita. No ha acudido a pesar de llamarlo varias veces por teléfono (salta el contestador y se deja mensajes).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-24','Acude la la CTAEx. Trae el recibo del banco (transferencia móvil). Se le da la medicación prescrita y se le explioca su administración. Se le da la cita en ESM para el 28 de diciembre a las 11:40 y quedamos el día 1 de diciembre a las 8h en la puerta del SEPAD. Le llamaremos cuando tengamos la cita para DNI. Preguntado por la falta a la cita de cedex no sabe explicarla.','2');
