insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2015-11-25','Situación Maria Luisa. Ha fallecido su madre en Octubre. Se notificará a judirico CTAEx. La hija y nieta de Maria Luisa han vuelto a vivir con esta, son elementos desestabilizadores, aunque actuamente está estable. Desde futuex nos comunica que han solicitado informes psiquiatricosde Maria Luisa, los cuales nos enviarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2015-11-25','Informe ssb: La hermana Carolina está regularizando la tramitación con la Seguridad Social: dar de baja PF(ya que la madre de Maria Luisa era la titular) y solicitar la orfandad total','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2015-11-26','Convesración con Amparo, Directora CM "El Campillo" (Asistida Cáceres). Teléfono 75287. Hoy, a las 10:00h se realiza el traslado de Dª Sofía a la residencia de Deleitosa. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Contacto T. Social SSB Deleitosa (630-555887). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Territorial de Cáceres: Isabel Ceballos (927-004239)y Pina (74325). Isabel Ceballos (Territorial de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2015-11-26','Nos Informa Blanca(psicóloga crr) que se acordó que con las pagas extra navidad se pagaría una deuda contraida con un compañero de 100 euros. Solicitan 100€ para ese pago, más 100€ para ropa ANOTACIÓN PSICOLOGA CRR:Félix Figueroa tiene dos deudas en total 200 euros. La deuda de la madre está saliendo de sus pagas aún no ha sido pagada en la totalidad. La deuda con el compañero viene de junio y se acordó con ellos que saldría de la paga extra. Con lo que ahora pagaría 150 euros, quedando 50 euros para el mes que viene. Estamos trabajando la responsabilidad de Félix en la asunción de deudas teniendo en cuenta las dificultades de abordaje por nuestra parte ya que ante cualquier indicación que perciba como límite su estilo de afrontamiento es agresivo. ACEPTADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JESUS'and edp.apellido1='DE LA OSA'and apellido2='DE LA OSA'),'2015-11-26','SOLICITAN CRR 100€ DE LA PAGA EXTRA NAVIDAD PARA ROPA. ACEPTADO','2');
