insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='CACERES'and apellido2='CABANILLAS'),'2015-10-30','Se le informa que de momento se le deniega la compra del ordernador, ya que es para realizar un curso de aprendizaje del mismo, se le indica que realice uno presencial. El motivo es que se aisla con su novio en la habitación y no se relacionan ni con la familia ni exterior. Una vez hecho el curso se volverá a valorar la adquisición del mismo.','2');
