insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2015-11-26','Conversación con Magdalena Nieto (45609), T.Social Centro Residencial "Juan Carlos Rodríguez Ibarra", de Villafranca de los Barros. Traslado previsto el 01 de diciembre. En viar la documentación disponible (DNI, T. Sanitaria, nº póliza seguro deceso, cuenta corriente, etc) a la siguiente dirección: C/. Cuba s/n. 06220. Villafranca de los Barros. Toni habló también previamente con Mario, el Director de la residencia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2015-11-27','Conversación con Marta, Enfermera de la Residencia de Deleitosa (927-540159). Ha ingrsado sobre las 11:30, enfadada porque no quería estar allí: se quería ir a su pueblo y hablar con Pedro. Quedo con Marta en que mañana, si lo cree conveniente, me llame y me ponga con Dª Sofía para hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2015-11-25','Conversación con Montse, T. Social de la Residencia de Deleitosa (927-540126. 656-843976). Mañana se realiza el traslado desde Geryvida en Cáceres. Se le informa de la PNC que tiene Dª Sofía y se le indica alguna de las características personales de ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2015-11-26','Ayer intemtó sacar 1500 euros del banco sin que se lo permitieran (llamaron a la Comisión para informarnos).Conversación con Ati.Se justifica diciendo que era para no tener que estar yendo al banco todos los días. Todos los meses da a su madre 600 euros y para Navidad le da otros 200 como regalo. Como no pudo sacar los 1500 euros, sacó (al menos) los 600 para pagar a su madre con la tarjeta, que se le ha dicho que se le va a anular, pero el se opone a ello). Pendientes a la respuesta de la Fiscalía al escrito enviado por Mª José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2015-11-26','Conversación con D. Víctor, padre de Minerva. Necesita 200 euros para comprarle ropa. Quedamos en que mañana ha de llevar a Minerva a Aprosuba 7 y que hemos notificado al Juzgado que sigue hasta hoy sin llevarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2015-11-27','Conversación con María (Directora Aprosuba 7). Han estado allí y Minerva se ha mostrado encantada cunado le han enseñado el Centro y lo que puede hacer en él. Le han explicado el punto de recogida diario y la hora en la que tiene queestar en él. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con D. Víctor. Dice (sin mucho entusiasmo quizá) que sí, que a Minerva le ha gustado y que han quedado en que la llevaría a partir del lunes. Se le autorizan los 200 euros para ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2015-11-27','Hablamos con Juan José sobre el dinero del que va a disponer a partir del 01 de diciembre: podrá sacar 200€ los días 1 y 16 de cada mes (400 € en total al mes). Se muestra de acuerdo con ello y quedamos pendientes de hablar sobre el presupuesto para el dentista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-11-30','Llama Jonathan desde un fijo (924-304538) que, según dice, es de una amiga: se le ha roto el cargador y el móvil lo tiene sin batería (llamo al móvil y salta el contesdtador). Quiere que llame a su Hemano Antonio (687-969982) porque quedaó en hacerlo él para quedar en el banco "...y si no le llamo igual no acude pensando que no voy a ir". Llamo a Antonio: dice que su hermano ha vuelto con la chica que estaba antes y que él no quiere saber nada con ella ni con su familia... Confirmamos que mañana acudirá con su hermano al Juzgado de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2015-11-30','Se envia por fax al Programa de Familia de Tajo-Salor, la autorización para la colocación de Diu.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2015-11-30','Llama Pedro (T.Soc. CSS de Plasencia): un sobrino de D. Juan ha llamado preguntando por el testamento de su tío. Se le indica que caso de volver a llamar, le diga que se ponga en contacto con la Comisión.','2');
