insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-11-30','Hoy a las 12:00 horas había prevista una reunión entre Juan y la delagada de Futuex para ver las necesidades de Juan. Este no ha asistido. Nos enviarán informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2013-01-11','Se recibe fax del Juzgado de 1ª Instancia nº 002 de Coria acordando la firmeza del auto 183/12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2015-11-30','Paloma lleva 6 meses sin cobrar la PNC, actualemente coge las cantidades de dependencia. TS Jerez de los Caballeros(Inma): 924730270/607564251 SE ENCARGARÁ ALBERTO DE CONTACTAR CON BBVA Y PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2015-11-30','Conversación con Almudena (T.Soc. Aprosuba 10. 924-891012). El informe emitido de fecha 19 de noviembre tiene un carácter básicamente informativo, de dar a conocer el episodio de agresividad protagonizado por Agustín. El informe anterior de octubre refería que se encontraba bien en el centro, participaba de las actividades, etc. En este momento, desde Aprosuba10 no se pretende tomar decisión alguna al respecto, ni se solicita intervención de la Comisión: seguirán observando el comportamiento de Agustín y comunicarán cualquier incidencia que ocurra. Almudena comenta que en alguna ocasión Agustín le ha dicho que se quería cambiar de Centro, para al cabo de cierto tiempo pedirle que, "...cuando te diga esas cosas no me hagas nunca caso. Si yo estoy muy bien aquí...". Creen que está empezando a actuar como en el CAM: formando una especie de grupo de "acólitos" a su servicio. No se tiene constancia de ello, pero lo están teniendo en consideración por las repercusiones que ello pudiera tener en un futuro. Seguiremos en contacto para cualquier cosa que se necesite desde Aprosuba 10 y que esté en manos de la Comisión facilitar.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2015-11-30','ENVÍO CARTA PARA ADJUDICACIÓN DE VIVIENDA EN CÁCERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LUJAN'and apellido2='PIMPOLLO'),'2015-11-30','ENVÍO DE CONSENTIMIENTO MÉDICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2015-12-21','Hablo con Mariluz sobre el tema de traslado desde CSS PLsencia a CSS Mérida. Llevará el caso a la subcomisión, aunque considera que no resolverá nada probablemente. En mi sponión, el único motivo para trasladar a D. José Luis sería el que ello supusiera algún beneficio para él, más allá de que la madre tenga interés en ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-12-01','Tras haber quedado la CTAEx con su hermano Antonio en que lo llevaría al Juzgado de Plasencia, Antonio finalmente, el mismo día 1, se niega a llevarlo. Cuando llego a Plasencia el Juicio se ha suspendido (lo comunicaron a la letrada de la Junta en Cáceres pero no a la Comisdión: se ha dado traslado de las actuaciones al MºFiscal a fin de que emita informe sobre la prescripción de los hechos (consta en el expediente copia de dicha suspensión y derivación a Fiscalía).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2015-12-01','Visito a Dª Rosa en la Residencia de Plasenzuela. Me acompaña Rosa, Auxiliar, a su habitación. La encuentro sentada en una butaca, medio de lado y en posición semifetal, con la sonda nasogástrica. Se niega a hablar conmigo cuando me presento como representante de la Junta. Muy enfadada me dice: "No tengo nada que hablar con la Junta. La Junta me ha hecho mucho daño y si eres de la Junta ya sabrás el daño que me ha hecho..." De estos argumentos no sale en mis intentos de mantener una mínima conversación con ella. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Rosa me comenta que desde que llegó en abril no ha consentido en ningún momento en comer, por lo que desde entonces está sondada. Tampoco quiere salir de su habitación, porque la gente y el ruido le molesta mucho. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo también con Greta, Enfermera, por ai tanto tiempo con la sonda no pudiera causarle algún daño. Comenta que no, que desde que llegó Dª Rosa solo en una ocasión se quitó la sonda. El riesgo existiría si se la quitase con frecuencia y hubiese que volver a ponérsela una y otra vez, por el riesgo de erosión e infección que ello conllevaría. Comento que si en estas condiciones Dª Rosa no sufre de estreñimiento, confirmando que así es, más si cabe cuando se niega a salir de la habitación y dar paseos. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Les propongo llevarla al comedor con los demás residentes a las horas de las comidas para ver si, observando a la gente comer y viendo los alimentos (que supongo no ve desde que ingresó, al menos) le puede estimular el deseo de alimentarse por sí misma. Harán la prueba, pero creen que ella se va a alterar al estar entre la gente y el bullicio que se genera. En caso de que se pruebe y no de resultado, se propone que sean las propias cuidadoras las que entren en la habitación comiendo alguna cosa para que Dª Rosa las vea, o que le dejen algún alimento (seguro) en la mesilla al que ella pueda acceder sin estar en presencia de nadie. Quedamos en que llamaré en una semana para ver qué tal ha ido la prueba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2015-12-02','Conversación con Mª Carmen, Directora Residencia (667-891640). Se le informa que ayer se nos comunicó la sentencia por la que se nos nombraba tutores de Dª María, quedando pendiente la aceptación del cargo por parte de la Comisión ante el Juzgado. Se le informa de que desconocemos hasta ahora el estado de las cuentas de Dª María, pero quedamos en esperar a que la Comisión se haga cargo de ellas para empezar a facturar la estancia en la residencia. La Directora me informa de que Dª María llevaba 200 euros a su ingreso y que de ellos se está haciendo uso hasta el momento para sus pequeños gastos (podología, etc.) guardando los justificantes correspondientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2015-11-26','Conversación con Magdalena Nieto (45609), T.Social Centro Residencial "Juan Carlos Rodríguez Ibarra", de Villafranca de los Barros. Traslado previsto el 01 de diciembre. En viar la documentación disponible (DNI, T. Sanitaria, nº póliza seguro deceso, cuenta corriente, etc) a la siguiente dirección: C/. Cuba s/n. 06220. Villafranca de los Barros. Toni habló también previamente con Mario, el Director de la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2015-12-03','Recibimos información de la Residencia "Juan carlos Rodríguez Ibarra" acerca de los intentos de fuga con agresión protagonizados por D. Blas la pasada tarde, que requirieron la presencia de la Guardia Civil y su posterior traslado a la UHB de Mérida donde en estos momentos permanece ingresado. (Ver informes de la dirección del centro, del Médico, T. Social y del Psicólogo obrantes en expediente). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Visitamos a D. Blas en la UHB y hablamos con su Psiquiatra, José Gómez. Considera que la reacción de D. Blas es fruto de una situación estresante que requiere un periodo de adaptación adecuado. Desde su ingreso en UHB la pasada noche no ha causado problema alguno, se le ha administrado tratamiento y se ha mostrado tranquilo y colaborador. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Ante nuestra visita se ha mostrado cordial, tranquilo y dialogante. Ha manifestado en varias ocasiones su deseo de ingresar en alguna residencia de Montijo, próxima a su pueblo. Se le ha explicado que va a permanecer unos días en la UHB, periodo que dependerá de la estimación de su psisquiatra. Se le informa que tras el alta deberá volver a la residencia de Villafranca: entiende que debe tratar de mantener un comportamiento adecuado en ella y que si sigue con la idea de acercarse a su pueblo deberá darnos tiempo para que quede una plaza vacante en Montijo si fuera necesario. Se le propone que vaya alguien de Futuex a visitarlo una vez por semana más o menos, lo que parece aceptar y también se le propone llevarle algunas cosas de su casa para que se sienta más cómodo en la residencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Le haremos una visita a los pocos días de volver a la residencia para tratar de aumnetar su confianza en nosotros. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Mario, Director de la Residencia (640-036926). Le explico la situación de D. Blas, las gestiones con SSB, UHB, la psoibilidad de denunciar los hechos si las compañeras agredidas lo consideran oportuno (no lo van a hacer). Muestra su total colaboración para facilitar la adaptación de D. Blas a la residencia, con la esperanza, que compartimos, de que llegue a encontrase bien y vaya dejando prograsivamente de insistir en su deseo de volver al pueblo (lo cual no descartamos en caso preciso). Se le informa al Director del tiempo aproximado de estancia en UHB y de que contará en su regreso con un tratamiento prescrito por su psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-12-10','Se le autoriza el cobro de la asiganación semanal de 50€ para el viernes 4 de diciembre ya que el lunes 7 es festivo.Se le hace hincapié que no volverá a cobrar hasta el 14 de diciembre','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2015-12-04','Hemos solicitado al Registro de la Propiedad de Mérida, nota simple de las propiedades que Julio Vaquero tenga en Montijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2015-12-04','Telefonea el hermano para solicitar que se le autorice sacar 150€ para gastos y 50€ para comparar ropa interior. Sale con permiso penitenciario hasta el martes. SE ACEPTA EL GASTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2015-12-04','Llama su hermana Mª Socorro (913-582638). Dice que este año no le pueden pagar el desplazamiento porque su madre está mal económicamente este año. "Si no lo podéis pagar vosotros, sintiéndolo mucho, no podrá pasar con nosotros las Navidades". Marisa hablará con Carmen (directora de Aprosuba 3).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2015-12-04','Hablo con Javier Corchuelo (Ocaso): están pendientes de pintar la puerta del piso de D. Ricardo. Quedamos en que el pintor se pasará por la Comisión para acompañarlo y abrirle el piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-12-04','Clara (T.Soc. C.Salud. 924-281204///52809). No está acudiendo al C.Salud. Están tratando de trabajar con él pero no quiere. La próxima vez que acuda a su despacho nos llamará','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2015-12-04','Javier, el Director del CRR de Mérida, nos informa de que ha "aparecido" una señora en el CRR diciendo que era tía de Dª Concepción y pidiendo una serie de datos que, por supuesto, no se le dieron. Posteriormente, hablando con Dª Concepción, se confirmó que nm exitía ningún parentesco entre ellas y que se habían conocido hacía algún tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2015-12-04','Buenos dias, os informo la situación física actual de Vicente Rojo, tutelado vuestro y usuario del piso supervisado. Ayer tras repetirle en 5 o 6 ocasiones en los dos últimos meses ataques epilépticos, y tras consejo de su médico de cabecera, el monitor del piso le acompaña a urgencias, donde ha quedado desde ayer tarde en observación. Nos informaron que la anterior vez que estuvo ingresado por este motivo, le aconsejaron quedar ingresado durante unos dias para realización de un estudio más profundo pero él se negó. Esta vez se lo han preguntado ,y parece que al estar presente el moniotr del piso, a contestado que sí. Nuestra preocupación es que una vez que no esté el monitor presente pueda volver a negarse. Estamos en contacto para cualquier aclaración, un saludo Leonor','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2015-12-04','Residencia:927-448465. Sigue con su insistencia en marcharse. He tratado de hablar con Juana, T. Social SSB (927-448247) pero se ha marchado ya. llamarla la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2015-12-09','Antonia Canelada del Río me pide 100 euros de la paga extraordinaria para realizar un ingreso a su hermano. Desde el centro no ven impedimento. (Caja Extremadura, sita en la C/ Rafael Lucenqui de Cáceres). Pueden hacerlo como los anteriores, mandar la autorización al centro y desde aquí la llevamos al banco. ACEPTADO Marisa en encarga del trámite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2015-12-09','Telefoneamos al hospital de Mérida y desde la UHB (Dr. José Psiquiatria) nos informan que se procede al alta de Blas. El traslado se realizará por la tarde, ya se ha procedido a comunicarselo a la Residencia. Durante la estancia Blas a aceptado las normas y su comportamiento ha sido a adecuado. Se le ha detectado una infección de orina (ya sabiamos con anterioridad, ya que tiene prevista cita con el urólogo), Se le diagnóstica Trastono adaptativo. Lleva prescrita medicacion, restigal y pastillas para dormir. El Dr. José nos informa que desde la Residencia no han puesto ningun incoveniente ni problemas. Hemos intentado hablar con ellos pero nos ha sido imposible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2015-12-09','se envia por fax el consentimiento informado de colocación de de diu.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2015-12-09','Telefonea la hermana María José (629 78 55 81) para informarnos que su hermano está ingresado en agudos en Psiquiatria del Infanta Cristina. Contactamos con el Hopital el Dr. Antonio Guisado nos antiende. Nos informa que hoy lo han traslado de neurología a Psquiatria derivado del psiquiatra de Zona. Se le diagnostica una criss compulsiva de incontinecia urinaria, al principio creían que tenia un delirium tremen, desconocían que era tutelado por la Junta. Estará ingresado de 7 a 15 días. Acordamos llamar para conocer su estado para una interveción en domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-12-11','Ha telefoneado Rosa (TS. Centro de Salud). Referente al control de la medicación a través de la tarjeta, lo ve inviable, ya que es imposible controlar la medicación que saca y aun sacándola no podemos asegurar q la tome.No obstante no le parece ético este tipo de actuación Se le ha pedido que acceda al inyectable a lo cual se niega. Se le informa que vaya al centro de dia para realizar las comidas y tomar la medicación a lo cual se niega','2');
