insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2015-12-11','Telefonea la hermana para comprobar si nos hemos puesto en contacto con el hospital. Nos informa que no su hermano no puede volver a su domicilio ya que tiene una denuncia de los vecinos, ya que lanzço varios muebles y una botella de butano. Que las condiciones de la vivienda no son las adecuadas. Que el hermano realiza grandes ingestas de alcohol y que ha engordado 20 Kg. No está de acuerdo con la actuaciaciación de la Junta y que tomarán medidas. Se le indica que pueden pedir la tutela del hermano y nos dicen que no es posible ya que no se hace caso de ellos. Se le informa que en función de la evolución en el hospital de su hermano dirigiariamos nuestra intervención, pero que hasta el momento había denegado cualquier recurso institucional, como visitas y atención a domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-12-14','Clara (T.Soc. C. Salud. 927-154305).Dice que ha estado allí. En cuanto le hemos solucionado el tema del banco se ha ido. Le han visto en el bar jugando a las máquinas. No sabe si se etá medicando o no, aunque sí ha ido a por la receta electrónica).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2015-12-14','Se recibe en la Comisión solicitud de la hermana de José María, Teresa (927-470279 y 618-819511), a través del CRR de Cáritas de Plasencia, para que su hermano pueda pasar las vacaciones de Navidad con ella desde el 23 de dieiembre al 03 de enero). Dada la poca información que tenemos de la familia, me pongo en contacto con Consuelo (CRR Cáritas) pero tampoco tienen más información que ofrecer que las llamadas que la hermana ha hecho preguntando por José María. Hablo también con Paula, del CRR de Plasencia (927-423978), la cual informa lo siguiente: La familia siempre se ha interesado por el bienestar de José María, si bien a partir de que la Comisión se hizo cargo de la tutela su hermana dijo que quería que su hermano estuviera bien atendido, pero que ella no se quería comprometer ni implicar directamente en sus cuidados. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ En relación a qué recurso consideraría Paula más adecuado para José María ella considera que el principal problema que él tiene es que NO SABE DECIR "NO", lo que le lleva a tener repetidas recaídas en el consumo (y no un consumo cualquiera, sino dierctamente heroína), con lo que cada recaída no es solo un paso atrás, sino "una carrera atrás" para él. Según Paula, el entorno es, por lo tanto, un problema para Jose María, de lo que se deduce que el recurso adecuado sería aquel que estuviera lo más alejado posible de los ambientes que él conoce en Plasencia: CRR de Badajoz, Mérida, Cáceres. No obstante, se puede considerar que quizá sea cosa de tiempo el que José María pueda establecer nuevas relaciones no "adecuadas" para sí mismo allí donde se encuentre. Por su parte, Consuelo (Cáritas) considera que quizá unos pisos tutelados pudieran ser una alternativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='DEAN'and apellido2='SANCHEZ'),'2015-12-15','CORREO DE JOSE MANUEL ESCALONA Desconozco los informes solicitados. Os envío la sentencia y antecedentes. Se ha decretado la curatela del mismo. Ya informé en la vista judicial la dificultad que esto supone para ejercerla máxime cuando D. Julio vive de forma independiente y sin domicilio fijo, cara a conocer y actuar tanto con respecto al tratamiento y medicación como en fase psicótica. Ni la fiscalía ni la Juez parecen ser conscientes de los problemas que plantean en la práctica esta medida. Aceptad la curatela. Sse aconseja -cara a una posible responsabilidad en el ejercicio del cargo- que se ponga en conocimiento del Juzgado cualquier tipo de incidencia (no conocer su paradero, imposibilidad de control de la medicación, falta de colaboración ...) que os encontréis en el seguimiento del caso. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2015-12-15','Conversación con el Director de la Residencia. Enviará informe a Juzgado y Ctaex a final de año. Suben a Dª Rosa al comedor y se pasa allí la mayor parte del día: el peor momento es el de salir de su habitación: "luego se tranquiliza". Sigue sin intención de comer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2015-12-15','Conversación con Teresa (hermana de José María, con domicilio en Jerte, 927-470279 y 618-819511).El año pasado estuvo un par de semanas con ellos en enero sin problemas destacables. Pido a Teresa que, en la medida de lo posible, traten de "controlar" las salidas que José María y su hermano Félix (también pasará las Navidades con ellos), sobre todo en relación al consumo de alcohol u otras sustancias, ya que en este momento José María lleva tiempo sin consumir: Teresa dice que harán todo lo posible para ello y que ellos no suelen salir por la noche, sino por la tarde. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Me pregunta sobre el recurso que le vamos a buscar a José María: dice, rotunda, que en ningún casos sea en el mismo que está Félix (CRR Cáceres) porque José María no puede ver a su hermano, por el comportamiento controlador que Félix tiene, si bien luego se echan de menos y quieren verse. Finalmente, le doy algunos teléfonos de la Comisión.','2');
