insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='GONZALEZ'and apellido2='ROJAS'),'2015-12-18','Nos comunica Daniel (T. Social de Calzadilla de los Barros, 645-916544) que DªCarmen ha estado en el Hospital de Llerena donde ha sido operada de una fractura de cadera. La Comisión desconocía hasta este momento dicho ingreso y tampoco se nos solicitó el consentimiento informado para dicha intervención. Dª Carmen fue acompañada por una hermana y su "cuidadora". Suponemos que no informaron al Hospital de que la paciente estaba tutelada. Una vez dada el alta hospitaliaria y sin informar a la Comisión Tutelar, Dª Carmen fue trasladada a su domicilio en Calzadilla y, de este, a los pisos supervisados de la localidad el pasado fin de semana al comprobarse desde SSB que ella no podía ser atendida adecuadamente en su domicilio: en el piso supervisado hay dos auxiliares, pero no tienen capacidad para que permanezca inmóvil por lo que tienen que sujetarla a la cama. Hablaremos con el hospital de Llerena para ver en qué circunstancias se produjeron los hechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2015-12-16','LLAMA SU HERMANO LUIS MIGUEL 62551439 NOS INFORMA QUE HAY QUE REALIZAR LA PARTICIÓN HEREDITARIA DE SU PADRE YA QUE HAY UNA DEUDA DE UN PRESTAMO Y PRETENDE VENDER LA CASA PARA PAGARLO. LE DIGO QUE CUANDO LLEVE TODA LA DOCUMENTACIÓN ALA NOTARIA NOS DIGA EL OFICIAL QUE LO LLEVA Y HABLAMOS DIRECTAMENTE CON EL PARA ENVIARLE NUESTRA DOCUMENTACIÓN. LA NOTARIA ES EN CÁCERES, C/ VIRGEN DE GUADALUPE. FDO: Mª JOSE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2015-12-22','ENVIAN DEL CENTRO SOCIOSANITARIO CITACIÓN PARA EL JUZGADO D 1ª INSTANCIA Nº 1 DE PLASENCIA POR DELITO DE ABUSO SEXUAL A OTRA PACIENTE. EL JUICIO ES EL 18 DE FEBRERO DE 2016 a las 10:00h. LE ASIGNARÁN ABOGADO DE OFICIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2015-12-22','Se envía respuesta a Manuel Zambrano (68553) al escrito presentado por D. Ventura en la Portavocía de Presidencia. La contestación se envía por correo electrónico (manuel.zambrano@gobex.es). Queda el original en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GARCIA'and apellido2='LLANOS'),'2015-12-22','Conversación con Cristobal y Mª Ángeles, de Aprosuba 8 (924-454727). El sepelio de D. Ángel se realizó el sábado por la tarde, tras realizarle la autopsia por la mañana. Los efectos personales se le entregarán a la familia y el dinero que tenía en metálico se ha ingresado en el banco. La ropa la donarán. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Juan Diego (sobrino, 667-503761 y correo: jdpachon78@yahoo.es). Lo llamo para darle el pésame y que lo transmita a la familia. Quedamos en que enviará la factura de la Funeraria a la Comisión. Le envío la dirección a su correo a petición suya. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ D. Ángel García Llanos : Descanse en Paz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2015-12-22','Conversación con Mª Ángeles (Aprosuba 8, 924-454727).Eva les confesó que era había sido ella la que había subido las fotos a Facebook y que, además, llevaba un tiempo acosando a un muchacho del pueblo de su expareja (Pueblo Nuevo). Al parecer, este muchacho no ha puesto denuncia alguna al respecto. Las medidas que han tomado para resolver el problema han sido las siguientes: restricción de las llamadas al móvil, restricción de las salidas del Centro y además en compañía, y eliminación del acceso a internet mientras se trabaja con ella la situación generada. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Mª Ángeles me informa de que Caja Rural de Montijo (924-454452)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2015-12-23','LE DAN LA LIBERTAD, EL PRÓXIMO DÍA 8 DE ENRO DEL 2016. SE LE HACE UNA TRANSFERENCIA POR PECULIO DE 600 EUROS. LE ACOMPAÑA EL CAPELLA´N DE LA CENTRO PENITENCIARIO A A ESTACIÓN DE AUTOBUSES. SE VA A BADAJOZ A CASA DE SU TÍA COSUELO, SE LE HA LLAMADO PERO EL MÓVIL NO DA LLAMADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2015-12-23','LLAMO A SARA, LA PROPIETARIA DEL BAR PARA COMINICARLE QUE SI LAS PRÓXIMAS FACTURAS SON TAN ALTAS, NO SE HARÍAN LOS PAGOS. DESPUÉS HE LLAMADO A LA RESIDENCIA DONDE SE ENCUENTRA Y SE LO COMENTO A LA DIRECTORIA, Y Y ME PASA CON ÉL PARA ECHARLE UN POQUITO LA BRONCA PARA QUE NO SÉ GASTE TANTO EN CAFÉ Y TABACO. EN LA MISMA LLAMADA LA DIRECTORA ME COMUNICA QUE LE HAN DIAGNOSTICADO A MANUEL UN TUMOR DE VEJIGA Y ESTÁ CONSTANTEMENTE HACIENDOSE PRUEBA. LE DIGO QUE TODO INFORME MÉDICO QUE LE VAYAN DANDO, NOS LO ENVÍEN A NOSOTROS PARA SABER DE SU SITUACIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2015-12-23','Hablamos por teléfono con Maribel (TS IMas 927 627 138), para informarla de la situación de Vetura respecto a su solicitud del SAD. Queda paralizada hasta que sepamos cual sea su nuevo domicilio. ACUERDO: enviarle a ella la documentación. Nos informa que la ex pareja de Ventura, Mari Angeles está en el 3er. grado en el cif de Zamora en un piso tutelado de la caixa. Tiene una propuesta de matrimonio de un chico marroquí y ha manifestado que se marachará a Alicante. No abre las cartas que le envía Ventura. el hijo de Mari Ángeles sigue viviendo en Cáceres en casa de los padres de su novia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2015-12-23','Hemos intentado contacatar con el Dr. Guisado (Psiquiatra del Infanta Cristina) lo cual nos ha sido imposible. Teresa la delegada de Futuex ha contactado con la hermana de Manuel, para quedar y ver el domicilio. Maria José le informa que el Psiquiatra le ha dicho que seguirá ingresao estas fiestas. También le manifiesta que la situación que tiene su hermano es causada por la CTEX.','2');
