insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2015-12-23','Hablamos con Cristina TS Centro penitenciario. Rafael se encuentra en el programa de PAIEM. Acordamos realizar una visita, para acordar modelo de interveción una vez se realice la salida del centro. (Barajamos la posibidad de un albergue en un primer momento)','2');
