insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO MANUEL'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2015-12-29','Visita de D. Domingo Díaz. No se le ha contestado a su escrito de junio de 2015 solicitando rebajar el alquiler de este año de 170 a 140 euros/año. Quedamos en redactar un contrato en el que se regule el alquiler y se acepta que para 2015 ingrese 140 euros como renta de las tierras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2015-12-29','Visita de D. Domingo Díaz. No se le ha contestado a su escrito de junio de 2015 solicitando rebajar el alquiler de este año de 170 a 140 euros/año. Quedamos en redactar un contrato en el que se regule el alquiler y se acepta que para 2015 ingrese 140 euros como renta de las tierras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2015-12-29','Llamada telefónica de Dª Antonia (651-391899), hermana de D. Antonio.Información que facilita: +++Ella está viviendo con sus hijos en una residencia de estudiantes de la UP, tras haber sufrido su piso un incendio hace unos días y haber sido alojada inicalmente en el Hotel Cervantes por parte del Ayuntamiento de Badajoz al alargarse la reparación de la vivienda. +++Su hermano está durmiendo en casa de un amigo desde el día 23, pero dicho amigo se marcha unos días con sus padres. +++Solicita buscarle a Antonio una habitación en el Hotel Cervantes, pero necesita dinero porque el pago es en efectivo, ya que no se puede quedar con ella en la residencia porque no se lo permiten. Solo necesita el alojamiento, porque ella puede cocinar en la residencia de estudiantes y estar con su hermano durante el día. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Servicios Sociales de Badajoz: Yolanda Herrera (T. Soc. 924-478516) y con José Antonio (Coordinador de los SS. 924-210150). Confirman el episodio del incendio, la estancia inicial en el hotel Cervantes y la estancia actual de Dª Antonia en la residencia de estudiantes. Confirman que Dª Antonia siempre intenta sacar dinero. En cuanto a que D. Antonio se pueda quedar en la residencia comenta que el Ayto. no tiene capacidad para decidir aceptar o no estancia de otras personas ya que solo se ceden al Ayto. dichas instalaciones en situaciones de emergencia como la actual. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Eva, hija de la propietaria del Hotel Cervantes (Mª José, 924-223710). Pasará allí la noche del 29, 30,31 y 1 y volverá al CSS de Mérida el día 2 de enero.Le dejo a Eva varios teléfonos de la Comisión por si esta noche hubiera alguna incidencia.El hotel se pagará por transferencia a la cuenta que se indique en la factura, la cual deberá ir a nombre de D. Antonio. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo nuevamente a su hermana quien, de motu proprio, dice que le pagará el taxi de regreso. SE le informa de las gestiones con el hotel y hablo tambiénb con D. Antonio para que no salga del hotel por la noche salvo que vaya acompañado de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2015-12-30','Conversación con Maribel (Psiquiatra CSS Mérida, 924-388193). Se fue de permiso el día 23 de diciembre. Lo recogió un taxi. Le dieron 300 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2015-12-30','Llamo al Hotel Cervantes. Hablo con Eva: Antonio acudió al hotel y ha pasado la noche sin problema alguno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2015-12-30','Llamo al Hotel Cervantes. Hablo con Eva: Antonio acudió al hotel y ha pasado la noche sin problema alguno.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2015-12-30','Visita de Jonathan (10:00h). Refiere que ha estado en los calabozos, por agresión a su "novia", desde el sábado 26 al lunes 28 de diciembre, día en que se celebró juicio rápido, imponiéndole orden de alejamiento, según dice, de 200 m. de ella. No trae la documentación del Juzgado ni sabe el juzgado que intervino. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Dice que ella le está acosando a él, que se va a venir a vivir al "Peri" y que entonces el tendrá que salir de su casa...Dice que se va a ir unos días a casa de un amigo (si es cierto, creo que no es por este suceso, sino porque se quiere divertir estos días). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Quiere dinero extra porque "tengo ganas de juerga..." a pesar de lo preocupado que hasta este momento se ha mostrado, llorando incluso al principio de la conversación. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Volverá a casa y trerá la documentación del juzgado +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Tiene pendiente cita en salud mental (hay que pedirla) al no acudir este pasado día 28 por los motivos citados. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Pendiente volver a pedir cita para hacerse el DNI. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Autorizar extra de 50 euros para hoy. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Vuelve con los siguientes documentos del Juzgado de 1ª Instancia e Instrucción nº 4 de Mérida: ***Acta de Información de Derechos al Investigado. ***Auto de 28 de diciembre y Sentencia nº 142/2015 dictados en el Juicio Rápido 0000069/2015 (V. Dom.).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2015-12-30','Se pinta la entrada de la vivienda. Pintor: Antonio (Pinturas Lele, 636-479390).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2015-12-29','Se recibe informe de la Residencia "Padre Damián". Archivado en su expediente, tanto electrónico como en papel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-01-04','Visita de Mari Loli.Temas: +++Dificultades de convivencia con Emi. +++Seguro de la vivienda: no quiere Caser porque dice no entrar el tema de fontanería. Prefiere Santa Lucía u Ocaso. +++Dice estar desanimada (se le nota), quizá por lo conflictos mewncionados con Emi. Dice quererse marchar a casa pero reconoce que allí no va a seguir el tratamiento, ni le apetece cocinar, ni come... +++++++++ Hablo con Beatriz, Psicóloga del CRR (924-304538) sobre esta visita. confirma que Mari Loli está en una fase de decaimiento, pero que entra dentro de lo habitual en su situación debida también a las dificultades que ocasionalmente surgen en relación a la convivencia entre ellos. Hablaré con el CRR sobre todo ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-04','Confirmo con la Sección de Discapacidad: tiene nuevamente concedida plaza en "Las Cruces" desde julio de 2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2016-01-04','Conversación con Hotel Cervantes (Mª José y Eva): D. Antonio ha tenido un comportamiento correcto durante su estancia en el Hotel, respetuoso y agradable con todo el mundo y no ha salido ninguna noche. Nos enviarán la factura para su cobro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GARCIA'and apellido2='LLANOS'),'2016-01-04','Llamada de Juan Diego. Enviará la factura por correo electrónico y ordinario. Pregunta por la forma de pagarla y dice que la familia se presta a abonar aquello que sea necesario si su tío no tuviese suficiente dinero en su cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GARCIA'and apellido2='LLANOS'),'2016-01-05','FALLECIDO El 18/12/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-01-05','Se entrega Nota Interior para Subcomisión de Casos para asignación de recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-01-05','Conversación con directora de Aprosuba 8. Convocamos reunión para el día 14 de enero de 2016 a las 10:00.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GARCIA'and apellido2='LLANOS'),'2016-01-07','Hemos recibido la factura del sepelio de Angel 3.249,20€, se acordó con la familia que aportaría la cantidad que Ángel no tuviese en cuenta. Marisa inicia los tramites: verificará la cuantia a aportar por cada uno, dejando una provisión para pagar las pensiones indebidamente cobradas, que nos puede reclamar la seguridad social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2016-01-07','Telefonea (671710359) para comunicarnos que el lunes no pudo sacar su asiganación y necesita pagar al Podologo y Dentista 50€ en total. Solicita que se le de un extra ya que viene su hijo de Bilbao el 19 de enero ya que no pudo venir en las fiestas. Marisa la informa que la delegada tutelar que la acompaña está de vacaciones y se incorpora el lunes. En referencia al Extra es imposible ya que cuenta con saldo de 300€ en cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2016-01-07','Se acuerda solicitar PF., se comenzarán los tramites este mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTIN'and edp.apellido1='POZO'and apellido2='CANSECO'),'2016-01-11','Se envia por Fax consentiento informado para punción biopsia, el 7 de enero. Se envia por correo postal el original en 11 de enero','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2016-01-07','Telefonea para pedirnos autorización para sacar 280€ que le han ingresado sus primos de Barcelona para Reyes. Marisa realiza la comprobación en el banco y NO le han ingresado nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2016-01-07','Llamamos a Teresa de Novaforma 927 22 37 45, para conocer el resultado de e la cita del día 5 de enero de Salud Mental.: Nos informa que le han recetdo APOLAZ 1 vez al día, asistió a la visita con la Educadora (Sandara), le manifestó la obsesión que tiene que las educadoras y monitoras que más trabajan con él, hablan de él a sus espaldas. La educadora confirma al Psiquiatra que no es cierto. En referencia a los intentos de suicidio, la Psiquietra informa que son llamadas de atención ya que con el cordón de la zapatillas no es posible','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2016-01-07','Teresa de Novaforma nos informa que el la vivienda de la Haba, de la cual es copropietario Felipe con dos sobrinos de un hermano fallecido, una de las sobrinas se ha ido a vivir allí, pidiendole la llave a Felipe ( aun no se la entregado), y que esta se haría cargo de los gastos de agua y luz. PENDIENTE: VERIFICAR SI ESTO ES CIERTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2016-01-07','Ha telefoneado desde la casa de su madre en Cabeza del Buey, nos informa que el dí 13 de enero se marcha del CRR de Badajoz. Se muestra disconformen porque según el le faltan 3000€ en su cuenta. Tlfno de contacto924 63 22 38/ 646053956 He llaamado 3 veces al CRRBadajoz y me ha sido imposible contactar con ellos (Fdo.: Toni Barragán)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2016-01-07','Llama Andrés Flores PNC Ext 74381. que ha pasado la tutela con su tia para comunicar que desde abril no cobra. Devuelven del Banco la PNC a la seguridad social. Le derivo a Marisa para comprobación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-01-07','Visita la CTAEx sobre las 11:00 horas. Viene solicitando un extra de 40€ para ropa. Acuerdos tomados con él: Como no tiene telefono vendrá el próximo martes para que el informemos de : -Cita dni.: 25 de enero a las 14:15 horas. -Asociaciones donde realizar Trabajos a la comunidad como alternativa de prisión (pendiente de confirmar) -Fecha cita Salud Mental (pendiente confirmar. -Autorización Extra para sacar dinero para ropa 40€ confirmar hora y dia con futuex. -Debe de traernos listado con sus necesidades economicas semanales) Tras una charla con sobre su vivencia en el calabozo, nos reconoce verbalmente que no quiere ir a la cárcel. (pretendemos que viva en la realidad y deje ese recurso como forma de susentencia) A lo largo de la conversación nos informa que es normal pegar a la pareja que el no es maltatador porque no lo hace habitualmente. Intentamos que asimile que dos guantazos son malos tratos. Reconoce verbalemte lo relizado. Volvemos a intentar que sea el que tome las decisiones ( ahora vuelve a retomar la relación con su hermano y alude a él para solicitar extras económicos) .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-01-08','INFORME FUTUEX 28/12/15 No se ha presentado a la cita de Salud mental. El Psiquiatra le ha realizado una valoración a la delegada tutelar donde indica: " Que Jonathan es de los casos de trastorno de personalidad como otros muchos muy difícil de tratar, comenta que al madurar algo quizás toman conciencia de la necesidad de abandonar malos hábitos y medicarse, con 20 años prima la impulsividad y descontrol. Al ser límite intelectualmente complica más la situación"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='CACERES'and apellido2='CABANILLAS'),'2016-01-08','INFORME FUTUEX .4/12/2015: -VALORACIÓN DELEGADA TUTELAR: "No veo ninguna evolución. Parece tranquila, sigue la misma línea anterior. Consume alimentos hipocalóricos, la obesidad persiste, el ejercicio es mínimo. Sigue sin querer hablar de anticonceptivos. Esta muy poco habladora. Afirma no tener demandas. Acudió a la consulta médica, dice, por unas molestias en garganta. Como expuse anteriormente no quiere recibir ni buscar ningún tipo de curso para mantenerla algo activa. Deberíamos insistir en que acudiese algún centro para fomentar mas habilidades y relacionarse con más gente. Está limitada a diego y los padres del él. Hace la vida de un vegetal y sin percibir estímulos externos que le aporten algo. Recordemos que son una familia muy limitada intelectualmente y muy mayores. Diego, aunque no lo quieren reconocer es discapacitado intelectual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-01-08','Telefonea el hermano Luis Miguel (625 51 43 94) para saber si hemos aportado la documentación a la notaria para realizar la aceptación de la herencia. Se le informa que aún no hemos recibido el original del juzgado, que en cuanto lo recibamos lo enviamos a notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2016-01-08','Telefoneamos a la TS. de la prisión de Granada, nos confiman que los excarlen hoy a las 12;00 horas y que el párroco lo acompañará a la estación. Intentamos contactar con la tía, no ha sido posible. Marisa dará la orden al banco de no pasar la trasnferenca al peculio y lunes acordaremos la asignación a percibir por su tia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-08','recibimos email de Arca de Noe (676-693050, Director Vicente Gutiérrez), donde se nos informa que produjo baja voluntaria Comunidad Terapeutica el 4 de enero de 2016. Hablamos con el director del Centro y nos comenta que después de pasar sus vacaciones en su domicilio de Cabeza de Buey fueron a recogerlo, había consumido marihuana, le hicieron los análisis pertientes y dió positivo. El día 4 marcha y el día 5 se comunica con el centro arrepentido para pedir que se le envie dinero, le envian un giro de 30€ a las 12:00 Horas. No ha vuelto al centro ni ha contactado. No saben donde habita actualmente, ya que la madre no quiere que el hijo se quede con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-08','Contacta por telefono la TS de Cabeza de Buey, Águeda (636786917) para comunicarnos que está en una casa derrumbada, que la madre no de hace cargo del hijo y un amigo que habitualmente le ayuda tampoco. Contactamos de nuevo con Arca de Noé, y deciden de reunirse para aprobar si se le concede una nueva oprtunidad, finalmente acceden pero no existe la posibilidad de gestionarle cantidad economica para que vaya en tren ( 14;15 h)y el día 5 ya se había gastado una cuantia enviada desde la Comunidad Terapuetica. Acordamos con la TS. Agueda que le buscarán un taxi para que lo lleve al Centro, que posteriormente haremos la transferencia el lunes. El taxita queda que lo recogerá a las 15:00 H. Queda con Águeda que l enviará un wasap cuando lo deje en el centro. La pareja de un sobrino se puso también en contacto con nosotros para explicarnos la situación, debido a que la relación no es positiva decidimos no darle más información que estabamos realizando las gestiones pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2016-01-08','Ha venido la madre para decirnos que no ha cobrado la PNC de diciembre. Le explica Belén que ya ha enviado la carta a prestaciones para su regularizxación y que en este mes estaría resuellto. La madre nos informa que ha contratado con su dni (DE LA MADRE), canales de orange y moviestar, pero que no quiere drlos de baja porque su hijo no entiende y no quiere problemas. Nos informa que a ella le han concedido la PNC, pero se lo tiene oculto a su hijo porque sino le pediría constantemente. Que ella le guarda su asignación de 60 euros en caja fuerte para ir haciendo pagos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2016-01-08','Telefonea Sole (TS Ntra. Sra de la Luz 673 55 66 90), para decirnos que no cobra la PNC desde abril, nos informa que en la cuenta está Critina, la tia (referente positivo), la abuela que falleció y la tutelada. Se le llevó el parte de defunción de la abuela al banco pero como habían pasado más de tres meses, ya no se podía dar de baja a la abuela. en el Banco le recomienda abrir una cuenta nueva. Si así se hiciese se solicta incluyan al director del centro en las autorizaciones para gestionar pagos. Belén ha estado telefoneando toda la mañana al banco sin éxito','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-01-08','Ha venido a la comisión manifestando que se quiere del CRR, los motivos que alega es que no le dan las cuanttias que pide , mientras que a otros sí, que el resto de sus compañeros la tratan mal y siempre la castigan a ella.....ç Que no le han dado los extras que acordamos en la reunión. Se marcha muy enfadada porque dice que somos tan malos como ellos y que solo le hacemos caso a ellos y no a ella. Llamamos a las 15:00 al CRR donde nos confirman que ha vuelto al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-01-08','Ha venido a la Comisión porque quiere marcharse del CRR.. Que no le han aumentado la asignación y que su medicación es muy alta. Tras una conversación con ella le recordamos que si se va del centro no verá a su pareja y que las asiganciones estaban concedidas al igual que la compra de ropa en rebajas que debía de revisar con Gilesa. Acordamos que cuando vaya a su proxima revisión hablariamos de como se encuentra en el centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ERNESTO'and edp.apellido1='GARCIA'and apellido2='LOPEZ'),'2016-01-11','Visita del abogado Enrique Perianes Carrasco (tfno: ), por trámites de aceptación de herencia. Los hermanos de Don Ernesto han dado poderes a Don Enrique para llevar a cabo los trámites de la herencia. Nos traerá la documnetación correspondiente para estudiarla y comunicarlo al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-11','08.50h.Conversación con Vicente Gutiérrez, Director Arca de Noé. 14.00h. Conversación con Carmen Psicóloga de Arca de Noé. Enviará Informe de la evolución de Hermenegildo en el Arca de Noé.Se ha marchado antes de que llamases. No sabemos a dónde. 14:15. Conversación con Águeda, T. Soc. de Cabeza del Buey. No tiene constancia de que haya ido al pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2016-01-11','Se pone en contactos el sobrino para comunicarnos que la arrendataria del local no recibe factura. Arredantaria Cristina , 651541706 Intentamos contactar con la gestoria que lleva su documentacion . JOSÉ IGNACIO MARIN (924 31 22 70), . No ha sido posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-01-11','Solicita el pago de Zapatero 10€, peluquero 30€, Modista 10€ .Pendiente confirmar por Belén si le pasó a Mamen para su pago. Pendiete el pago a farmacia Mata (la factura no específica el producto.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2016-01-11','JULIÁN HA LLAMADO PARA COMUNICAR QUE LE MIERCOLES, 13 DE ENRO FIRNMARÁ EL ALTA EN EL CRR DE BADAJOZ. TAMBIÉN SE QUEJABA DE PERSONAL DEL CRR. ANTE ESTO LLAMÉ PARA QUE ME EXPLICARÁN LO QUE HABÍA OCURRIDO. ME DIJIERON,QUE JULIÁN LLEVA ACOSANDO A UNA EMPLEADA BASTANTE TIEMPO, INCLUSO PERSIGUIENDOLA HASTA SU CASA ( ESTA ES LA EMPLEADA QUE ÉL SE QUEJA). QUE ANTES ESTABA MUY IEN PERO QUE EN DICIEMBRE EMPEZÓ A CONSUMIR ALCOHOL Y NO SE TOMA LA MEDICACIÓN.DICE QUE SE IBA PARA SU CASA DE CABEZA DEL BUEY PORQUE SU MADRE ESTÁ MUY MALA, ( LO QUE TIENE LA MUJER SON LAS ENFERMEDADES PROPIAS DE UNA EDAD AVANZADA).DESDE EL CRR, EL MIERCOLES VAN A INTERNAR QUE LO VEA EL PSIQUIATRA PARA QUE LE HAGA UN INTERNAMIENTO INVOLUNTARIO. lLAMO A JULIÁN PARA CONVENCERLE DE QUE SE QUEDE EN EL CRR, PERO NO HAY MANERA. LA DIRECCIÓN DE CABEZA DEL BUEY ES C/ CERVANTES,6.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-01-12','ENVÍO AL CENTRO DE ACOGIDA, NFORME SOCIAL PARA ACEPTARLO EN EL CENTRO HASTA QUE SE LE ACEPTE Y ENTREA DE LA VIVIENDA SOCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-01-12','Visita a Don Juan José en los Pisos Tutelados de Pozuelo de Zarzón. Quiere volver a Montijo. Se le informa que vamos a gestionar su traslado para aproximarlo a esta localidad, pero considerando también las aletrnativa de Badajoz y Mérida (esta última es la que menos le gusta, pero Badajoz sí es una opción para él). ACCIONES A REALIZAR: +++ Hablar con T. Social y Médica de Familia de Montijo para ver la idoenidad o no de traslado a Montijo (se puede hacer el jueves 14 de enero si da tiempo, tras la visita a Aprosuba 8). +++ En función de lo anterior solicitar cambio de plaza residencial por aproximación a localidad de origen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-12','Conversación Vicente Gutiérrez: no ha vuelto al Centro "Arca de Noé" a fecha de hoy. LLamo a Águeda: no ha aparecido por allí. CAMF. Clemencia (Directora). Aviso de que, si encuentran a Hermenegildo por Badajoz esta tarde (compañeros de Arca de Noé) lo llevarán al CAMP, tal como he quedado con su director.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-13','Conversación con Vicente Gutiérrez: Hermenegildo esta de nuevo en el Centro "Arca de Noé". +++Hermenegildo:dice que quiere volver al CAMP de Don Benito, pero que ha perdido las maletas que se llevó ayer cuando se volvió a marchar y que no tiene ropa (Vicente dice que yiene algo de ropa allí que puede utilizar). +++Vicente: quedo con él en que lo acercarán al CAMP, aunque para ellos -dice- es un trastorno. Le pido que lo hagan así para asegurar que llega y no se vuelve amarchar. Quedamos en que lo llevarán ellos y pagaremos la gasolina. Vicente se encargará de preguntar por las maletas a la Policía Local y en la oficina de objetos perdidos por si pudieran aparecer. +++Llamo al CAMP (924-021564) para avisar de la llegada de Hermenegildo.Hablo con Clemen (Directora). +++Llamo a Águeda, T. Soc. de Cabeza del Buey (636-786917). para informarla','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-01-13','Isabel, madre de Jesús Manuel: 657-947818.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-15','CAMP "Las Cruces". Hermenegildo llegó el día 13 por la mañana acompañado por personal de "Arca de Noé". Incidencias: +++17:00h. Intento de salir del centro sin permiso. Se consiguió retener. +++19:20h. Se marcha del centro y regresa a las 20:30h. Había fumado porros según manifestó él mismo. Hablo con Clemen de estas incidencias nada más llegar Hermenegildo al centro.Propuestas: +++++Solicitará permiso para restringir llamadas de la familia. +++++Valoraraán la alternativa de, llegado el caso, solicita ingreso en UDAC.','2');
