insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-01-15','Tras el correo remitido por el Centro de Acogida Temporal de Cáritas en Cáceres, informando de la imposibilidad de acoger en él a D. Jesús, hablo por teléfono con la Coordinadora del centro, Eva (927-235082): no solo no disponen de plazas vacantes, sino que tienen en espera una derivación del Ayto. para una persona sin recursos a la que no saben si podrán acoger. Le comento la posibilidad del Albergue Municipal, pero me indica que no es un albergue de acogida, sino de carácter turístico, aunque muy barato (14-15€): no es alternativa porque en estos momentos D. Jesús está pagando unos 17€ en el Hostal.','2');
