insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-01-20','Conversación con Mª Carmen de Arribas (71452) de S.G. de Arquitectura y Vivienda. +++Ha mantenido una primera entrevista con Jesús. +++Su informe de adjudicación de vivienda es favorable, en vivienda sita en la Mejostilla. +++Reunión de la Comisión de Vivienda: miércoles 27 de enero. Me llamará/llamar el jueves. +++Alquiler maximo: 166 euros. Existe posibilidad de minoración de renta en función de cumplimiento de criterios. +++Periodo entre adjudicación y ocupación de la vivienda: un mes (se suele ser flexible). +++++++++++++++++++++++++++++++++++ AYUNTAMIENTO: +++Consultar ayudas para gastos de primera necesidad (enganche luz, agua, etc). +++Ver posibilidad de facilitar alojamiento a Jesús hasta entrega de vivienda: hablar con Juan Antonio, director del IMAS (927-212335) antes de hacerlo con algún T. Soc. del Edificio Valhondo: 927-249600). ++++++++++++++++++++++++++++ SECRETARÍA GENERAL DE ARQUITECTURA, VIVIENDA Y POLÍTICA DE CONSUMO. +++Maribel Moreno Duque (SGT): Secretarias: Susana Hdez. Espada (50042//924-332042) e Isabel Mateo (50450/924-332450) +++Nuria Sánchez Villa (Jefa de Servicio Adjudicación Vivienda: 924-332454). Jefa de Mª Carmen.','2');
