insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2016-01-19','RECIBIMOS LLAMADA DEL HERMANO DE JUAN, MANUEL MORA RODRIGUEZ (928 98 57 00 / 670 35 93 13 ). LLAMA DESDE CANARIAS DONDE RESIDE. DICE QUE EL ALCALDE DE TALARRUBIAS SE HA PUESTO EN CONTACTO CON EL PARA COMUNICARLE QUE SE VA A EXPROPIAR PARTE DE UNA VIVIENDA QUE ERA PROPIEDAD DE SUS PADRES Y NECESITAN LA FIRMA DE AMBOS HERMANOS. MANUEL ME COMENTA QUE LE GUSTARÍA VENDER LAS PROPIEDADES QUE TIENEN EN EL PUEBLO, UNA CASA, UNA COCHERA Y UN TENAO. COMENTA QUE NO TIENE PAPEL ALGUNO DE NINGUNA NI DEL FALLECIMIENTO DE SUS PADRES. LE DIGO QUE RECABAREMOS TODA LA INFORMACIÓN QUE PODAMOS DEL REGISTRO CIVIL, CATASTRO Y REGISTRO DE LA PROPIEDAD PARA FORMALIZAR LA HERENCIA Y DESPUES SOLICITAR LA VENTA DE TODO. POR OTRA PARTE HABLO CON EL ALCALDE Y ME DICE QUE NOS ENVIARÁ EL ESCRITO PARA QUE FIRMEMOS EN NOMBRE DE JUAN. FDO.Mª JOSE GONZALEZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2016-01-20','PEDIDOS CERTIFICADOS DE DEFUNCIÓN DE LOS PADRES AL REGISTRO CIVIL Y DE BIENES DE LOS PADRES AL CATASTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2016-01-20','RECIBIMOS LLAMADA DE LA HERMANA DE TERESA, Mª JESUS PARA DECIRNOS QUE HABLEMOS CON UN ABOGADO QUE ESTÁ LLEVANDO LA FORMALIZACIÓN DE UN CONTRATO DE COMPRAVENTA DE UN TERRENO QUE VENDIERON SUS PADRES EN SU DÍA Y NO SE HABÍA ELEVADO A ESCRITURA PUBLICA. HABLO CON EL ABOGADO, JESÚS BARROSO 679 496 532, ME COMENTA QUE EN SU DIA SE HIZO UN CONTRATO PRIVADO DE COMPRAVENTA FIJANDO A FINALES DE 2015 LA FECHA PARA ELEVAR A ESCRITURA PUBLICA ESE CONTRATO. COMO LA MADRE DE LA TUTELADA Y VENDEDORA DEL TERRENO FALLECIÓ ES NECESARIO QUE FIRMEN LAS HIJAS. LE ENVIO COPIA DE LA SENTENCIA Y DEL DNI NOS ENVIARÁ BORRADOR DE LA ESCRITURA Y POSTERIORMENTE DEBEREMOS RATIFICARLA AQUÍ EN LA NOTARÍA DE MERIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2016-01-20','REUNIÓN DE EQUIPO CTAEX:Pedro, Amalia, Alberto. Toni. ACTUACIONES ACORDADAS: -Visita a domicilio CTAEX SSB -Delegada tutelar: Que pida presupuesto para mejora de la vivienda, cama, conexion luz., todo lo necesario para habilitar la vivienda. Que pida Informe de Salud para valoración de internamiento no voluntario. -Posibles recursos para asignar. Piso supervisado o CRR -Comprobar si tiene valoración de Dependencia -Pedir empadronamiento. -Alberto ver las deudas pendientes y parte economica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2016-01-21','Llama Sonia de Asindi ( 927 39 01 93), solicitando que hablemos pcon Maria Victoria, ya que esta ha solicitado conocer los ahorros que tiene para arreglar su domicilio, heredado de sus padres. El hermano ha hablado con ella y le ha dicho que ahora no es el momento por las fechas de lluvia. Se pide que se realice por teléfono, para aproximar la Comisión a la tutada, ya que ha manifestado en varias ocasiones que no conoce a sus tutores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-01-21','CONSULTA CON MAI REFERENTE A TRASLADO DE RESIDENCIA. Consultamos una petición de traslado de residencia para acercamiento a su localidad (Badajoz-Merida-Montijo. Orden de prioridad). Juan José fue ingresado por decretto, no tiene dependencia con lo cual dos soluciones: -Pedir traslado a la territorial, lo cual no es probable que se llegue a producir por la demanda que hay en Badajoz y que las plazas se adjudican prioritariameente a Dependencia. -Recomendación: Solicitar dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2016-01-21','Se telefonea Cadex para confirmación del 65% de discapacidad, la cual se puede revisar desde diciembre 2013, a petición de Ángel(Jurídico)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-01-21','Telefoneamos a Ana(TS. Salud mental 927 45 80 36) para que el Psiquiatra se ponga en contacto con MariLuz (SEPAD 924 00 38 93) para adjudicación de recurso. Acordamos que nos indicará la respuesta del Psiquiatra por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-01-21','Confirmamos con Mai(68496) que no se ha recibido solicitud o petición de cambio de residencia','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-01-21','Conversación con Juani, dueña del Hostal (927-211210). Como máximo se puede quedar hasta el día 8 de febrero. COMPROMISO de CTAEx: solucionar alojamiento temporal hasta ocupación de vivienda social (si se la adjudican) antes del 31 de enero. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamada a Dª Isabel (657-947818), madre de Jesús. Hablará su marido para ver si, además de los 100 euros que da mensualmente para el pago del Hostal, puede aportar algo más para solventar la deuda.Nos llamará. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-01-21','Nos comunica el hermano que está ingresada en el infanta Cristina, en neurología. Nos informa el neurologo , que padece una encefalopatía, causada por una hipoglucemia), que actualmente está dormida, responde al dolor, mueve las extremidades, pero no se comunica. La semana que viene está previsto realizar una resonancia, donde se verá los daños, posteriormente habrá que trasladarla de centro, la TS del hospital se podrá en contacto con nosotros. PENDIENTE: confirmar si se ha informado al juzgado 2 de badajoz de la situación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2016-01-22','Conversación con Sonia (ASINDI, 927-390193). Se informa a Dª Victoria de las pensiones que tiene (cuantía), saldo actual en el banco y coste de su plaza residencial. Quiere saber todo esto porque quiere arregalar su casa "porque en ella he vivido con mis padres y no la quiero vender...". Respecto de la reforma se le informa lo siguiente: +++ hay que valorar el estado de la vivienda y pedir 2 ó 3 presupuestos para solicitar autorización judicial si fuera preciso. +++según la reforma a realizar, quizá con el saldo actual no sea suficiente para emprenderla. De toda la conversación se informa a Sonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-01-22','Llama Juan manuel, hermano de Mª Ángeles : la resonancia se la van a hacer hoy y tendrán el resultado para el lunes. Ingresada en el Infanta Cristina, hab. 627.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-18','INCIDENCIA Día 15/01/2016: 14:30 Hs., se fuga; 23:45 Hs., la policía local de la localidad de Cabeza del Buey comunica que tienen en sus dependencias a Hermenegildo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-18','INCIDENCIA Día 16/01/2016: 13:15 Hs. regresa al centro residencia, tras irle a recoger en taxi a la localidad de Cabeza del Buey. En el comedor provoca nuevo incidente, negándose a comer el menú establecido y abandona el comedor, teniendo un nuevo intento de fuga; 19:30 Hs. se fuga, nuevamente, y regresa voluntariamente sobre las 20:30 Hs. Accediendo a las dependencias de este centro residencial saltando las vallas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-19','INCIDENCIA Día 18/01/2016: 16:30 Hs. se fuga; 17:35 Hs. regresa al centro acompañado del vigilante, ya que se le encuentra en la calle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-21','INCIDENCIA Día 20/01/2016: 15:30 Hs. se fuga; 19:30 Hs. regresa por voluntad propia y, tras apreciar el vigilante que hubiera podido haber consumido algún tipo de sustancia, le resgistra, tanto a él como su habitación. Encontrando un pequeño envoltorio con, posiblemente, marihuana. Motivo por el que es enviado a enfermería y se procede a apicar el protocolo de actuación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-22','INCIDENCIA Día 21/01/2016: 08:00 Hs. se fuga; 11:27 Hs. regresa al centro; 15:30 Hs. se fuga; 01:50 Hs. se recibe una llamada telefónica procedente de la Comisaría de Castuera, quienes comunican que tienen allí a Hermenegildo. 04:10 Hs. regresa al centro acompañada por un educador, que, previamente, se ha trasladado hasta la comisaría de Castuera para hacerse cargo de él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-22','INCIDENCIA Día 22/01/2016: 08:13 Hs. se fuga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-01-22','SE recibe comparecencia de D. Ventura en la Fiscalía de Cáceres. Pendiente de contestar hasta que nos envíen información solicitada a la Caixa por correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-01-22','Se recibe por fax comparecencia de D.Ramón en el Juzgado de 1ª Instancia e Instrucción nº 2 de Jerez de los Caballeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-25','Llamada de Águeda, T. Soc. de Cabeza del Buey (636-786917). Hermenegildo se escapó nuevamente el pasado viernes. Está con ella ahora en el despacho: me pide "un billete de 20€" para comparar comida (dice que tiene hambre y que no come desde hace dos días). Comenta que está viviendo en una casa vacía a la que le ha pegado una patada a la puerta (parece ser así, según Águeda). "No quiero ir a ningún colegio más. Yo me quedo en mi pueblo, me dais dinero todas las semanas y ya está...Porque yo soy bueno, Pedro y no me meto con nadie..." "Negocio con él dinero a cambio de que vuelva al CAMP voluntariamente: acepta, pero volverá mañana en el tren de las 13h. Promete no volver a escarparse. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Clemencia (Directora CAMP) para informarle de la situación de Heremenegildo. Querían ir a buscarlo pero le digo que quizá sea preferible esperar a que vuelva el por su cuenta manaña a partir de las 13h. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con la Secretaria del Juzgado nº 2 de Castuera de la situación: enviaré informe por FAX y ella hablará con la Jueza. A las 14:00 aproximadamente llamo de nuevo pero no me cogen el teléfono. Intentaré nuevamente mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-01-25','Hemos enviado al abogado de oficio toda la documentación que precisa para iniciar el procedimiento de modificación de medidas (pensión alimenticia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-01-25','Hemos enviado al Juzgado de Primera Instancia nº 2 de Coria, ratificación de Consolación en el EJV (solicitud de autorización judicial para venta de inmueble). Ese Juzgado ha admitido a trámite el EJV, con el requisito de la ratificación. Posteriormente ese Juzgado lo enviará a los de Mérida, para que acuda Consolación en persona a ratificarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-01-25','Conversación con el hermano de Mª Ángeles. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Concha (T. Soc. Infanta Cristina: 924-218100): se informará del estado de Mª Ángeles. Hablaremos a partir de las 14:00h. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Blanca (T. Soc. CSS de Mérida). Se inyectó la insulina el día antes de ingresar en el CSS. No han comunicado nada al juzgado al no heber ingresado todavía cuando se produjo el suceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-01-25','Llamo a Dª Josefina Ramírez de la Rosa (620-552211 y 91-4739486). Respecto a la vivienda que quiere ocupar su hermano (C/. Almendralejo nº 30, de Torremejía) dice ser propiedad de tres de los hermanos (incluida ella) y que ella misma se preocupó de que su hermano Juan apareciese en el reparto como usufructuario de dicha vivienda. Comprobaremos en el Registro la propiedad de la vivienda y quedamos pendiente de convocatoria de la reunión. Insiste en que su hermano no está ni para vivir solo ni acompañado en casa alguna (recuerda los tres conatos de incendio que provocó su hermano en el pasado) y que no está dispuesta a darle las llaves de la casa comoél le ha pedido en su última carta. Le planteo la posibilidad de retomar la reunión que quedó postpuesta antes de Navidad, propuesta que acepta y considera necesaria. Le dejo mi correo electrónico para que me diga el día y la hora en la que podríamos tenerla (le sugiero un viernes, dado que se tienen que desplazar desde Madrid). Aviso a Blanca (924-388081), T. Soc. del CSS de la próxima convocatoria de esta reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2016-01-25','Conversación con Ana Delfa (Directora CRR Badajoz: 924-231645). Han recibido la valoración de Dependencia: Grado 1. No están de acuerdo con ella, porque las necesidades de Dª Sonia son muy importantes y dicha valoración puede afectar a recursos futuros de los que tubiera derecho a disponer. Le pido envíen un informe decriptivo de la situaciób de Sonia, para poder apoyar, en su caso, una nueva valoración de ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2016-01-25','Conversación con Ana Delfa (Directora CRR de Badajoz: 924-231645). Ingresó en UHB de Infanta Cristina la pasada semana de forma voluntaria. No quiere volver al CRR porque dice que se quiere ir con su mujer y su hija','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-01-26','PEDIDA NOTA SIMPLE DE LA VIVIENDA AL REGISTRO DE LA PROPIEDAD NUMERO 2 DE MERIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-01-26','Conversación con Juani, T. Soc. de Pozuelo de Zarzón. Se le explica que hay que solicitar la plaza por dependenia. Hará los trámites para solicitarla. Si es necesario me pondrá en contacto con D. Juan José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-01-26','INCIDENCIA Sobre la 1.00 Hs. de la madrugada, Mariloli, avisa a los profesionales del CRR de no ser capaz de respirar bien, estos no consideran que tenga gravedad, pudiendo ser una leve sensación de ansiedad, hablan con ella y vuelve a la cama. Sobre las 3.00 Hs. viene al despacho de educadores refiriendo un dolor de pecho y brazo, por lo que se llama de forma inminente al 112 los cuales la trasladan al hospital. Allí, le hacen una serie de pruebas, las cuales no dan resultados fiables, causados por un posible fallo de las pruebas, por lo que deciden mantenerla ingresada y realizar le pruebas mas adelante. En el momento presente nos ponemos en contacto con el hospital para que nos informen sobre el estado de la usuaria, posponiendo nuestra llamada ya que no disponen aún de información. Minutos después, hablamos con Mariloli, la cual nos dice que se encuentra bien y que cree que le darán el alta. Desde el CRR volveremos a ponernos en contacto con el hospital a la espera de mas información. Cuando dispongamos de esta la haremos llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-01-26','INCIDENCIA Dolores vuelve a el CRR. Acude con un informe en el que se pide que solicite cita para realizar unos análisis. Pedimos cita para mañana. Y a la espera de nuevos resultados. A pesar de no ser nada urgente le mandan Tioner 100mg/ml de manera provisional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-01-26','Se envía al Juzgado de 1ª Instancia nº2 de Castuera fax informando de la última escapada de D. Hermenegildo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2016-01-26','Hemos solicitado al Registro de la Propiedad de Almendralejo, nota simple de los bienes inmuebles, rústicos o urbanos, a su nombre, en especial el sito en C/. Velázquez, nº70, de Almendralejo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2016-01-26','Hemos solicitado al Registro de la Propiedad de Llerena, nota simple de los bienes inmuebles que figuren a su nombre, en especial del sito en Cortijo el Compresor, s/n, en el cual vive.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-01-26','Hemos comunicado al Juzgado de Instrucción nº 1 de Badajoz, Sentencia nº 121 del Juzgado de Primera Instancia nº 1 de Badajoz, de Incapacidad y nombramiento de la Comisión Tutelar como sus tutores, así como que tiene dos hermanas, María José e Isabel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-01-26','Llama Encarna (T.Soc. C. Salud de Plasencia): D. Francisco no quiere volver a ser atendido ni por el Dr. Ganso, ni por la Dra. Zazo, ni por el Dr. Castañón. El Dr Quiroga no lo ha visto todavía. Llamaré al Hospital para hablar de la posibilidad de concertar cita con este traumatólogo para conocer otra opinión sobre el estadod el brazo de D. francisco. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo al Hospital Virgen del Puerto de Plasencia (927-428302). Intento hablar con Flor o Fernando pero no me coegn el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2016-01-26','Conversación con María, T. Soc. CSS de Mérida: +++José Mª no entiende por qué está en Mérida y quiere volver al CSS de Plasencia desde que ingresó en Mérida el 22-04-2015. +++Comprobar vigencia de la orden de alejamiento.','2');
