insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='CACERES'and apellido2='CABANILLAS'),'2016-01-27','Llama Soledad: quiere 150 euros para arreglo de móvil, un abrigo y un disfraz de carnaval. Se le indica que nos debe enviar los recibos o factura de las compras y arreglos (se le da número de fax) y se le hace ver que últimamente ha tenido varios extras que no se pueden repetir y menos con esta frecuencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-01-21','Reunión en la Comisión con Directora y T. Social de Aprosuba 7. Enviarán informe de Minerva en relación a la conveniencia o no de que continue en el docimicilio familiar. Hablar del caso con Amalia cuando se reincorpore.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2016-01-27','LLama Dª Juana Pin, madre de Marco (666-898908). Solicita una ayuda para ella porque estám muy necesitados. Dice que cuando su hijo vaya a verla que le demos 300 ó 400 euros. Le explico las obligaciones que la tutela que ejerce la Comisión tiene y que, cuando su hijo vaya a verla se le puede dar dinero de bosillo, pero no atender otras necesidades diferentes a las del propio tutelado.','2');
