insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-01-27','Hablo con Fernando, T. Soc. Hospital Virgen del Puerto de Plasenci (927-428302). Plantea solcitar un cambio de especialista, en documento formalizado, especificando el especialista que se quire tener asignado. Quedamos en que hablará con Encarna, T. Soc. del C.de Salud (927-423436/Ext 74439) para plantear la solicitud (que en cualquier caso debemos firmar nosotros).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-01-27','Conversación con Concha, T. Social del Hoispital Infanta Cristina. La alternativa para Mª Ángeles no es el CSS de Mérida, sino una plaza sociosanitaria T-2 o T-3. Gestionará dicha plaza y nos enviará la solicitud para su firma por la Comisión (He tratado de hablar con Blanca sobre ello pero no ha sido posible esta mañana). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Juan Manuel (hermano) para informarle de todo ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERRERA'and apellido2='CAMBERO'),'2016-01-27','Se recibio escrito de su hijo Fco. Javier solicitando información de la tutela ya que hace mas de 20 años Antonio les abandono y no habían vuelto a saber de el. Habia estado a visitarle a la residencia de Montanche. Nos facilita el contacto de su abogada para que le informemos. Puestos en contacto con ella, Mª Dolores Garcia 670665106, nos manifiesta la existencia de una herencia de los padres de Antonio por la cual lega todo excepto la legitima estricta que le corrsponde a Antonio a los tres hijos de este. Hay una vivienda y dos fincas rusticas pequeñas, los hijos de Antonio ya han aceptado el legado en notaría por lo que es necesario que ratifiquemos esas escrituras y que Antonio renuncie a su parte de la herencia. Se ha pedido autorización judicial para renunciar a la herencia según los fundamentos manifestados en dicha solicitud','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-01-28','Conversación con Mª José Bernardo (CaixaBank, 927-620580), solicitada por ella en constestación a nuestro correo electrónico: Actualmente no existe ninguna cantidad retenida en la cuenta de D. Ventura. A la que se refiere la comparecencia en Fiscalía se debió a un fallo informático POR EL QUE NO SE ACTUALIZÓ la "Fe de vida". Dicho fallo parEce haberse resuelto ("NO ME EXPLICA CÓMO) y la cuenta está libre para que la Comisión autorice los pagos que sean precisos. Se solicita en este momento estracto bancario de los últimos seis meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-01-28','Conversación con Concha (T. S. Infanta Cristina): Mª Ángeles tiene una puntuación de 30, lo que le da acceso a una plaza sociosanitaria T-2 (de 30 a 38 puntos). Está tramitándose. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Blanca (CSS Mérida): tienen que comunicar a Servicios Penitenciarios la situación sufrida por Mª Ángeles, al estar cumpliendo pena judicial en el Centro. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-01-28','Visita de D. Víctor, padre de Minerva (634-660568).Necesita comprar ropa a Minerva. Dice que la última que le compró se le quedó pequeña ¿?. Se le autorizan 250€ con la condición de que nos envíe los comprobantes de las compras realizadas. Acepta, creo que un poco a regañadientes.','2');
