insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2016-02-03','REcibimos del ESM de Cáceres documnetación relativa al ingreso de D. José María en la URA de Plasencia. Si su situación mejora, la alternativa al ingreso en centro cerrado sería el CRR, cuya solcitud también se ha tratmitado por Pilar Martín. Según sentencia,el Centro debe comunicar cada tres meses la situación, al haberse producido inicialmente el internamiento en centro cerrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='MENDEZ'and apellido2='CORBACHO'),'2016-02-03','Llama Francisco Salgado (hermano de Saturnino, 927-244205). Saturnino sale de permiso penitenciario hoy y hasta el día 8 de febrero. Solicita reintegro de 350€ para ropa y dinero de bolsillo.Se le indica nº de fax de la Comisión para que nos envíe las facturas de esta compra y de las anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-02-03','Conversación con Concha, T. Social (H. Infanta Cristina). Dª Mª Ángeles será traladada al centro "Encinar de las Cruces" de Don Benito donde sde le a concedido plaza sociasanitaria T-2. El traslado se realizará hoy a partir de las 16:00h. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se comunica a su hermano y se habla también con Blanca (CSS Mérida) para que le entreguen los efectos personales de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-02-03','Conversación con Francisco Salgado, hermano de Saturnino (927-244205). Su hermano sale hoy de permiso penitenciario y hasta el día 8 de febrero. Solicita extra de 350 euros para comprar ropa y dinero de bolsillo. Se le da nº de fax para que envíe estas facturas y las que tiene pendientes de compras pasadas.Llamo al Centro Penitenciario de Cáceres (927-181145) Oficina de Régimen: confirman el permiso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='DIAZ'and apellido2='ABADES'),'2016-02-03','TRASLADO Al Hospital de Mérida con fecha 02/01/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2015-11-30','Conversación con Almudena (T.Soc. Aprosuba 10. 924-891012). El informe emitido de fecha 19 de noviembre tiene un carácter básicamente informativo, de dar a conocer el episodio de agresividad protagonizado por Agustín. El informe anterior de octubre refería que se encontraba bien en el centro, participaba de las actividades, etc. En este momento, desde Aprosuba10 no se pretende tomar decisión alguna al respecto, ni se solicita intervención de la Comisión: seguirán observando el comportamiento de Agustín y comunicarán cualquier incidencia que ocurra. Almudena comenta que en alguna ocasión Agustín le ha dicho que se quería cambiar de Centro, para al cabo de cierto tiempo pedirle que, "...cuando te diga esas cosas no me hagas nunca caso. Si yo estoy muy bien aquí...". Creen que está empezando a actuar como en el CAM: formando una especie de grupo de "acólitos" a su servicio. No se tiene constancia de ello, pero lo están teniendo en consideración por las repercusiones que ello pudiera tener en un futuro. Seguiremos en contacto para cualquier cosa que se necesite desde Aprosuba 10 y que esté en manos de la Comisión facilitar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2005-04-21','Solicitado informe al C.A.M.P. y al banco.Recibido el del banco','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-02-03','Consulta Almudena por la petición constante de viajes a su casa en Villanueva del Fresno. Cada viaje se va en taxi y le cuesta unos 190€. Descartamos en la conversación el que se vaya en transporte público, porque no lo hay directo desde Azuaga y los trasbordos pueden ser conflictivos. Se tratará de espaciar estos viajes el máximo en el tiempo para también reducir los costes al máximo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-03','Conversación con Águeda, T. Social de Cabeza del Buey. Hermenegildo está con ella en estos momentos: dice que le da de comer un señor en su casa y que duerme en un cajero. Hablño con Hermenegildo: debe volver al CAMP pero insiste "No Pedro, yo no voy a volver más a Don Benito. Me quiero ir otra vez a "Arca de Noé" y te prometo que ya no me escapomás de allí". Le hago ver que de allí me pidió volver al CAMP pero insiste en que nunca se marchará de allí se lo volvemos a llevar. Se le autoriza 20€ para que pueda desayunar y comer algo. Le propongo a Águeda realizar un Informe sobre la situación de Hermenegildo para enviarlo conjuntamente al Juzgado nº 2 de Castuera. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Guadalupe, Secretaria Judicial del nº 2 de Castuera (924- 772118 y directo el 924-773894). Se le explica la situación en la que está Hermenegildo. Comenta que ya ha dado parte al Juez y este, a su vez, a la Fiscalía para que tome las medidas que considere oportunas. Solicita enviemos por fax informe del SSB de Cabeza del Buey informando de la situación y paradero de Hermenegildo, así como los escritos de 2012 y 2013 en los que se solicitó internamiento involuntario. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Águeda. Hermenegildo ha ido varias veces al SSB. Hablo con él. Le pido que vuelva al CAMP y que mientras no vuelva allí no voy a hablar de cambio de Centro. Dice que volverá el viernes con el taxista para lo cual me pide permiso: no se lo "doy" y le insisto en que vuelva ya, pero se niega: "Volveré el viernes..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-02-03','Hablo con Jesús: sin cambios en sus planteaminetos. No acepta estancia provisional en piso supervisado, no reconoce la situación económica en la que se encuentra, no quiere renunciar a una parte del dinero de bolsillo del que dispone (50€/semana). El día 8 es el último en el que puede quedarse en el Hostal. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Juani, dueña del Hostal: le abonaremos los 280€ restantes de noviembre y 250€ de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2016-02-04','Conversación con Pedro Barragán, hermano de Guadalupe (629-278526 y 927-426250): la casa está para tirarla. Todo lo está pagando él: +++aceptación de herencia (desde hace 3 años, en enero 2013). +++catastro de los tres últimos años. +++etc. Las llaves las tiene Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2016-02-04','Llama D. Manuel, preguntando por el tema de la expropiación.Desde la Comisión se ha enviado ya el documento firmado en relación a este tema, lo que se comunica a Don Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-02-04','Hablo con Clara (T. Soc. C. Salud de Guadalupe): urge solicitar cambio de especialista para Juan, pero no creemos que una hoja de reclamación sea la vía. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Martina (Dependencia) para ver la posibilidad de agilizar la valoración de Juan para asignarle el recurso correspondiente (queda pendiente de hablar mañana con Clara (Dependencia)). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con ESM de Cáceres: no es posible elegir especialista. Solo en determinadas circunstancias se podría valora una cuestión de este tipo.Le comento que su médico, Dra. Consolación,han hecho una derivación al ESM de Cáceres. Verá dicha derivación y los términos en los que está hecha. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo al Dr. Medina, Psiquiatra del ESM de Trujillo, al que Juan se niega a ir.Tiene cita a principios de marzo.Le provoca rechazo el tema del inyectable. Considera, y soy de su opinión, que Juan debe acudir a la proxima consulta con él, siquiera para mantener el contacto. Hablará con la Dra. Consolación para decirle la cita de la próxima consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2016-02-04','Informe de Piso Supervisado de Zafra: han decidido espaciar los permisos al domicilio familiar por la inestabilidad emocional y conductual con la que volvía de cada uno de ellos. Solo irá a su casa una vez al mes y solo por el día (volviendo por la tarde al Piso. Ingreso en UHB de Llerena del 7 al 13 de enero de 2016 (conflicto con una compañera del piso y relación sentimental con otro usuario del CRPS).','2');
