insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-02-05','Conversación con Mar Román, de Santander Consumer (maria.mar.roman.@lindorff.com).REF: MV3472. La ejecución hipotecaria está solo pendiente de que el juzgado determine la fecha para que el banco tome posesión de ella. La Comisión plantea la posibilidad de que D. Ventura permanezca en la vivienda mediante el pago de un alquiler a precio de mercado, para evitar un desequilibrio en su situación personal y de salud. Para ello, Mar nos pide un informe sobre la situación de la D. Ventura, en el que se haga constar referencia sobre los precios de alquiler de la zona y la situación de él.','2');
