insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-05','FUGA Comunicar que Hermenegildo se ha fugado sobre 13:30 Hs. Acuden a buscarlo la directora y el conductor del Centro y Hermenegildo noha querido subrise en la furgoneta para regresar al Centro, les ha amenazado con una piedra. Ha tenido que intervenir la Policía Nacional. Lo van a traer de regreso al Centro engañado con el argumento de que van a ir a Villanueva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-05','REGRESO 14:55 Hs. Hermenegildo regresa al Centro, en coche, con dos agentes de la Policía Nacional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2016-02-04','TRASLADO Ha sido trasladada desde el hospital Infanta Cristina de Badajoz a una plaza sociosanitaria, modalidad C-2, en el Centro Encinar de las Cruces en Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-02-08','Del Registro de la Propiedad de Mérida: es USUFRUCTUARIO al 100% de la vivienda sita en C/. Almendralejo nº 30 de Torremnejía. No hemos recibido todavía noticias de la hermana, DªJosefina, para fijar la fecha de la reunión aplazada antes de Navidad, tal como quedamos el pasado 26 de enero en nuestra última conversación. Conversación con Dª Josefina: mantenemos la reunión el jueves 11 de febrero a las 13:00h en el CSS de Mérida (aunque no haya todavía Psiquiatra asignado)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-08','FUGA En fecha 05/02/2016, 16:00 Hs. Sobre las 23:00 Hs., la Policía Local llama al Centro para comunicar que Hermenegildo está ingresado en la Unidad de Salud Mental del Hospital de Mérida. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llama su sobrina Marta (678-284973) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Clemen. Sigue en UHB de Mérida. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2016-02-08','Hemos solicitado a la Notaría de D. José Luis Pérez Cardesa,de Cáceres, nota simple de la escritura de la herencia correspondiente al marido de Dª. Concepción, donde los titulares de la finca donde vive Concepción, son sus hijos, Manuel e Inmacuada, renunciando ella al usufructo sobre la finca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2016-02-08','Hemos solicitado a la Gerencia del catastro de Badajoz, nos indiquen nombre de la finca de la que son titulares los hijos de Dª. Concepción, Manuel e Inmaculada, para comprobar si se trata de la finca El Compresor, donde vive.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2013-03-27','27/11/2013 Expediente -Se visita a Emilia , abuela de Daniel Montaño ( C/ Berna , 53 tf. 619085037) para comprobar el estado de la vivienda y su solicitud de salidas con Daniel . La casa está en perfecto estado de habitabiliadad e higiene , en muy buenas condiciones y con mucha limpieza . La abuela tb tiene un buen aspecto a nivel personal y solicita permiso para que Daniel pase con ellas las fiestas del 24-25-31-1-6 de diciembre . Por nuestra parte y siempre que mantenga sus compromisos de no faltar a las citas propuestas y no permitir acceso al domicilio de su hija ( orden de alejamiento en vigor ) no existen inconvenientes para ello .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-02-05','-Se comprueba con May que tiene pedida para traslado la RM del Prado , y la de la Granadilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-02-09','Llama Juani (Las Veletas): Jesús se marchó ayer del Hostal. Le ha llevado sus cosas a un amigo. Juani le propuso pasare la noche en el hostal si no encontraba otro lugar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Jesús (635-336539).Dice que está durmiendo desde esta pasada noche en un cajero automático. Trato de hablar razoonadamente con él por enésima vez, pero insiste en que el no se va temporalmente a un piso supervisado, que le tenemos que buscar un piso para él y sus hijos y que nosotros solo nos teníamos que preocupar de su tratamiente. Por detrás de él, se oye a alguien decirle que "...lo que pasa es que se han gastado tu dinero y ahora no saben justificarlo...". ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Carmen: la resolución de Vivienda no está firmada todavía por Secretraía General. La enviarán en cuanto lo esté.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-02-09','-SOLICITADA AMPLIACIÓN DE PLAZAS POR PIA , A LAS DOS SOLICITADAS EL PRADO , Y LA GRANADILLA SE AÑADE FELIPE TRIGO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2016-02-09','Recibimos llamada de la Notaria de Fuente del Maestre para comunicarnos que Manuel Jesús debe firmar una herencia de sus tios. Quedamos con la Notaria que en la herencia le representará su hermana y posteriormente nos envian copia de las escrituras para ratificarlas aqui en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-02-09','Hemos reenviado al Juzgado de Primera Instancia nº 3 de Ávila, la rendición de cuentas correspondiente al año 2015, que ya enviamos el 20 de mayo del año 2015, pero que no les consta haberla recibido. La necesitamos para que nos remitan la aprobación de las mismas, así como la del año 2014 y aportarla al Informe justificativo de la asunción, por la Junta de Castilla y León, de la tutela de Margarita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2016-02-09','Hemos remitido a la firma Qualit Abogados, la firma de Consolación, en nombre de Vicente, para que presenten la liquidación del impuesto de sucesiones correspondiente a la herenca de su tía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-09','Visito a Hermenegildo en la UHB de Mérida. Hablo con Alfredo de la Rubia (Psiquiatra):"es impermeable a cualquier propuesta de ingreso en Centro". Tiene prevista el alta para esta tarde o mañana por la mañana (según disponibilidad de ambulancia. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Hermenegildo: "Pedro, si me llevas otra vez a Don Benito (CAMP) te prometo que me eswcapo otra vez, te lo aseguro. Mira, Pedro, yo quiero que me lleves al Psiquiátrico de Mérida." Le xplico que eso no depende de mí, sino del especialista, pero que se lo plantearé a él. No cabe derivación ni a UME ni a URH dado que la discapacidad intelectual y el consumo de tóxicos son motivos de exclusión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se comunica a Clemen la posibilidad de alta para hoy o mañana y la conversación con el Psiquiatra. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se envía al Juzgado fax con las últimas incidencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='RODRIGUEZ'and apellido2='FERNANDEZ'),'2016-02-08','La dirección del CSS de Mérida remite informe, a petición mía (Pedro) dirigido al Juzgado de 1ª instancia nº 2 de Mérida: no se considera al paciente capacitado para que se le tome declaración ante la autoridad judicial.','2');
