insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-02-11','Indico a Dª Josefina que la reunión será en la Comisión Tutelar, Hoy a las 13:00h. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ -SE MANTIENE REUNIÓN EN LA CTAEX CON BLANCA ( TS DEL CSS ) Y HNOS DE JUAN ( JOSEFINA Y ANGEL MARI ) . NI LA FAMILIA NI BLANCA VEN CON TOTAL SEGURIDAD LA PROPUESTA PLANTEADA POR EL PSIQUIATRA DE EXTERNALIZACIÓN , VOLVER A SU DOMICILIO EN TORREMEJIA DEL QUE ES USUFRUCTUARIO CON UNA " NOVIA " QUE HA CONOCIDO EN EL CSS. COMENTAMOS LOS INCONVENIENTES DE SU VUELTA Y LA ESCASA SUPERVISIÓN QUE TENDRIAN. DE MOMENTO SE QUEDA PARALIZADA LA PROPUESTA A EXPENSAS DE NUEVA VALORACIÓN POR EL NUEVO PSIQUIATRA. DESDE CTAEX SE PROPONE UN RECURSO INTERMEDIO : CRR , RM...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2016-02-11','Seguimos aportando documentación requerida en relación con la solicitud de asistencia jurídica gratuita de noviembre del 2015 para que la represente en el procedimiento de Ejecución de Títulos no judiciales (863/2015) seguido en el Juzgado de Primera Instancia nº 13 de Bilbao.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2016-02-11','Llama Juanjo, T. Soc. del Hospital Infanta Cristina (924-218100). D. Bartolomé está ingresado en el HIC deste el pasado 3 de febrero en la UHB. La T. Soc. de Puebla de la Calzada (Rosa) le informa que sus cuentas están bloquedas y que le estan ayudando desde Cáritas y el Ayuntamiento. Consideran que habría que buscarle un centro residencial. Hoy van a tener una sesión clínica para tratar el tema. Le comento que dado el diagnóstico que figura en la Sentencia,esquizofrenia paranoide, polineuropatía sensitivo-motora y ludopatía, valoren la posibilidad de derivación a UME, CRR según consideren. Valorado por Dependencia con un Grado 3.','2');
