insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-10','FUGA 16:30 Horas. Hermenegildo regresa al Centro tras haber estado ingresado en la Unidad de Salud Mental de Mérida desde el pasado día cinco de febrero. ~~~ 17:40 Hs. Tras su merienda en el Centro, Hermenegildo se fuga de nuevo. Fue visto dirección Villanueva de la Serena. Aún no ha regresado. ~~~ Desde su reingreso, el 13/01/2016, en el CAMP de Don benito, se ha fugado en DIEZ ocasiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-10','Nos comunica Carmen Puig, del CAMP de Don Benito, que: "con relación al residente de este centro y tutelado por la Comisión Tutelar de Adultos de Extremadura, D. Hermenegildo Ruíz Romero, la solicitud de derivación a la UDAC de Plasencia, junto con la documentación requerida, ha tenido salida en el día de hoy, 10 de febrero de 2016."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2016-02-11','RECIBO LLAMADA DE SU CUÑADO RAFAEL (625194851) ME COMENTA QUE NECESITAN HACER LA DECLARACIÓN DE HEREDROS DEL PADRE DE JACINTO Y SU MADRE SE NIEGA A IR A LA NOTARIA. ESTA DECLARACIÓN DE HEREDEROS ES NECESARIA PARA PARTIR LA HERENCIA DE SU ABUELO Y TIENE A TODA LA FAMILIA ESPERANDO YA QUE HASTA QUE NO RESOLVAMOS ESTO NO PUEDEN CONTINUAR CON LOS TRÁMITES. QUEDO CON EL EN QUE INTENTAREMOS CONVENCER A LA MADRE DE ALGUNA MANERA PARA QUE VAYA A FIRMAR A LA NOTARIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='DEAN'and apellido2='SANCHEZ'),'2016-02-12','-TRAS CONVERSACION CON JUAN ( PFHC DE CACERES ) PROCEDE A ANULAR LA BAJA PREVISTA PARA LA PF AL EXPLICARLE QUE LA SENTENCIA ES UNA CURATELA MUY ESPECIFICA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-02-11','-SE MANTIENE REUNIÓN EN LA CTAEX CON BLANCA ( TS DEL CSS ) Y HNOS DE JUAN ( JOSEFINA Y ANGEL MARI ) . NI LA FAMILIA NI BLANCA VEN CON TOTAL SEGURIDAD LA PROPUESTA PLANTEADA POR EL PSIQUIATRA DE EXTERNALIZACIÓN , VOLVER A SU DOMICILIO EN TORREMEJIA DEL QUE ES USUFRUCTUARIO CON UNA " NOVIA " QUE HA CONOCIDO EN EL CSS. COMENTAMOS LOS INCONVENIENTES DE SU VUELTA Y LA ESCASA SUPERVISIÓN QUE TENDRIAN. DE MOMENTO SE QUEDA PARALIZADA LA PROPUESTA A EXPENSAS DE NUEVA VALORACIÓN POR EL NUEVO PSIQUIATRA. DESDE CTAEX SE PROPONE UN RECURSO INTERMEDIO : CRR , RM ...','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-02-15','Catalina acude preocupada porque le han dicho que va a ir una compañera a compartir piso, cosa que no es verdad. Para que se quede tranquila llamo a Asun y confirma que no hay nada de lo que dice Catalina. Pendiente de aclarar el tema de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-02-12','Hablo con Clara. Solicitamos se valore lo antes posible a Juan Chamorro y se establezca el PIA correspondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2016-02-12','Hablo con Clara. Solicitamos se valore lo antes posible a Juan José y se establezca el PIA corespondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2016-02-15','Hablo con DªMª Luisa. Solicita extra de 150€ para comprar comida. SE autorizan 100€ (solo quedan en cuenta 312). Ha comprado unos tresillos por 80€ cada uno y una tv que ha financiado a 4 meses (59.33€/mes) con Santander Consumer. Se le trata de hacer ver que si necesita el dinero para comer no debe guiarse, como ella dice, por las ofertas -"es que estaban muy baratos...". Dice estar bien con su hija y que esta le ayuda mucho, pero por detrás se oye a la hija gritando hasta que Mª uisa la corta. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con su hija, Carolina, que se muestra muy airada por la carencia de dinero de su madre "necesita dar de comer a la niña, comprar butano, etc..." Le recuerdo que la Comsión tiene como deber cuidar de su madre y no de ellas, por lo que si quiern continuar así hasta que encuentre un trabajo deberá adaptarse a la circunstancias y tener en cuenta las prioridades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2016-02-15','Convesración con Pilar (T. Soc. ESM de Cáceres). Han dado un G1 a D. José María, por lo que no puede acceder a CRR vía PIA. La única alternativa que queda, si no cambian la valoración, es acceder por emergencia social argumentando que no se encuenra en el centro adecuado a sus necesidades. Pilar no enetiende por qué lo valoran con G1, dadas las circunstancias recogidas en la Sentencia de incapacitación por el médico forense. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Trato de hablar con José Manuel, Técnico PIA (927-006788/689575711/927-006770 y FAX: 927-006789). No mer cogen el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-02-15','Hablo con Asunción Cabrera (924-388179 y asuncion.cabrera@yahoo.es). Carmen no acudió a la última cita. Asun me pide comntactar con ella y citarla para el jueves 18 de febrero a las 11:30h. La llamo varias veces pero corta la comunicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='MORENO'and apellido2='CARRASCO'),'2016-02-12','SE asiste al Juzgado de lo Penal nº1 de Badajoz. Archivan la causa 66/2015 pero, según la abogada, Dª Mª Dolores Moreno Nieto, no queda cerrada todavía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-02-15','SE respeonde a las comparecencias de D. Ramón al Juzgado de 1ª Instancia de Jerez de los Caballeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='GONZALEZ'and apellido2='OLIVERA'),'2016-02-08','Se presenta en la CTAEx denuncia de deficiencias en el funcionamiento del CR "Nuestra Señora de la Piedad" de Almendralejo, por parte de la Médico del centro Dra. Dª Alejandra Mª Merino Mtez, al tener tutelada a Dª Inés. También se presenta denuncia ante la Inspección de Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='GONZALEZ'and apellido2='OLIVERA'),'2016-02-15','Hablo con Inspección de Mayores para saber si ha habido alguna actuación por su parte y se me indica que va a ser el SES el que investigue la denuncia. De momento, en esta tutela hemos pedido toda la información relativa a Dª Inés y estamos a la espera de recibirla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2005-04-21','Esquizofrenia Paraoide crónica con axacerbaciones agudas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-02-15','Hablo con María (T. Soc. del CSS de Mérida-UME):Ingresó el pasado 10-02-2016 en UME, proceedente de UHB del Hospital Infanta Cristina, acompañado por su hermana Mª José (Medico C. Salud de Alburquerque). Isabel Contador (hermana, profesora de Infantil):655-655100 (llamar de 12 a 12:30h).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-02-15','-Amalia ( TS ) realiza visita al piso de Coronada . Se comprueva el lamentable estado de la vivienda , los pisos de la cocina y baño se han caido , la casa está muy sucia , paredes con numerosos agujeros ... Los anteriores inquilinos se han llevado el lavavajillas nuevo y la mesa de camilla y sillas del salón . -Me reuno con su hermana y seguidamente con los hijos . La hermana está dispuesta a cubrir los gastos para adecentar la vivienda y poder volver a alquilarla . 227€ del sofá + 266 albañil + carpinteria + pintura . Los hijos darán de alta agua y luz adelantando su dinero . Una vez que se alquile se les devolverá el dinero que aporten a cada uno . -Caser seguro no cubre nada de los desperfectos del suelo de la cocina y baños . -Se amplian a Felipe Trigo , la Granadilla y el Prado las plazas para traslado . -Se va a solicitar la posibilidad de permuta . -Hay que reclamar a los anteriores inquilinos el pago pendiente de alquiler + lavavajillas+ mesa y sillas del salon. -Tema juridico también pendiente ( pensión compensatoria de hijos )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2016-02-17','Conversación con Magdalena Gómez, T. Social CR "Rodríguez Ibarra" (45609). Se informa de cómo actuar en caso de incidencia en fin de semana. Dom Blas se encuentra bien, recibe las llamadas de su hermana Juana y ocasionalmente dice que quiere volver a su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-17','Hablo con Clemen. La Pol. Local les llamó el lunes para decirles que Hermenegildo tenía una citación en el Juzgado de 1ª Instancia nº 2 de Castuera el próximo 18 de febrero. El mismo lunes me llamó Clemen para decírmelo y le pedí que nos enviara la citación por fax cuando les llegara (porque el 18 también tenemos un Juicio en Plasencia). Traté de hablar con el Juzgado para confirmarlo por teléfono pero no fue posible. Hoy hablo de nuevo con Clemen y me dice que la Pol.Local se equivocó y llevaron a Hermenegildo al Juzgado el pasado lunes, 15 de febrero. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con el Juzgado nº 2 de Castuera (924-772118). A raíz del último fax enviado al Juzgado desde CTAEx, ESTE HA ABIERTO UN PROCEDIMIENTO DE INTERNAMIENTO INVOLUNTARIO, PARA EL CUAL SOLICITÓ EL RECONOCIMIENTO MÉDICO-FORENSE así como el RECONOCIMIENTO JUDICIAL QUE SE LLEVÓ A CABO EL PASADO LUNES 15. Quedamos a la espera de que se nos remita dicho informe así como la decisión tomada por parte del Juzgado en relación a D. Hermenegildo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-02-17','Clara (T. Soc. C. Salud Guadalupe): cita en ESM el 01 de marzo de 2016 a las 12:00h. Se comunica a Toni (Futuex). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a la Dra. Consolación (927-367217). No cogen teléfono. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-02-17','Llega Resolución de Denegación de la Vivienda solicitada a Jesús. Motivo: "...no es el recurso adecuado, dadas las características del solicitante, ya que en el caso de existencia de vacantes , el entorno de ubicación de las viviendas puede ser un factor negativo para la recuperación del mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2016-02-17','Bartolomé recibe el sad por dependencia. Desde SSB Rosa 606 911844, contactan para tener conocimiento del presupuesto que cuenta Bartolomé, ya que le realizan la compra de alimentos y cocinaposterior. Se le informa por email a Rosa( ya que no ha sido posible contactar por teléfono) que el banco está realizando el "bastanteo" de la documentación., en cuanto lo resuelvan contactamos con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2016-02-17','SE fija reunión en SEPAD para el viernes 19 de feberero a las 09:00h. Tema Alta en Piso Supervisado y búsqueda de piso de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='GARCIA'and apellido2='DE PRUNEDA TREVIJANO'),'2016-02-17','- Nos comunican que tiene plaza residencial en Olivenza. Del CRR Badajoz nos informan que está ingresado en el H.I.C. tiene una enfermedad grave de garganta en valoración . Enviarán informe del ESM para entregar a May indicando no problemas de conducta. Solicitaremos que nos guarden la plaza residencial .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2016-02-17','- El padre de Iván ha fallecido hace unas semanas , según información de Juan Gordillo director del CAM Ana Bolaños. Ver si se puede solicitar P. Orfandad para Iván . Su padre era adjudicatario de Vivienda con alquiler social por la que se abona 25€/ mes . La idea es que la mantengan los hijos para poder tener un lugar donde reunirse los cinco , cada mes abonaría uno la mensualidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CELESTINO'and edp.apellido1='RINA'and apellido2='ALEGRE'),'2013-02-06','La madre de Celestino murio en diciembre de 2012 y se ve posibilidad de pedir pensión de orfandad. Ya se ha intentado en otra ocasión pero se quedó pendiente. Esther TS del centro informa que hay unos familiares que han solicitado la tutela a Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CELESTINO'and edp.apellido1='RINA'and apellido2='ALEGRE'),'2016-02-18','Acuden Clemen y Miriam del CAMP de Don Benito. Informan del ingreso urgente de D. Juan en la UCI del Hospital Don Benito-Villanueva. Hablo con la UCI del Hospital. No pudeo hablar con el médico porque está en otra intervención. Comento que pueden contactar con la Comisión hasta las 15:00h (son las 14:45h). Doy el fax para que nos envíen el consentimiento informado. En caso de necesidad, por la tarde, se pondrán en contacto con el CAMP de Don Benito.','2');
