insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2016-02-22','INFORME FUTUEX 10/02/2016. • Revisiones y Consultas Médicas: Próximas revisiones: 9 de Marzo de 2016, consulta de enfermería e inyectable. • Medicación y pautas: Depakine 500 mg (1-1-1) Xeplion 150mg (una al mes) Placinoral 2mg (1-0-2) 29 de Marzo de 2016, consulta de psiquiatría. Ha comezado dieta por sobre peso, no obstante debe disminuir consumo de cafe, coca cola y tabaco ( una cajetilla) -Ha recibido la visita de su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2016-02-22','Hemos enviado a notaria de Fuente de Cantos documentación acreditativa de la tutela de Antonio, a los efectos de ir preparando la herencia de sus padres y tíos abuelos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-02-22','SE envía nota interior a la Unidad de Gestión de Programas Asistenciales, sobre el pago de la plaza de Vivienda Tutelada de Aprosuba 8 entre los meses de octubre y enero (a.i.)de Eva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2016-02-22','Llama Juan, hermano de D. José María. Quiere saber si puede pedir la tutela de su hermano ("Ya el juez me dijo que no") y saber si por cuidarlo tenía derecho a alguna pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-02-19','Llama Isabel Mateos (50450) de S.G. de la Vivienda, interesándose por la situación de D.Ventura. Le informo de que estamos a la espera de que Santander Consumer responda a nuestra última propuesta de que Ventura se mantenga en la vivienda a cambio de pagar un alquiler a precio de mercado. Se le envió la propuesta junto con los precios de alquiler de la zona. Informaremos a Isabel (también podemos hablar con Susana) del resultado de esta propuesta y, mientras tanto, queda el expediente abierto en Vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-02-18','Conversación con Hermenegildo: quiere que le enviemos dinero para comer, pero se niega a volver al CAMP, condición que le ponemos para darle el dinero."No voy a volver. Además, Pedro, el lunes me dijo la Jueza (fue al juzagado con la Guardia Civil para pasar reconocimiento judicial y forense) que me estaba buscando otro centro y que en dos semanas lo tendría. Y me dió permiso para quedarme en el pueblo esas dos semanas..." Solamente para desmentirlo hablé con la Jueza (Dª Felisa) quien, por supuesto, desmintió dichos puntos, informándome de que estaban a la espera del Informe Forense para tomar una decisión. Retomo la conversación con Hermenegildo y se mantiene en su postura. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Marta (sobrina)."Ya que él no quiere volver al CAMP y si vuelve se va a escapar, si le parece se puede quedar aquí con nosotros. Mi madre dice que puede comer en su casa pero que no quiere que se quede a dormir, por lo que para dormir se quedará en la mía." Mi respuesta es la siguiente: "Yo no puedo decirles a ustedes lo que deben hacer, eso depende de ustedes. Yo lo que les digo es que Hermenegildo donde debe estar es en el CAMP." Conversación con Marta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-02-23','Llamada de Jesús. Pide más dinero y pregunta por la vivienda que le hemos solicitado a Vivienda (se le informa de la denegación). Se insiste en que acepté ingresar en un Centro temporalmente hasta pagar sus deudas y ahorrar algo de dinero para acceder a un alquiler, pero se niega en redondo por enésima vez. Comenta que estuvo hace unos días en el ESM y Pilar le volvió a insistir sobre el tema. Refiere que tiene una vivienda en Zarza la Mayor, c/.Concejo nª 54, que su padre puso a su nombre en el 89 y que ahora, al parecer, está a nombre de sus padre "...sin que yo haya firmadao nada..." .Pediremos nota simple al Registro de la Propiedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='DEAN'and apellido2='SANCHEZ'),'2016-02-23','SEGUIMIENTO FUTUEX 16/02/2016: Se contacta con el telefonicamente y se niega a habalr con ella ya que insiste en que no está tutelado,tal y como aparece en sentencia. ACTUACIOON ACORDADADA POR CTAEX´con futuex para mes de marzo: -Volver a contactar para aclarar los términos de le curatela. -Seguimiento en el centro de salud sobre la asistencia y comportamiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CARDENAS'and apellido2='CARMONA'),'2016-02-23','Conversación con la Dra. Esther Fdez. Quintero (CSS Mérida): Dª Carmen ingresó el pasado 19 de febrero en el Hospital de Mérida. A fecha de hoy ya ha recibido el alta médica: presenta fractura de nariz por caída con contusión craneal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2016-02-16','Se visita a Dª Concepción (627-154054) en el cortijo "El Compresor", acompañado por Josefa Sánchez, T. Social del SSB de Azuaga (924-137996). Llegamos al cortijo sobre las 10:30h. Concepción no respondía a nuestras llamadas, por lo que un señor (Antonio) que había allí, cuidando de los animales, fue por las traseras y la llamó: estaba durmiendo. Se disculpó por ello. Tenía un aspecto normal, vestía ropa deportiva y estaba un poco somnolienta. La vivienda, carente de suministro eléctrico (deuda con Endesa de 1000€), estaba bastante limpia (salón y dormitorio), según Josefa porque su hija Inmaculada había estado allí hasta el día anterior.Nos enseñó la casa, salvo la habitación de su hija que ésta cerraba con llave cuando se iba. Salón:ordenado y bastante limpio, con una mesa camilla con brasero de gas, sofá , dos sillones y varias sillas; dormitorio de Concepción: el novio de su hija le ha llevado una cama, que en el momento de la visita estaba sin hacer, cierto desorden en la habitación, con ropa colgada en dos armarios y también en bolsas en el suelo bien colocadas.Fuera de la casa, adosada al lado de la entrada, está la cocina, hecha un desastre: muy sucio todo, caótica, guarda los alimentos en un armario (casi todos no perecederos). Dice que cocina todos los días pero la cocinilla, de gas, no daba la sensación de ser utilizada. El aseo, fuera de la vivienda, frente a la entrada de esta, tampoco estaba en buenas condiciones, aunque algo menos malas que la cocina. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++FFuera de la vivienda había un caballo, un poni y un mastín. También en una de las naves, en la que estaba trabajando Antonio.Al parecer, este hombre siempre ha trabajado allí, cuidando sus animales a cambio, según Concepción, de diferentes artreglos que ha dio haceindo en la casa: el tejado debe ser buevo, porque por dentro se ven las rasillas nuevas sin lavar con yeso, las vigas son nuevas,las tapias que limitan la finca, etc. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Concepción no acepta ayuda de ningún tipo: ni SAD, ni plaza residencial, ni nada. Solo quiere estar en su casa, carente de electricidad. Preguntada por los dos ingresos que tuvo en CSS dice que se encontraba muy bien allí: "Comía bien, estaba tranquila, etc..." Cuando se le indica que si no preferiría estar así en un Centro dice que no, que ella está bien donde esta. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ En Zalamea dice tener una casa de su madre y un piso compartido con Ángela (cedido). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Estamos pendientes de tener una entrevista con su hija Inmaculada, a falta de concretar día y hora, dados los exámenes que en esta semana tiene ella en la Universidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-02-23','INFORME FUTUEX 15/02/16: Necesita el arreglo maxilofacial. Solicita la compra de movil y retomar las revisones de traumotología. ACTUACIONES FUTUEX PARA MES DE MARZO. -Ver presupuestos de moviles -informara que tiene concedido abogado de oficio pero aun no asignado (Ángel ya le ha informado anteriormente en varias ocasiones. -Informarle que se ha enviado un escrito al ses para que vuelvan a realizar las reviosnes de traumatologia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-02-23','-Se recibe resolución del ISFAS en la que se le concede PHHC con ayuda de 3ª persona con efectos 1-1-2016 de 551,90€.Tambien está percibiendo P. Orfandad tras el fallecimiento de su padre.','2');
