insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2016-02-24','Se recibe en la Comisión correo electrónico de Javier (Director de CRR PLasencia: 927-423978///677-407640) en relación a Dª Eugenia. Temas: dependencia de tragaperras, limitación uso dinero y denuncia interpuesta en el Juzgado contra la CTAEx y la T. Ocupacional del CRR. Ver sentencia de incapacitación. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Javier pero mestá el equipo reunido. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='FARIÑAS'and apellido2='SOTO'),'2016-02-24','-May nos comunica que hay plaza en la RM de Valencia de Alcantara , se solicitó traslado desde RM Felipe Trigo en 2011. Ahora se desaconseja , no la visitan los familiares y tiene deterioro cognitivo . Nieves ( TS ) enviará justificación desaconsejando el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-02-25','En relación con el Juicio Rápido 69/2015 (Ejecutoria 397/2015) (violencia doméstica contra su exnovia Susana Tobal Rodríguez), se le impuso, entre otras, pena de 24 días de trabajo en beneficio de la comunidad. Para cumplirla, DEBE acudir, cuando le citen (indicamos que lo hicieran aquí), a una entrevista a celebrar en el Servicio de Gestión de Penas, en Badajoz (C/. Fernando Castón, 2)(92423827, Ramón). En esa entrevista le dirán los sitios donde puede cumplir la pena. Para ello, antes de acudir, disponen de una trabajadora social (Paqui 924256158), con la que hablar por nuestra parte y ofrecer alternativas para su cumplimiento. Las responsabilidad civil derivada de este juicio, por importe de 225 euros, ya ha sido abonada.','1');
