insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2016-02-26','Mª Soledad del Moral Chaves consulta, desde el Programa de Atención a Familias de la Mancomunidad Tajo-Salor, sobre la trámites de la herencia tras el fallecimineto del padre de Dª Felisa el pasado mes de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2016-02-26','Visita realizada por Amalia Y Pedro en la Prisión de Badajoz. Conclusiones: D. Rafael se mostraba con claros delirios megalomaníacos. Consideramos que debe permanecer en Centro cerrado, opinión compartida también por Víctor, Psicólogo que lleva el caso de nuestro tutelado. Enviarán informes clínicos y psicológicos que justifiquen la solicitud, por parte de CTAEX, de internamiento involuntario al Juzgado de 1ª Instancia nº4 de Badajoz. LA EXCARCELACIÓN SE PRODUCIRÁ EL PRÓXIMO LUNES, 14 DE MARZO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SAUCEDO'and apellido2='AGUEDO'),'2016-02-24','José Antonio Saucedo se encuentra en la Residencia "Nuestra Señora de la Luz", cuyo coste es afrontado por la D.G. de Infancia y Familia (Ver contrato).Compañeros de la D.G. de Infancia y Familia con los que hemos contactado para el traspaso de la tutela: Pilar Salguero (Jefa de Sección en Badajoz), Carmen Brioso (60350) y Rosa Mª Alonso (68831). El Técnico que ha seguido el caso es José Miguel Manzano (40057 y 924-010057). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Cuando estemos en disposición de hacernos cargo de la plaza residencial (esta u otra) lo comunicaremos a Infancia y Familia para que dejen de pagarla. Con Rosa quedamos en que, hasta entonces, sería la D.G. la que seguiría abonando la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-03-01','Acuden los padres de D. Ramón y su hermano Juan (634-703501) porque no han recibido la transferencia pactada en su anterior visita hace unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2016-03-01','Recibimos I.Social de Rosa Zúñiga, T. Soc. de Don Benito (924-808053 y fax 924-808176), para cumplimentar el expediente de solicitud de plaza residencial para Dª Mª Luisa. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se intenta enviar dicho informe por fax al Servicio Territorial de Badajoz, a Teresa García (40149 y 924-010149///fax 924-010001) sin resultado, por lo que se envía al siguiente correo electrónico: concepción.herrera@gobex.es. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Dª Carolina, hermana de Mª Luisa, (924-812397 y 696281560). Tiene claro que lo que se debe hacer: ingreso involuntario en centro ("Ella no va a querer de forma voluntaria. Luego se echa a mi sobrina y se cierra esa casa y ya sabrá ella lo que hace. Porque mi hermana es la usufructuaria, ya que la casa era de mi madre". +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Obtiene 63 puntos en el baremo para acceder a plaza residencial: 2ª en listado genereal de EL Prado; 5ª en el de La Piedad y 10ª en la de Cervantes. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Solicitaremos internamiento involuntario al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2016-03-02','LLama Dª Juana Pin, madre de Marco (666-898908). Solicita una ayuda para ella porque están muy necesitados. Dice que cuando su hijo vaya a verla que le demos 300 ó 400 euros. Le explico las obligaciones que la tutela que ejerce la Comisión tiene y que, cuando su hijo vaya a verla se le puede dar dinero de bosillo, pero no atender otras necesidades diferentes a las del propio tutelado. SE le indica que si están en una situación precaria, acuda a la Trabajadora Social del Ayuntamiento para ver cómo se le puede ayudar en su situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2016-03-02','Llama María Barrasa (T. Soc. CSS Mérida). Ricardo está insistiendo en marcharse a su piso. En UME no puede eseguir mucho más tiempo y no quiere piso supervisado. La alternativa es la URH, lo que puede comprometer el alta. Vamos a solicitar presupuesto para valorar el coste de las reformas a realizar en su piso. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se pide presupuesto a "Construcciones José Gómez". Hoy mismo visitan, junto con CTAEx, la vivienda y el próximo viernes, 4 de marzo, acudirán nuevamente a las 10:00h para valorar las distintas reformas a realizar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-02-29','Piden de Santander Consumer certificación de las pensiones de D. Ventura. Este próximo jueves se reune la Comisión de Valoración. Se envía este mismo día dicha certificacción por correo electrónico(maria.mar.roman@lindorff.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-03-02','Llama Isabel Mateos (50450), de D.G. Vivienda. Se le informa de la última gestión realizada. La informaremos del resultado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2016-03-02','Vuelvo a llamar a Javier (Director del CRR: 927-423978 y 677407640). NO está. Avisarán de mi llamada cuando llegue. De todas formas, llamaré a partir de las 10:30h. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a las 14:10h. Me dicen en el CRR que está en Mérida, por el aniversario del CRR de la localidad. Llamo al móvil pero no contesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2016-02-25','Visita de la CTAEx en Aprosuba 3. Teléfono de Pedro:662-482389).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2016-03-02','Hablo con D. santiago Ortega Méndez, abogado (924-842616) que Aurora dice haber contratado para remover la tutela. No le suena el tema, pero lo consultará en su archivo y nos llamará para confirmarlo o no. Le dejo también el correro de CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN JOSE'and edp.apellido1='EXPOSITO'and apellido2='VERDION'),'2016-03-02','Llamo a Dª Mª Ángeles Expósito (924-002699, 610-894887 y del trabajo Ext. 62699). No coge el teléfono. Llamo a su hermano Marcos, al que, tras consultar algunas dudas, le pido el teléfono de su hermana:610-894887.Tampoco me contesta en este teléfono. Una vez contactado con Mª Ángeles, se responde a las dudas que plantea respecto del ejercicio de la tutela y se le informa de que puede recabar la legislación pertinente en el Código Civil y la Ley de Enjuiciamiento Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2016-03-02','Visita de Juan Manuel (651-148796) con su madre, Dª María (664-678227) y una amiga de la madre. Solicita Dª María un aumento de los 200 euros que se le transfieren desde junio del año pasado. Considerando los gastos que comenta Juan Manuel (tabaco >120€/mes, móvil de tarjeta 15€/mes y algún café) se considera oportuno el envío mensual de 266€ mensuales, quedando los 100 restantes en su cuenta para posibles extras. Se lo indico así a Marisa, ya para el mes de abril. Además le debe a su madre los 200€ del móvil que le va pagando poco a poco. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se le recuerda a Juan la posibilidad de comprar tabaco "a granel", que ya conocía. Se insite en tratamiento y asistencia a consultas. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hoy lo ha visto el Dr. Periáñez en Mérida, pero lo ha derivado ya al ESM de Miajadas, donde vive con su madre. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ La madre se está planteando la remoción para asumir ella la tutela y Juan también lo desea. Pero ella se muestra prudente y prefiere esperar para ver cómo evoluciona su hijo. Ahora dice estar contenta con su comportamiento pero, como digo, se muestra prudente. "...No hay que bajar la guardia".','2');
