insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-02-22','Hola, esta mañana he hablado con una compañera en relación a Isabel Muñoz Melchor. Quisiera comunicarle otro teléfono de contacto de la residencia donde se encuentra (Jaraicejo) ya que ha cambiado el director: Marcos: 659950675 y 699036400 Un saludo Olga Rubio Collado. T. Social C. Salud Plasencia III. S.E.S. Telf.: 927 42 84 21','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-02-22','Buenos dias tras embiarle varios correos y no darle solucion para consegir un tlf e optado por comprarme uno lo cual me lleva a kedarme sin dinero para toda la semana culla cantidas de 50e no cubre mis necesidades ya ke como sabeis y devida a vuestra falta de administraciob me veo obligado a vivir en la calle si kereis suvirme la cantidad adsignada me lo comentais y si kereis darme dinero para malvivir esta semana lo demostreia yo soy jesus manuel ramos bargon y ya ke vosotros no haveir puesto los medios para ke consigiera un tlf y asi estar por lo menos localizado ya los e puesto yo ke sepais ke no me keda dinero para pasar la semana y la cantidad de 50e semanales para vivir en la calle es insuficiente mi numero de tlf es 635336539','2');
