insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2016-03-04','Hemos enviado al Juzgado de Primera Instancia nº 4 de Badajoz, solicitud de internamiento involuntario. Ya nos indican de antemano que no va a proceder el mismo porque necesitamos aportar Informe Médico Psiquiátrico que lo avale. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ ++++++++++++++++++ Hablo con Víctor (Subdirector de Tratamiento, 924-289102) sobre esta situación y posteriormente con Victoria Pita (924-289105), Médica del centro penitenciario: van a intentar tener consulta por videoconferencia con el Psiquiatra de la UHB o del ESM de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2016-03-04','Hemos contactado con el abogado de oficio, D. José Antonio Pardo Castro para que proceda a solicitar la anulación del testamento otorgado por Marcelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-03-04','Pedro. Llamo a Miguel Medina (Psiquiatra ESM Trujillo). No está. Hablo con Nuria, Enfermera del ESM. Segun comenta, vieron a Juan bastante mal, con indicios de descompensación. Se le comenta que desde CTAEx consideramos que debe estar atendido en un Centro y que nuestra sugerencia es que el Psiquiatra haga un informe con la propuesta de intervención que considere oportuna. Se comenta que, en caso de internamiento involuntario, es más ágil la derivación desde Psiquiatría que si se solicita al Juzgado. Enviarán informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='DEAN'and apellido2='SANCHEZ'),'2016-03-04','Recibimos informe de seguimiento de Salud Mental de fecha 24 de febrero de 2016.Plan de seguimiento: en 2 meses analítica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-03-04','Mar, de Santander Consumer, me informa de que la comisión de valoración HA DENEGADO la propuesta de alquiler a precio de mercado hecha por la CTAEx. Le pido que, si es posible, nos envíe la resolcuicón documnetada. Tiene que consultar si es posible porque "se trata de documentación interna". Le pido que nos dé un margen de tiempo para poder buscar una alternativa válida para Ventura. No le puedo indicar un plazo hasta que no hable con la compañera de la DG Vivienda. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Isabel Mateos (50450). Le informo del resultado de la propuesta. Quedamos en que el lunes me llamará una vez haya hablado con Nuria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-03-07','-nuevo tf de Vanesa : 642089801 -Miguel ( novio ) ha estado en SS.SS le van a tramitar prestación economica . Mña tiene nueva cita .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='CACHO'and apellido2='LINDO'),'2016-03-07','Hablo con Víctor nuevamente. Me comenta que Mª Victoria, la médico, está con el tema del Informe del Psiquiatra y que incluso había hablado con Beatriz Martín, de la Sudirección de Salud (924-382511). Hoy no está, pero mañana se pondrá en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2016-03-07','Llama José para decirme que el sábado vió en la calle a sus antiguos compañeros de NACE y que Mini (Mª Carmen) le dijo que no había vuelto a llamrlos ni a preguntar por ellos, a lo cual José respondió que "Tampoco vosotros lo habéis hecho conmigo, así que vosotros por vuestro lado y yo por el mío..." Y Mini me respondió que, aunque me vieran tendido en el suelo, no me iban a ayudar..."Para que veas, Pedro. Y nada, solo quería que lo supieras, lo que me había pasado."','2');
