insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-03-07','Llamo a Consuelo (927-420448). José María fue a la consulta de salud mental el pasado día 28 de febrero y le volvieron a dar cita para el 30 de mayo. Consuelo considera que es muy tarde. Lamaremos al ESM de Plasencia para tratar de adelantar la consulta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-03-07','Llama Dª Josefina preguntando por la situación de su hermano. Se le indica que, desde nuestra última reunión, no hemos tenido ninguna novedad del CSS. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Blanca: el Psiquiatra, Alfredo garcía de Vinuesa ha habldo ya en una ocasión con Juan y le ha dicho que debe tener paciencia, que debe estudiar su caso y una vez lo haga hablarán del tema. Según Blanca, Juan y su pareja están bastante tranquilos, ya que no acuden a ella con la frecuencia y premura que lo estaban haciendo en los últimos meses.','2');
