insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2016-03-10','Visita a Felipe en Novaforma. Se quiere ir en Semana Santa a La Haba. La semana próxima quedamos en programar visita domiciliaria con Futuex, a la que asistirá también CTAEx para hablar con su sobrina, que actualmente ocupa la vivienda de la que tiene un legado (25%).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2016-03-14','Llama D. José González, Alcalde de La Haba: quiere saber si la Junata puede hacer algo respecto a los ocupantes de la vivienda de Felipe y nos informa de que hace unos días la pareja de su sobrina fue detenida por la Guardia Civil al intentar entrar en la vivienda colindante mediante la fuerza, estando los propietarios de la misma en su interior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2016-03-11','Visita domiciliaria a Dª Marisa, en compañía de Rosa, T. Social del SSB. Acudimos con ella Amalia Y yo a la vivienda de Dª Marisa, sobre las 10:15h de la mañana. Dª Marisa estaba en casa, al cuidado de su nieta. Esta estaba sentada en su cochecito y su aspecto era inmejorable: bien vestida, limpia y aseada y con un aspecto saludable, activa y sonriente al llamar su atención. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ La casa, la parte que pudimos ver, estaba ordenada y limpia (entrada, salón y al fondo la cocina). Según supimos más tarde havía poco que la hermana de Marisa la había pintado y arreglado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Carolina, la hija de Marisa, se encontraba acostada cuando llegamos a la vivienda (10:15h), pero salió enseguida cuando oyó quiénes éramos y a qué habíamos venido. Salió en pijama y poniéndose las zapatillas, se sentó al lado de su hija, al otro lado de la mesa camilla sin decir nada. A propuesta de Rosa, pedidoms a Marisa que nos acompañara al SSB para hablar con ella, momento en el que intervino su hija, Carolina, para mostrarse contrariada por no enetender por qué no podíamos hablar con su madre delante de ella. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Dª Marisa nos acompañó al despacho sin problema. Su aspecto era normal, con un discurso tranquilo y educado. Nos contó que se encontarba bien conviviendo con su hija y nieta: "Mi hija ha cambiado, ahora me hace más caso. Tiene un genio muy fuerte, en eso ha salido a su padre." Dª Marisa desmiente todas aquellas incidencias que aparecen en los informes del SSB y de Futuex: la desestabilización emocional desde que su hija volvió, los gastos extras originados, los problemas de convivencoia con los vecinos, los problemas de convivencia con su hija...Pinta una situación completamente diferente a la que desde CTAEx se tiene conociemineto por cauces oficiales. A lo largo de la conversación, se emociona en un par de ocasiones:en la segunda llega al llanto al decirnos que su hija se va a ir a Sevilla porque allí sí tiene derecho a la Renta Básica (según Rosa, se ha negado a acceder a ella por no querer verse obligada a la contraprestación que la misma exige, además de estar diciendo que se va a ir a Sevilla desde hace mucho tiempo) y que va a echar mucho de menos a su nieta, con la que parece tener un fuerte vinculo emocional. Cuando se le plantea que si no es para ella un esfuerzo excesivo el cuidado de su nieta y el mantenimiento de su hija responde que no, que es su abuela y madre y que ella no se quiere ir a ninguna residencia. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Cuando se marcha, Rosa insite en que nos ha mentido en todas y cada una de las cosas que nos ha contestado y referido. Le proponemos hablar con la hermana de Dª Marisa, Dª Carolina (se llama como su sobrina). Esta acude al despacho de Rosa y nos comenta lo siguiente: su hermana debe estar en una residencia, en el piso su sobrina mete a gente desconocida, se cree que puede darse consumo de sustancias y/o prostitución (todo ello lo niega María Luisa). Ella quiere que llevemos a su hermana a una Residencia -"Ella se va a adaptar enseguida, aunque ella diga que no se quiere ir..."- y que su sobrina salga de la vivienda y se arregle como pueda. Quine le preocupa es la niña..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Antes de marcharnos, volvemos al domicilio de María Luisa porque tenemos ciertas dudas de cómo su hija haya podido reaccionar tras su regreso: se encontraban las tres, jun to con un señor que María Luisa dijo que era amigo suyo. Rosa habló con él porque dijo no conocerlo. La situación estaba tranquila, con los tres adultos sentados alrededor de la mesa camilla. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Intentamos hablar con el ESM de Don Benito pero no nos fue posible contactar con ellos. Queda pendiente por lo tanto solicitar informe de Psiquiatría de María Luisa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ En opinión de Amalia y Pedro, con lo visto durante la visita y los datos recabados y sin ignorar los informes previos del SSB y de Futuex, María Luisa no parece que para ella sea necesario un ingreso en residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ARROYO'and apellido2='BERROCAL'),'2016-03-08','FALLECIDA El 18/10/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-03-14','Llama la madre de Jesús, para saber si hay alguna novedad en su situación. Nos informa de que su cuñado va a recoger la ropa sucia al lugar que Jesús le indica y se la vuelve a llevar donde él le dice.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2016-03-14','Conversaciones con el Dr. Pablo Calderón (Psiquiatra UHB de Badajoz). Teléfono: 924-218073. Para avisar del traslado de la prisión de D. Raafel, explicar las circunstancias del caso y plantear la posibilidad de ingreso en UHB hasta valorar clínicamente su estado mental. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Nueva conversación con el Pablo Calderón: informa de que ha llegado Rafael a la UHB acompañado por la Policía, esposado porque no tienen orden de libertad hasta dentro de unas horas y preguntando qué hace allí con una persona esposada.Le digo que voy a habblar con el centro penitenciario y que lo vpolveré a llamar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Belén, T. Soc. Centro Penitenciario (924-289117), Por que contacto con José Manuel. Explico la situación y le dirá a José Manuel que me llame. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamada de José Manuel (Subdirector de Régimen): me explica la situación de Rafael, a quien ya han vuelto a llevar a la cárcel: su intención, como ya habíamos hablado el viernes, era ingresarlo ya en libertad.Me pide el teléfono del Psiquiatra, se lo doy y queda en llamarme una vez hable con el. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ llamada de José Manuel: han vuelto a llevar a Rafael a la UHB y han considerado que se encontraba bien y que no era necesario el ingreso. Han regresado a la prisión, donde lo único que puede hacer es darle dinero para el autobús porque quiere quedarse en el albergue del Padre Cristóbal en Mérida (previamente desde CTAEx se habían enviado informes al albergue para que concocieran la situación de Rafael y su próxima lleagada al centro). Le pido que me deje hablar con Rafael, como una excepción: me dice que sí, que va a volver a Mérida y se quedará en el albergue. le doy los números de CTAEx para que se pinga en contacto con nosotros y le digo que, si me es posible, mañana le haré una visita en el centro.','2');
