insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='FAGUNDEZ'and apellido2='CORTES'),'2016-03-15','Recibos Fax donde nos trasladan que el estado de adolfo es Fragil, la internista del hospital ha contactado con la medico de Camp, informando de la situación y solicitando que se informe a los familiares. Adolfo tiene una hermana, la cual lo visita una vez al año. Segun conjeturas de Inmaculada (TS) cree que la hermana conoció la existencia de Adolfo hace poco tiempo. Se acuerda que desde el Cam informen a la hermana Maria (hermana) 617 245 145','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-03-15','Conversación con Agustina, Psiquiatra de UHB de Mérida. Han comunicado al Juzgado el ingreso "involuntario". Agustina considera que Carmen no tiene capacidad oara vivir sola sin supervisión. Cree que una alternativa podrían ser los pisos supervisados o el CRR. Pendiente de hablar también con Asunción Cabrera sobre esto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2016-03-15','Llamo al ESM de Don Benito. Alberto no está hoy y la T. Social va mañana. La Enfermera no está en este momento. Dejo los teléfonos y me llamará más tarde. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Ángeles, Enfermera ESM (924-802006). Le explico las circunstancias de Mª LUisa, nuestra visita y los datos que parecen desprenderse de los informes previos que tiene la Comisión. Se le pide que, en la consulta que María Luisa tiene el 16 de abril, consaideren la conveninecia o no de ingreso en centro residencial. Lo comentará con Inma (T. Social) y con Alberto (Psiquiatra).','2');
