insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-02-01','SE REMITE INFORMACIÓN AL DEFENSOR DEL USUARIO DE LA SANIDAD PÚBLICA Y ESTAMOS ESPERANDO LA CONTESTACIÓN.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2016-03-15','Confirmamos por telefono INSS, que Modesta percibe una PNC, y que las pensiones restantes que aparecen en la cuenta bancaria de BBVA son de su Hija Flora (PF y Orfandad Parcial). Flora se encuentra en el CRR de Plasencia, Paula la Terapeuta Ocupacional nos informa que se encuentra en tramites de Incapacitación Legal. En el extracto bancario aparece 3 domiciliaciones de seguros, 4 de Cruz Roja, 1 Telefonia Movil, 1 de Telefonia fija, comunidad.......por lo cualconjuntamente con parte económica, se acuerda mantener a Modesta en la misma cuenta bancaria ya que con la PNC no podría hacer frente a todos los gastos. En cuanto se tenga, más información se procederá a la baja del teléfono fijo al igual que de la cuota de socio de Cruz Roja ( si fuera cuota de socio)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-03-15','José Mª Tovar (669-439020).Posibles abusos sexuales por parte de un celador de Novaforma. Se plantea esta posibilidad a raíz de que el pasado viernes 11 de marzo, al ser José Mª informado por Tomás de que al defecar sangraba y ser reconocido por el médico de cabecera, quien diganosticó desgarro anal, planteando la posibilidad de si Tomás tenía o no relaciones sexuales. José Mª planteó la situación en Novaforma y le dijeron que tenían que comunicarlo a la Junta Directiva, cosa que, al parecer, según refiere José Mª no se ha producido. ACTUACIÓN: SE LE PROPONE A José Mª SOLICITAR AL MÉDICO DE CABECERA INFORME DE LA EXPLORACIÓN REALIZADA O PARTE DE LESIONES (en este caso debería presentarlo al Juzgado) en el que se haga constar las posibles circunstancias que han podido dar luagar a este tipo de lesión. CON DICHO INFORME, ACUDIR A LA FISCALÍA PARA PONER EN SU CONOCIMIENTO LOS HECHOS RELATADOS POR TOMÁS Y QUE LA FISCALÍA TOME LAS MEDIDAS QUE CONSIDERE OPORTUNAS PARA ACLARAR LOS HECHOS. José Mª está de acuerdo en todo ello y en esta semana, si consigue dicho informe, lo pondrá en conocimiento de la Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-03-15','José Mª Tovar (669-439020).Posibles abusos sexuales por parte de un celador de novaforma. Se plantea esta posibilidad a raíz de que el pasado viernes 11 de marzo, al ser José Mª informado por Tomás de que al defecar sangraba y ser reconocido por el médico de cabecera, quien diganosticó desgarro anal, planteando la posibilidad de si Tomás tenía o no relaciones sexuales.','1');
