insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-03-15','Trabaja como Peón de Jardinería en el Centro Especial de Empleo "San Jorge" de Cáceres, perteneciente a la Asociación ASPAINCA. En octubre de 2003 se recibe escrito del Centro Especial de Empleo San Jorge de Cáceres, perteneciente a la Asociación ASPAINCA comunicando el despido de Tomás. No habiendo acuerdo entre las partes ante la UMAC se presenta demanda por despido improcedente ante el Juzgado de lo Social de Cáceres, bajo la dirección de la Letrada Margarita García Abella, propuesta por José Mª Tovar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='GONZALEZ'and apellido2='ROJAS'),'2016-03-16','Enviado Sepad Zafra Modelo de Aceptación del Programa Individual de No aceptación, consistente en un Servicio de Atención Residencial. Pedimos valoración (conservación telefónica) a Daniel (TS.SSB Calzadilla) y Mamen (924 55 20 33)(TS Sepad), ambos coinciden que el recurso más apropiado son los pisos tutelados de Calazadilla, por el apego a la localidad y por las relaciones familiares , Carmen tiene una hermana, la cual la visita diariamente, el estado de Dependencia de Carmen, permite este recurso, cuando transcurra un tiempo si el deterioro físico fuese en aumento se solicitará un centro residencial. Daniel nos informa que se está intentando crear plazas residenciales.','2');
