insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2016-03-16','Contactamos con Charo (Dra. Aprosuba 1), nos informa de la próxima salida de 26 de Junio a 3 de Julio de 2016 al Albergue Nonte do Gozo. Actividad organizada por AD El Bellotín (asociación de Aprosuba), donde participa la tutelada. El coste del viaje son 200€ pensión completa y el autobús corre a cargo de la Asociación. La Comisión acepta el viaje siempre y cuando tenga capacidad económica para asumir el coste en su momento. Acordamos con Charo que la autorización valdría con la trimestral y que nos enviarán documentación redactada del viaje y sus actividades.','1');
