insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-03-16','La Dra. de Aprosuba 8, nos comunica que Eva quiere pasar el los dias 21, 22, 23 de Marzo (Semana Santa) en Mérida en el domicilio de una cuidadora de aprosuba. La Dra. está de acuerdo, por lo cual queda aprobada la salida ( quedaría incluida en la realción de salidas trimestrales). Pendiente que nos envien más información en lo referente al domicilio y cuidadora de Aprosuba ( que en esta salida no sería profesional sino desde el ámbito personal). Nos informa también del deseo de Eva de realizarse un tatuaje , acordamos abordar esta cuestión una vez pasada la Semana Santa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='TENA'and apellido2='ALVAREZ'),'2016-03-16','Llama la sobrina de Dª Modesta, Valentina Serrano Tena (692-632508) interesada por las pertencias pewrsonales de su tía y por saber por qué se tiró su casa. Respecto a lo segundo se le indica que nuestra función tutelar temino con el fallecimineto de su tía y que dicha información deberá solictarla al juzgado correspondiente. Respecto alas pertenencias, se le indica que sí tenemos unos documentos y joyas que nos entregaron desde la Residencia de Felipe Trigo. Pasará a recogerlas, debiéndo justificar documentalmente su relación con Dª Modesta (declaración de herederos) y firmando un acta en el que consten todas las pertenencias que se le entregan.','2');
