insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2016-03-14','-Nos comunican del ctro penitenciario de Bjoz que ha ingresado por robo con pena por 3 meses . Se anula transferencia para su tia Asunción y se activa la de peculio . -se queda paralizada la solicitud de plaza en centro de discapacidad como se habia acordado en reunion con él .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-03-16','SALIDA Desde Aprosuba-8 de Montijo le informamos de la actividad que durante la Semana Santa realizará la usuaria de vivienda tutelada, Eva Fermoselle Tejada: De acuerdo con nuestra converación telefónica Eva se irá acompañada por una cuidadora de Centro Ocupacional de la Asociación, (Consolación Chavero Hidalgo), a Mérida y se aloará en su domicilio desde el lunes 21/03/16 al 23/03/16. Durante esos días realizarán actividades de ocio por Mérida y alrededores. Dicha cuidadora será la responsable de recoger a Eva en la vivienda tutelada y llevarla a la misma el miércoles día 23/03/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='DEAN'and apellido2='SANCHEZ'),'2016-03-18','RECURSO Según información recibida del IMAS, mediante informe social, la sentencia de incapacitación está recurrida. Puesto en comunicación con el juzgado, se nos confirma que es cierto. De momento, no somos curadores de Julio Dean. Se va a hablar con Gabinete Jurídico para solucionar estos problemas de comunicación. Quedamos a la espera de noticias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-03-18','Hemos recibido del registro nuestro, escrito con liquidación del OAR,de Cáceres, correspondiente al Impuesto de Plusvalía, por la herencia de la vivienda que quieren vender, sita en Avda. de la Constitución 18, de Aldea Moret (Cáceres). Contactado con el OAR de Cáceres, nos dicen que ellos aún no han notificado la liquidación de ese impuesto. Les he facilitado vía fax nuestra dirección, para que nos lo notifiquen. Tenemos, desde que nos lo notifiquen, 2 meses para pagar (117,30 €). A su hermano Luis Miguel le corresponde abonar la misma cantidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-03-18','SE recibe en la Comisión Acta de Denuncia presentada por José Mª TOvar en el Juzgado de 1ª Instancia e Instrucción nº 5 de Cáceres. Trato de llamar a José Mª como indica en si correo eléctrónico pero el teléfono está apagado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-03-18','VIsita a Carmen en la UHB de Mérida. Agustina, su Psiquiatra, dice que se encuentra bien, pero que no es para que viva sola. Cree que una opción mejor para ella serían de nuevo los Pisos Supervisados. Hablará con Asunción sobre ello (nosotros lo haremos también). Tiene previsto darle el alta después de SEmana Santa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Vistamos el piso de Carmen (me acompaña una unidad de la Policía Local). Está en perfectas condiciones: todas las habitaciones ordenadas y limpias, camas hechas, etc. El frigorífico estaba completamente vacío: durante la convesración en la UHB, carmen dijo que sí cocinaba, pero que compraba todos los días. Agustina dijo que estaba baja en proteínas, lo que hace sospechar de una deficiente alimentación. También insistió la Psiquiatra en que TIENE LA BOCA EN MAL ESTADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='DEAN'and apellido2='SANCHEZ'),'2016-03-21','Convesración con Curro. Ciertamente el expediente está recurrido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-03-21','Llama Ceferino, porque quiere marcharse al CRR de Cáceres, porque dice que no se encuentra bien, que tiene mucha ansiedad y que quiere estar más ecrca de su madre, residente actualmente en Plasenzuela. Alquilaría un piso en Cáceres y viviría con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-03-04','INCIDENCIA Comunicamos desde el Servicio de Centro Ocupacional Aprosuba 7, que la tutelada y usuaria de nuestro Servicio, Minerna Martín Blanco, no ha asistido al centro el día 02/03/16.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-03-18','INCIDENCIA El enfermero, D. Manuel Romero García, adscrito al servicio de psiquiatría del C. S. de Jerez de los Caballeros, explica: *************************************** Se informa a la Comisión Tutelar del Adulto que el paciente, D. Ramón González Hernández, estando citado el Miércoles, 16/03/2016, para administración de su medicación inyectable mensual no se ha presentado. Se ha intentado contactar con él vía telefónica en varias ocasiones sin éxito. Se informa, también, de tal situación a la delegada de apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2016-02-05','El fax indica: Paciente que sufre caída accidental con fractura base 1º meta mano izq. Se consulta con traumatologa de guardia, quien indica férula posterior hasta punta de 1º dedo y control en una semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-03-21','Hemos enviado al abogado de oficio, D. Antonio Javier Fernández Sánchez (927404120 ajfernandez@icac.es), del Colegio de Abogados de Cáceres, documentación relacionada con la división de herencia, es decir, Partición inicial que se practicó, Recurso de apelación declarándola nula, Sentencia de incapacitación, aceptación del cargo, notas simples del registro de la propiedad indicando las propiedades a nombre de D. Francisco Ayala y/o sus padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-03-21','Consulta realizada por D. José Javier Álvarez, compañero del SEPAD (60351, del Equipo de Inspección de Mayores) y tío de Álvaro. Problemas que plantea: +++La cuenta en la que tenía todo su dinero su hermana Mª José (645-554472), junto a su hijo Álvaro está bloqueada (figuraba como responsable legal de Álvaro y creemos que lo que ha ocurrido es que se ha cambiado dicho responsable a partir de la asunción del cargo por CTAEx. +++Según D. José, no se contó con la familia durante el procedimiento de incapacitación. +++Plantea la remoción del cargo para que lo recupere su hermana y, al parecer, ya ha iniciado el procediemiento. +++Quire solucionar el problema de la cuenta bancaria de su hermana, aspecto que dice haber consultado ya ella en el juzgado, sin que sepa lo que le han dicho en él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2016-03-21','-SE REANUDA PNC INVALIDEZ CON EFECTOS ENERO DE 2016 CON LOS ATRASOS CORRESPONDIENTES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-03-18','Visita a Emilia en la UHB de Mérida. Según su Psiquiatra, el Dr. Alí, se trata de una persona tremendamente manipuladora. Tiene prevista el alta y vuelta al CRR para la próxima semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2001-03-20','-estaba percibiendo PNC pero como hay varios miembros perceptores de PNC en la unidad de convivencia se les veían reducidas. En julio 2015 se le tramitó PFHC pero no se anuló la PNC . PFHC tiene efectos ec desde octubre de 2015 hay un cobro indebido que comunico actualmente a PNC para que procedan a reclamarlo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-03-22','Intento por dos veces contactar con Marta, sobrina de Hermenegildo, pero en ambas ocasiones "se corta la línea". Llama Águeda (T. Soc. SSB) porque Hermenegildo está con ella. Hablo con Hermenegildo: dice que ya no fuma porros. Le digo que le vamos a pedir cita en CEDEX de Castuera para valorar y en su caso derivar a Comunidad Terapéutica. En ambos extremos se muestra de acuerdo. En esta ocasión se accede a su petición de poder sacar 10€. Quedamos en pedir cita a CEDEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-03-17','Llega vía fax autorización judicial de internamiento para Hermenegildo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORONADA'and edp.apellido1='RODRIGUEZ'and apellido2='MORENO'),'2016-03-22','cORREO-E.Buenos dias. Le comunico que Coronada Rdr. continua hospitalizada en el Hospital Don Benito- VVa de la Serena, y para continuar con el tratamiento la trasladaran al Hospital Infanta de Cristina de Badajoz. Es visita casi a diario por el medico de nuestro centro o personal auxiliar del centro. Le mantendremos informado . Centro residencial "San Francisco" Vva de la serena. Hablo con Petri (Directora): detectada obstrucción de carótida que requiere tratamiento/intervención en el Infanta. Comento a Petri que llame al Hospital para prever necesidad de consentimiento informado por si en estos días se requiere intervención, para dejarla firmada entre hoy y mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2016-03-22','Llamo al alcalde de la Haba para saber si han vuelto a tener noticias de la sobrina (600-263527) de Felipe: no está, dejo mi número y me llamará para confirmar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Novaforma y hablo con Noemí (927-629107,residencia///927-269021, Capellanías), la Terapeuta: si me confirman en el pueblo que no han tenido noticias de ello Felipe se pude ir a su casa. Queda pendiente el tema de cuánto dinero autorizarle para pasar del 26 al 30 de marzo en La Haba. Volveré a llamar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Felicidad: no puede tener en su casa a Felipe porque no tiene cama, pero sí puede seguir yendo a comer allí (al parecer Felipe va a por la comida y se la toma en su casa). Felipe le paga 11€/día (desayuno comida y cena).. En Novaforma me han dicho que en alguna ocasión ha malcomido para quedarse con el dinero, por lo que tras Semana Santa llamaremos a Felicidad para ver si ha ido a por la comida todos los días. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Novaforma. Presupuesto de Felipe: 100€ (33€ comida(Felicidad),37€ desplazamientos (bus y taxi, ida y vuelta), otros gastos 30€). Tiene que comprar también una bombona de butano, por lo que se le dan otros 20€ más. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamada del Alcalde:no han vuelto a tener noticias de la sobrina y su pareja. Según a la hora que llague Felipe le puede dar él personalmente las llaves y si no, dejárselas a Dª Felicidad en su bar para que se las entregue. Informo a Noemí sobre esta conversación. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Felipe ha decidido no ir al pueblo por Semana Santa. Hablo con el Alcalde para que no entregue las llaves a nadie y que estén pendientes de si aparace de nuevo la sobrina por allí. Me comenta que dará parte a la Guardia Civil para que estén atentos a alguna incidencia en ese sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2016-03-22','Conversación con Manuel Mora (928-985700, 670-359313), hermano de D. Juan. Le ha llamado el alcalde respecto del IBI del solar expropiado (al parecer debe de haber una deuda que no me ha sabido concretar). Le pido que nos envíe una copia del documento que le envíe el alcalde y que, una vez se acepte la herencia (si se acepta) gastos y beneficios irán al 50% entre ambos hermanos (salvo documentro notarial en contra de ello).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2005-04-21','Recibidos informes. Pedir INSS, saldo banco','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2016-03-22','Conversación con Isabel, Psicóloga de Aprosuba 1. Nos comunica que Juana se ha escapado del centro. Consultan sobre forma de proceder: denunciar inmediatamente a la Guardia Civil y caso de que vuelva por sí misma, comunicárselo igualmente. Nos enviarán por fax y/o correo la "fuga" y el "regreso". +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Nos comunican a las 14:20h el regreso de Juana al centro. 20´después de la primera conversación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2016-03-22','Nos envían un email hoy día 22, de la Residencia Hermanitas de Badajoz, solicitando autorización para que Andrea pueda maracharse en Semana Santa a su domicilio. Contactos con la TS (EVA) de la Residencia, la cual nos comunica que Andrea se ha marchado a su domicilio, hoy, con dinero en efectivo que le ha dado la Madre Superiora. (Acordamos que mañana Eva nos informará de la Cuantia). Le informamos que la Comisión no autoriza la salida, ya que Andrea no toma la medicación, por lo cual seguramente sufra una descompesación y no puede estar en su domicilio sin supervisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2001-03-20','-Percibe P.Orfandad Absoluta de 737,26 desd noviembre de 2015','2');
